                <div>
                  <label className="block text-sm font-bold text-gray-600 mb-1">{AR.password}</label>
                  <input 
                    required 
                    type="password" 
                    className="w-full border rounded-xl p-3 bg-gray-50 focus:ring-2 focus:ring-primary-500 outline-none"
                  />
