          ))}
        </div>
      )}

      {/* Modal: Add Test to Patient */}
      {showAddModal && (
        <div className="fixed inset-0 z-50 bg-black/60 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-lg rounded-2xl shadow-2xl animate-in zoom-in-95">
            <div className="p-6 bg-primary-600 text-white flex justify-between items-center rounded-t-2xl">
              <h3 className="text-xl font-bold flex items-center gap-2"><FlaskConical size={22} /> حجز تحليل جديد</h3>
              <button onClick={() => setShowAddModal(false)}><X size={24} /></button>
            </div>
            <form onSubmit={handleAddTestRequest} className="p-8 space-y-6">
              <div>
                <label className="block text-sm font-bold text-gray-600 mb-2">المريض</label>
                <select name="patientId" required className="w-full border rounded-xl p-3 bg-gray-50 outline-none focus:ring-2 focus:ring-primary-500">
                  <option value="">اختر المريض...</option>
                  {patients.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-sm font-bold text-gray-600 mb-2">نوع التحليل المطلوب</label>
                <select name="testDefId" required className="w-full border rounded-xl p-3 bg-gray-50 outline-none focus:ring-2 focus:ring-primary-500">
                  <option value="">اختر من القاموس...</option>
