import { 
  Patient, DialysisSession, Service, Invoice, Product, 
  Store, StockTransaction, Employee, FinancialAccount, 
  Transaction, FundingEntity, ShiftRecord, LabTest, LabTestDefinition, AuditLog,
  User, Permission
} from './types.ts';
import { supabase } from './supabase.ts';

export class DB {
  static currentUser: any = null;
  static patients: Patient[] = [];
  static funding: FundingEntity[] = [];
  static services: Service[] = [];
  static products: Product[] = [];
  static stores: Store[] = [];
  static accounts: FinancialAccount[] = [];
  static transactions: Transaction[] = [];
  static users: User[] = [];
  static employees: Employee[] = [];
  static shifts: ShiftRecord[] = [];
  static sessions: DialysisSession[] = [];

  // --- Patients ---
  static async getPatients() {
    const { data, error } = await supabase.from('patients').select('*').order('created_at', { ascending: false });
    if (error) throw error;
    this.patients = data || [];
    return data;
  }

  static async addPatient(p: Partial<Patient>) {
    const { data, error } = await supabase.from('patients').insert([p]).select();
    if (error) throw error;
    await this.log('إضافة مريض', `تمت إضافة المريض ${p.name}`);
    return data[0];
  }

  // --- Lab Test Definitions (Dictionary) ---
  static async getLabDefinitions() {
    const { data, error } = await supabase.from('lab_test_definitions').select('*').order('name');
    if (error) throw error;
    return data;
  }

  static async addLabDefinition(def: Partial<LabTestDefinition>) {
    const { data, error } = await supabase.from('lab_test_definitions').insert([def]).select();
    if (error) throw error;
    await this.log('تعريف تحليل', `تم إضافة تعريف للتحليل: ${def.name}`);
    return data[0];
  }

  // --- Lab Tests (Patient Results) ---
  static async getLabTests(patientId?: string) {
    let query = supabase.from('lab_tests').select('*, patients(name), lab_test_definitions(*)');
    if (patientId) query = query.eq('patient_id', patientId);
    const { data, error } = await query.order('date', { ascending: false });
    if (error) throw error;
    return data;
  }

  static async addLabTest(test: Partial<LabTest>) {
    const payload = {
      ...test,
      status: test.result ? 'COMPLETED' : 'PENDING'
    };
    const { data, error } = await supabase.from('lab_tests').insert([payload]).select();
    if (error) throw error;
    await this.log('حجز تحليل', `تم حجز تحليل لمريض ID: ${test.patientId}`);
    return data[0];
  }

  static async updateLabResult(id: string, result: string) {
    const { data, error } = await supabase.from('lab_tests')
      .update({ result, status: 'COMPLETED' })
      .eq('id', id)
      .select();
    if (error) throw error;
    await this.log('تسجيل نتيجة', `تم تسجيل نتيجة للتحليل ID: ${id}`);
    return data[0];
  }

  // --- Sessions ---
  static async getSessions() {
    const { data, error } = await supabase.from('dialysis_sessions').select('*, patients(name)').order('created_at', { ascending: false });
    if (error) throw error;
    this.sessions = data || [];
    return data;
  }

  static async addSession(session: Partial<DialysisSession>) {
    const { data, error } = await supabase.from('dialysis_sessions').insert([session]).select();
    if (error) throw error;
    await this.log('تسجيل جلسة', `تم تسجيل جلسة لمريض ID: ${session.patientId}`);
    return data[0];
  }

  // --- Funding ---
  static async getFundingEntities() {
    const { data, error } = await supabase.from('funding_entities').select('*').order('name');
    if (error) throw error;
    this.funding = data || [];
    return data;
  }

  static async addFundingEntity(name: string) {
    const { data, error } = await supabase.from('funding_entities').insert([{ name }]).select();
    if (error) throw error;
    await this.log('إضافة جهة تمويل', `تم إضافة ${name}`);
    return data[0];
  }

  static async deleteFundingEntity(id: string) {
    const { error } = await supabase.from('funding_entities').delete().eq('id', id);
    if (error) throw error;
    await this.log('حذف جهة تمويل', `تم حذف جهة ID: ${id}`);
  }

  // --- Services ---
  static async getServices() {
    const { data, error } = await supabase.from('services').select('*').order('name');
    if (error) throw error;
    this.services = data || [];
    return data;
  }

  static async addService(s: Partial<Service>) {
    const { data, error } = await supabase.from('services').insert([s]).select();
    if (error) throw error;
    await this.log('إضافة خدمة', `تم إضافة خدمة: ${s.name}`);
    return data[0];
  }

  static async deleteService(id: string) {
    const { error } = await supabase.from('services').delete().eq('id', id);
    if (error) throw error;
  }

  // --- Products (Inventory) ---
  static async getProducts() {
    const { data, error } = await supabase.from('products').select('*').order('name');
    if (error) throw error;
    this.products = data || [];
    return data;
  }

  static async addProduct(p: Partial<Product>) {
    const { data, error } = await supabase.from('products').insert([p]).select();
    if (error) throw error;
    await this.log('إضافة صنف', `تم إضافة صنف جديد: ${p.name}`);
    return data[0];
  }

  static async deleteProduct(id: string) {
    const { error } = await supabase.from('products').delete().eq('id', id);
    if (error) throw error;
  }

  // --- Stores ---
  static async getStores() {
    const { data, error } = await supabase.from('stores').select('*').order('name');
    if (error) throw error;
    this.stores = data || [];
    return data;
  }

  static async addStore(s: Partial<Store>) {
    const { data, error } = await supabase.from('stores').insert([s]).select();
    if (error) throw error;
    await this.log('إضافة مخزن', `تم إضافة مخزن: ${s.name}`);
    return data[0];
  }

  static async deleteStore(id: string) {
    const { error } = await supabase.from('stores').delete().eq('id', id);
    if (error) throw error;
  }

  // --- Payroll ---
  static async resetShifts() {
    const { error } = await supabase.from('shifts').delete().neq('id', '00000000-0000-0000-0000-000000000000');
    if (error) throw error;
    await this.log('تصفير شفتات', 'تم تصفير جميع الشفتات لبدء دورة جديدة');
  }

  // --- Finance ---
  static async addFinanceTx(tx: Partial<Transaction>) {
    const { data, error } = await supabase.from('transactions').insert([tx]).select();
    if (error) throw error;
    await this.log('حركة مالية', `تم تسجيل حركة ${tx.type}: ${tx.amount}`);
    return data[0];
  }

  // --- Users ---
  static async addUser(u: User) {
    const { data, error } = await supabase.from('system_users').insert([u]).select();
    if (error) throw error;
    this.users = [...this.users, data[0]];
    await this.log('إضافة مستخدم', `تم إضافة مستخدم: ${u.username}`);
    return data[0];
  }

  static async deleteUser(id: string) {
    const { error } = await supabase.from('system_users').delete().eq('id', id);
    if (error) throw error;
    this.users = this.users.filter(u => u.id !== id);
    await this.log('حذف مستخدم', `تم حذف مستخدم ID: ${id}`);
  }

  // --- Log ---
  static async log(action: string, details: string) {
    const user = JSON.parse(localStorage.getItem('dialysis_user') || '{}');
    const { error } = await supabase.from('audit_logs').insert([{
      user_id: user.name || 'غير معروف',
      action,
      details,
      timestamp: new Date().toISOString()
    }]);
    if (error) console.error('Error logging:', error);
  }
}

import React, { useState, useEffect } from 'react';
import { AR } from '../constants';
import { DB } from '../store';
import { Service, Store, Product, FundingEntity } from '../types';
import { Settings, Package, Store as StoreIcon, CreditCard, Tag, Plus, Trash2, Edit, X, Loader2 } from 'lucide-react';

const SetupModule: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'services' | 'stores' | 'products' | 'funding'>('services');
  const [loading, setLoading] = useState(false);
  const [showModal, setShowModal] = useState(false);

  // Data states
  const [services, setServices] = useState<Service[]>([]);
  const [stores, setStores] = useState<Store[]>([]);
  const [products, setProducts] = useState<Product[]>([]);
  const [funding, setFunding] = useState<FundingEntity[]>([]);

  useEffect(() => {
    loadData();
  }, [activeTab]);

  const loadData = async () => {
    setLoading(true);
    try {
      if (activeTab === 'services') setServices(await DB.getServices());
      if (activeTab === 'stores') setStores(await DB.getStores());
      if (activeTab === 'products') setProducts(await DB.getProducts());
      if (activeTab === 'funding') setFunding(await DB.getFundingEntities());
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleAddItem = async (e: React.FormEvent) => {
    e.preventDefault();
    const target = e.target as any;
    try {
      if (activeTab === 'services') {
        await DB.addService({ name: target.name.value, price: parseFloat(target.price.value), category: target.category.value });
      } else if (activeTab === 'stores') {
        await DB.addStore({ name: target.name.value, isMain: target.isMain.checked });
      } else if (activeTab === 'products') {
        await DB.addProduct({ name: target.name.value, unit: target.unit.value, minStock: parseInt(target.minStock.value), price: parseFloat(target.price.value) });
      } else if (activeTab === 'funding') {
        await DB.addFundingEntity(target.name.value);
      }
      setShowModal(false);
      loadData();
    } catch (err) {
      alert("حدث خطأ أثناء الإضافة");
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm(AR.confirmation)) return;
    try {
      if (activeTab === 'services') await DB.deleteService(id);
      if (activeTab === 'stores') await DB.deleteStore(id);
      if (activeTab === 'products') await DB.deleteProduct(id);
      if (activeTab === 'funding') await DB.deleteFundingEntity(id);
      loadData();
    } catch (err) {
      alert("حدث خطأ أثناء الحذف");
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-wrap gap-2 p-1 bg-gray-200/50 rounded-xl w-fit no-print">
        <button 
          onClick={() => setActiveTab('services')}
          className={`flex items-center gap-2 px-6 py-2 rounded-lg font-bold transition-all ${activeTab === 'services' ? 'bg-white shadow-sm text-primary-600' : 'text-gray-500 hover:text-gray-700'}`}
        >
          <Tag size={18} /> {AR.services}
        </button>
        <button 
          onClick={() => setActiveTab('stores')}
          className={`flex items-center gap-2 px-6 py-2 rounded-lg font-bold transition-all ${activeTab === 'stores' ? 'bg-white shadow-sm text-primary-600' : 'text-gray-500 hover:text-gray-700'}`}
        >
          <StoreIcon size={18} /> {AR.stores}
        </button>
        <button 
          onClick={() => setActiveTab('products')}
          className={`flex items-center gap-2 px-6 py-2 rounded-lg font-bold transition-all ${activeTab === 'products' ? 'bg-white shadow-sm text-primary-600' : 'text-gray-500 hover:text-gray-700'}`}
        >
          <Package size={18} /> {AR.products}
        </button>
        <button 
          onClick={() => setActiveTab('funding')}
          className={`flex items-center gap-2 px-6 py-2 rounded-lg font-bold transition-all ${activeTab === 'funding' ? 'bg-white shadow-sm text-primary-600' : 'text-gray-500 hover:text-gray-700'}`}
        >
          <CreditCard size={18} /> {AR.funding}
        </button>
