import React, { useState, useEffect, useRef } from 'react';
import Layout from './components/Layout.tsx';
import DashboardModule from './modules/Dashboard.tsx';
import ReceptionModule from './modules/Reception.tsx';
import PatientModule from './modules/Patients.tsx';
import LabModule from './modules/Lab.tsx';
import BillingModule from './modules/Billing.tsx';
import PayrollModule from './modules/Payroll.tsx';
import InventoryModule from './modules/Inventory.tsx';
import FinanceModule from './modules/Finance.tsx';
import SetupModule from './modules/Setup.tsx';
import UsersModule from './modules/Users.tsx';
import LoginModule from './modules/Login.tsx';

const INACTIVITY_LIMIT = 30 * 60 * 1000; // زيادة المدة لـ 30 دقيقة لتقليل الإزعاج أثناء التطوير

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const lastActivityRef = useRef<number>(Date.now());

  // تعيين مستخدم افتراضي لتعطيل صفحة تسجيل الدخول
  const [currentUser, setCurrentUser] = useState<any>({ 
    name: 'مدير النظام', 
    username: 'admin',
    role: 'ADMIN',
    permissions: ['VIEW_DASHBOARD', 'MANAGE_RECEPTION', 'MANAGE_PATIENTS', 'MANAGE_LAB', 'MANAGE_BILLING', 'MANAGE_PAYROLL', 'MANAGE_INVENTORY', 'MANAGE_FINANCE', 'MANAGE_USERS', 'SYSTEM_SETUP']
  });

  // جعل الحالة "متصل" دائماً كقيمة افتراضية
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(true);

  const handleLogout = () => {
    // في وضع التعطيل، يمكننا فقط تصفير البيانات أو إعادة التوجيه، 
    // لكن هنا سأتركها لتعيد الحالة لـ false إذا أراد المستخدم العودة لشاشة الدخول يدوياً
    setIsAuthenticated(false);
    setCurrentUser(null);
    localStorage.removeItem('dialysis_user');
    localStorage.removeItem('last_activity');
  };

  // مراقبة النشاط (اختياري، تم إبقاؤه مع زيادة المدة)
  useEffect(() => {
    if (!isAuthenticated) return;

    const resetTimer = () => {
      lastActivityRef.current = Date.now();
      localStorage.setItem('last_activity', lastActivityRef.current.toString());
    };

    const events = ['mousedown', 'mousemove', 'keypress', 'scroll', 'touchstart', 'click'];
    events.forEach(event => window.addEventListener(event, resetTimer));

    const interval = setInterval(() => {
      const now = Date.now();
      if (now - lastActivityRef.current > INACTIVITY_LIMIT) {
        // لا نقوم بتسجيل الخروج تلقائياً في وضع "التعطيل" إلا إذا رغبت في ذلك
        // handleLogout(); 
      }
    }, 1000);

    return () => {
      events.forEach(event => window.removeEventListener(event, resetTimer));
      clearInterval(interval);
    };
  }, [isAuthenticated]);

  const handleLoginSuccess = (user: any) => {
    setCurrentUser(user);
    setIsAuthenticated(true);
  };

  if (!isAuthenticated) {
    return <LoginModule onLoginSuccess={handleLoginSuccess} />;
  }

  const renderModule = () => {
    switch (activeTab) {
      case 'dashboard': return <DashboardModule />;
      case 'reception': return <ReceptionModule />;
      case 'patients': return <PatientModule />;
      case 'lab': return <LabModule />;
      case 'billing': return <BillingModule />;
      case 'employees': return <PayrollModule />;
      case 'inventory': return <InventoryModule />;
      case 'finance': return <FinanceModule />;
      case 'users': return <UsersModule />;
      case 'setup': return <SetupModule />;
      default: return <DashboardModule />;
    }
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      <div className="flex justify-between items-center mb-6 no-print">
        <div className="flex items-center gap-3">
          <div className="w-2 h-2 bg-green-500 rounded-full animate-pulse shadow-[0_0_8px_rgba(34,197,94,0.6)]"></div>
          <div className="text-gray-500 text-sm font-medium">
            مرحباً، <span className="text-primary-600 font-bold">{currentUser?.name}</span>
          </div>
        </div>
        <div className="flex items-center gap-4">
          <div className="text-[10px] text-blue-600 font-bold bg-blue-50 px-2 py-1 rounded border border-blue-100">
            وضع التطوير: تم تخطي شاشة الدخول
          </div>
          <button 
            onClick={handleLogout}
            className="text-red-500 text-xs font-bold hover:bg-red-50 px-3 py-1 rounded-lg border border-red-100 transition-colors"
          >
            تسجيل الخروج
          </button>
        </div>
      </div>
      {renderModule()}
    </Layout>
  );
};

export default App;

import { 
  Patient, DialysisSession, Service, Invoice, Product, 
  Store, StockTransaction, Employee, FinancialAccount, 
  Transaction, FundingEntity, ShiftRecord, LabTest, LabTestDefinition, AuditLog,
  User, Permission
} from './types.ts';
import { supabase } from './supabase.ts';

export class DB {
  static currentUser: any = null;
  static patients: Patient[] = [];
  static funding: FundingEntity[] = [];
  static services: Service[] = [];
  static products: Product[] = [];
  static stores: Store[] = [];
  static accounts: FinancialAccount[] = [];
  static transactions: Transaction[] = [];
  static users: User[] = [];
  static employees: Employee[] = [];
  static shifts: ShiftRecord[] = [];
  static sessions: DialysisSession[] = [];

  // --- Patients ---
  static async getPatients() {
    const { data, error } = await supabase.from('patients').select('*').order('created_at', { ascending: false });
    if (error) throw error;
    this.patients = data || [];
    return data;
  }

  static async addPatient(p: Partial<Patient>) {
    const { data, error } = await supabase.from('patients').insert([p]).select();
    if (error) throw error;
    await this.log('إضافة مريض', `تمت إضافة المريض ${p.name}`);
    return data[0];
  }

  // --- Lab ---
  static async getLabDefinitions() {
    const { data, error } = await supabase.from('lab_test_definitions').select('*').order('name');
    if (error) throw error;
    return data;
  }

  static async addLabDefinition(def: Partial<LabTestDefinition>) {
    const { data, error } = await supabase.from('lab_test_definitions').insert([def]).select();
    if (error) throw error;
    return data[0];
  }

  static async getLabTests() {
    const { data, error } = await supabase.from('lab_tests').select('*, patients(name), lab_test_definitions(*)').order('date', { ascending: false });
    if (error) throw error;
    return data;
  }

  static async addLabTest(test: Partial<LabTest>) {
    const { data, error } = await supabase.from('lab_tests').insert([test]).select();
    if (error) throw error;
    return data[0];
  }

  static async updateLabResult(id: string, result: string) {
    const { data, error } = await supabase.from('lab_tests').update({ result, status: 'COMPLETED' }).eq('id', id).select();
    if (error) throw error;
    return data[0];
  }

  // --- Sessions ---
  static async getSessions() {
    const { data, error } = await supabase.from('dialysis_sessions').select('*, patients(name)').order('created_at', { ascending: false });
    if (error) throw error;
    this.sessions = data || [];
    return data;
  }

  static async addSession(session: Partial<DialysisSession>) {
    const { data, error } = await supabase.from('dialysis_sessions').insert([session]).select();
    if (error) throw error;
    return data[0];
  }

  // --- Inventory & Stock ---
  static async getProducts() {
    const { data, error } = await supabase.from('products').select('*').order('name');
    if (error) throw error;
    this.products = data || [];
    return data;
  }

  static async addProduct(p: Partial<Product>) {
    const { data, error } = await supabase.from('products').insert([p]).select();
    if (error) throw error;
    return data[0];
  }

  static async deleteProduct(id: string) {
    const { error } = await supabase.from('products').delete().eq('id', id);
    if (error) throw error;
  }

  static async getStores() {
    const { data, error } = await supabase.from('stores').select('*').order('name');
    if (error) throw error;
    this.stores = data || [];
    return data;
  }

  static async addStore(s: Partial<Store>) {
    const { data, error } = await supabase.from('stores').insert([s]).select();
    if (error) throw error;
    return data[0];
  }

  static async deleteStore(id: string) {
