import { 
  Patient, DialysisSession, Service, Invoice, Product, 
  Store, StockTransaction, Employee, FinancialAccount, 
  Transaction, FundingEntity, ShiftRecord, LabTest, LabTestDefinition, AuditLog,
  User, Permission, TransferRequest
} from './types.ts';
import { supabase } from './supabase.ts';

export class DB {
  static currentUser: any = null;
  static patients: Patient[] = [];
  static funding: FundingEntity[] = [];
  static services: Service[] = [];
  static products: Product[] = [];
  static stores: Store[] = [];
  static accounts: FinancialAccount[] = [];
  static transactions: Transaction[] = [];
  static users: User[] = [];
  static employees: Employee[] = [];
  static shifts: ShiftRecord[] = [];
  static sessions: DialysisSession[] = [];

  // --- Patients ---
  static async getPatients() {
    const { data, error } = await supabase.from('patients').select('*').order('created_at', { ascending: false });
    if (error) throw error;
    this.patients = data || [];
    return data;
  }

  static async addPatient(p: Partial<Patient>) {
    const { data, error } = await supabase.from('patients').insert([p]).select();
    if (error) throw error;
    await this.log('إضافة مريض', `تمت إضافة المريض ${p.name}`);
    return data[0];
  }

  // --- Lab ---
  static async getLabDefinitions() {
    const { data, error } = await supabase.from('lab_test_definitions').select('*').order('name');
    if (error) throw error;
    return data;
  }

  static async addLabDefinition(def: Partial<LabTestDefinition>) {
    const { data, error } = await supabase.from('lab_test_definitions').insert([def]).select();
    if (error) throw error;
    return data[0];
  }

  static async getLabTests() {
    const { data, error } = await supabase.from('lab_tests').select('*, patients(name), lab_test_definitions(*)').order('date', { ascending: false });
    if (error) throw error;
    return data;
  }

  static async addLabTest(test: Partial<LabTest>) {
    const { data, error } = await supabase.from('lab_tests').insert([test]).select();
    if (error) throw error;
    return data[0];
  }

  static async updateLabResult(id: string, result: string) {
    const { data, error } = await supabase.from('lab_tests').update({ result, status: 'COMPLETED' }).eq('id', id).select();
    if (error) throw error;
    return data[0];
  }

  // --- Sessions ---
  static async getSessions() {
    const { data, error } = await supabase.from('dialysis_sessions').select('*, patients(name)').order('created_at', { ascending: false });
    if (error) throw error;
    this.sessions = data || [];
    return data;
  }

  static async addSession(session: Partial<DialysisSession>) {
    const { data, error } = await supabase.from('dialysis_sessions').insert([session]).select();
    if (error) throw error;
    return data[0];
  }

  // --- Inventory & Stock ---
  static async getProducts() {
    const { data, error } = await supabase.from('products').select('*').order('name');
    if (error) throw error;
    this.products = data || [];
    return data;
  }

  static async addProduct(p: Partial<Product>) {
    const { data, error } = await supabase.from('products').insert([p]).select();
    if (error) throw error;
    return data[0];
  }

  static async deleteProduct(id: string) {
    const { error } = await supabase.from('products').delete().eq('id', id);
    if (error) throw error;
  }

  static async getStores() {
    const { data, error } = await supabase.from('stores').select('*').order('name');
    if (error) throw error;
    this.stores = data || [];
    return data;
  }

  static async addStore(s: Partial<Store>) {
    const { data, error } = await supabase.from('stores').insert([s]).select();
    if (error) throw error;
    return data[0];
  }

  static async deleteStore(id: string) {
    const { error } = await supabase.from('stores').delete().eq('id', id);
    if (error) throw error;
  }

  static async addStockTransaction(tx: Partial<StockTransaction>) {
    const { data, error } = await supabase.from('stock_transactions').insert([tx]).select();
    if (error) throw error;
    await this.log('حركة مخزن', `نوع: ${tx.type}, كمية: ${tx.quantity}`);
    return data[0];
  }

  // طلبات التحويل
  static async createTransferRequest(req: Partial<TransferRequest>) {
    const { data, error } = await supabase.from('transfer_requests').insert([req]).select();
    if (error) throw error;
    await this.log('طلب تحويل', `طلب جديد من مخزن ${req.fromStoreId} إلى ${req.toStoreId}`);
    return data[0];
  }

  static async getTransferRequests() {
    const { data, error } = await supabase.from('transfer_requests').select('*').order('date', { ascending: false });
    if (error) throw error;
    return data;
  }

  static async updateTransferRequestStatus(id: string, status: 'APPROVED' | 'REJECTED', items?: any[]) {
    const { data, error } = await supabase.from('transfer_requests').update({ status, items }).eq('id', id).select();
    if (error) throw error;
    return data[0];
  }

  // --- System Users ---
  static async getUsers() {
    const { data, error } = await supabase.from('system_users').select('*').order('created_at', { ascending: false });
    if (error) throw error;
    this.users = data || [];
    return data;
  }

  static async addUser(u: Partial<User>) {
    const { data, error } = await supabase.from('system_users').insert([u]).select();
    if (error) throw error;
    return data[0];
  }

  // --- Other ---
  static async addFinanceTx(tx: Partial<Transaction>) {
    const { data, error } = await supabase.from('transactions').insert([tx]).select();
    if (error) throw error;
    return data[0];
  }

  static async resetShifts() {
    const { error } = await supabase.from('shifts').delete().neq('id', '00000000-0000-0000-0000-000000000000');
    if (error) throw error;
  }

  static async log(action: string, details: string) {
    const user = JSON.parse(localStorage.getItem('dialysis_user') || '{}');
    await supabase.from('audit_logs').insert([{
      user_id: user.name || 'Unknown',
      action,
      details,
      timestamp: new Date().toISOString()
    }]);
  }
}

import React, { useState, useEffect } from 'react';
import { AR } from '../constants.ts';
import { DB } from '../store.ts';
import { Product, Store, StockTransaction, TransferRequest } from '../types.ts';
import { Package, ArrowLeftRight, TrendingUp, TrendingDown, ClipboardList, Plus, Search, ArrowRightLeft, Loader2, X, Check, Bell, AlertCircle, Trash2 } from 'lucide-react';

const InventoryModule: React.FC = () => {
  const [activeSubTab, setActiveSubTab] = useState<'stock' | 'transfers' | 'requests'>('stock');
  const [showMoveModal, setShowMoveModal] = useState(false);
  const [showAddProductModal, setShowAddProductModal] = useState(false);
  const [moveType, setMoveType] = useState<'ADD' | 'DEDUCT' | 'TRANSFER'>('ADD');

  const [loading, setLoading] = useState(false);
  const [products, setProducts] = useState<Product[]>([]);
  const [stores, setStores] = useState<Store[]>([]);
  const [requests, setRequests] = useState<TransferRequest[]>([]);

  // طلبات التحويل المتعددة
  const [transferItems, setTransferItems] = useState<{ productId: string, quantity: number }[]>([]);
  const [selectedProductId, setSelectedProductId] = useState('');
  const [selectedQuantity, setSelectedQuantity] = useState(1);
  const [showProcessRequest, setShowProcessRequest] = useState<TransferRequest | null>(null);

  useEffect(() => {
    loadData();
  }, [activeSubTab]);

  const loadData = async () => {
    setLoading(true);
    try {
      const p = await DB.getProducts();
      const s = await DB.getStores();
      setProducts(p || []);
      setStores(s || []);

      if (activeSubTab === 'requests') {
        const reqs = await DB.getTransferRequests();
        setRequests(reqs || []);
      }
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const addItemToTransfer = () => {
    if (!selectedProductId || selectedQuantity <= 0) return;
    if (transferItems.find(i => i.productId === selectedProductId)) {
      alert("الصنف مضاف بالفعل");
      return;
    }
    setTransferItems([...transferItems, { productId: selectedProductId, quantity: selectedQuantity }]);
    setSelectedProductId('');
    setSelectedQuantity(1);
  };

  const removeItemFromTransfer = (pid: string) => {
    setTransferItems(transferItems.filter(i => i.productId !== pid));
  };

  const handleStockAction = async (e: React.FormEvent) => {
    e.preventDefault();
    const target = e.target as any;

    if (moveType === 'TRANSFER') {
      if (target.storeId.value === target.targetStoreId.value) {
        alert("لا يمكن التحويل لنفس المخزن!");
        return;
      }
      if (transferItems.length === 0) {
        alert("يرجى إضافة صنف واحد على الأقل");
        return;
      }

      setLoading(true);
      try {
        await DB.createTransferRequest({
          fromStoreId: target.storeId.value,
          toStoreId: target.targetStoreId.value,
          items: transferItems,
          status: 'PENDING',
          requestedBy: JSON.parse(localStorage.getItem('dialysis_user') || '{}').name || 'Unknown',
          note: target.note.value,
          date: new Date().toISOString()
        });
        setShowMoveModal(false);
        setTransferItems([]);
        alert("تم إرسال طلب التحويل للمسؤول");
        loadData();
      } catch (err) {
        alert("حدث خطأ");
      } finally {
        setLoading(false);
      }
    } else {
      // إيقاف الإضافة العادية للاختصار في هذا المثال أو تنفيذها هنا
      setLoading(true);
      try {
        await DB.addStockTransaction({
          productId: target.productId.value,
          storeId: target.storeId.value,
          type: moveType,
          quantity: parseFloat(target.quantity.value),
          date: new Date().toISOString().split('T')[0],
          note: target.note.value
        });
        setShowMoveModal(false);
        loadData();
      } catch (err) { alert("خطأ"); } finally { setLoading(false); }
    }
  };

  const processRequest = async (status: 'APPROVED' | 'REJECTED') => {
    if (!showProcessRequest) return;
    setLoading(true);
    try {
      await DB.updateTransferRequestStatus(showProcessRequest.id, status, showProcessRequest.items);
      if (status === 'APPROVED') {
        // تنفيذ حركات المخزن الفعلية لكل صنف
        for (const item of showProcessRequest.items) {
          await DB.addStockTransaction({
            productId: item.productId,
            storeId: showProcessRequest.fromStoreId,
            targetStoreId: showProcessRequest.toStoreId,
            quantity: item.quantity,
            type: 'TRANSFER',
            date: new Date().toISOString().split('T')[0]
          });
        }
      }
      setShowProcessRequest(null);
      loadData();
      alert(status === 'APPROVED' ? "تم اعتماد التحويل وتحديث الأرصدة" : "تم رفض الطلب");
    } catch (err) {
      alert("خطأ في معالجة الطلب");
    } finally {
      setLoading(false);
    }
  };

  const pendingCount = requests.filter(r => r.status === 'PENDING').length;

  return (
    <div className="space-y-6">
      {/* Header Actions */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 no-print">
        <div className="flex gap-2 p-1 bg-gray-200/50 rounded-xl w-fit">
          <button 
            onClick={() => setActiveSubTab('stock')}
            className={`px-6 py-2 rounded-lg font-bold transition-all ${activeSubTab === 'stock' ? 'bg-white shadow-sm text-primary-600' : 'text-gray-500 hover:text-gray-700'}`}
          >
            {AR.inventory}
          </button>
          <button 
            onClick={() => setActiveSubTab('transfers')}
            className={`px-6 py-2 rounded-lg font-bold transition-all ${activeSubTab === 'transfers' ? 'bg-white shadow-sm text-primary-600' : 'text-gray-500 hover:text-gray-700'}`}
          >
            حركات المخزن
          </button>
          <button 
            onClick={() => setActiveSubTab('requests')}
            className={`px-6 py-2 rounded-lg font-bold transition-all flex items-center gap-2 ${activeSubTab === 'requests' ? 'bg-white shadow-sm text-indigo-600' : 'text-gray-500 hover:text-gray-700'}`}
          >
            طلبات التحويل 
            {pendingCount > 0 && <span className="bg-red-500 text-white text-[10px] px-2 py-0.5 rounded-full animate-pulse">{pendingCount}</span>}
          </button>
        </div>

        <div className="flex gap-2">
           <button 
             onClick={() => { setMoveType('TRANSFER'); setTransferItems([]); setShowMoveModal(true); }}
             className="bg-indigo-600 text-white px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 hover:bg-indigo-700 shadow-sm transition-all active:scale-95"
           >
             <ArrowRightLeft size={16} /> طلب تحويل داخلي
           </button>
           <button 
             onClick={() => { setMoveType('ADD'); setShowMoveModal(true); }}
             className="bg-green-600 text-white px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 hover:bg-green-700 shadow-sm"
           >
             <TrendingUp size={16} /> توريد
           </button>
        </div>
      </div>

      {activeSubTab === 'requests' && pendingCount > 0 && (
        <div className="bg-indigo-50 border-r-4 border-indigo-500 p-4 rounded-xl flex items-center justify-between animate-in slide-in-from-top-4">
           <div className="flex items-center gap-3">
              <Bell className="text-indigo-600 animate-bounce" />
              <div>
                 <p className="font-bold text-indigo-900">لديك {pendingCount} طلب تحويل جديد بانتظار الموافقة</p>
                 <p className="text-xs text-indigo-700">يرجى مراجعة الطلبات أدناه لاتخاذ إجراء</p>
              </div>
           </div>
        </div>
      )}

      {/* Main Content */}
      <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden min-h-[400px]">
        {activeSubTab === 'stock' ? (
          <div className="p-6">
             <div className="flex justify-between items-center mb-6">
               <h3 className="font-bold text-lg">الأرصدة الحالية</h3>
             </div>
             <table className="w-full text-right">
                <thead className="bg-gray-50 border-b">
                  <tr>
                    <th className="px-6 py-4 font-bold text-gray-600 uppercase text-xs">اسم الصنف</th>
                    <th className="px-6 py-4 font-bold text-gray-600 uppercase text-xs">الوحدة</th>
                    <th className="px-6 py-4 font-bold text-gray-600 uppercase text-xs">الرصيد المتاح</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-100">
                  {products.map(p => (
                    <tr key={p.id} className="hover:bg-primary-50/30">
                      <td className="px-6 py-4 font-bold text-gray-800">{p.name}</td>
                      <td className="px-6 py-4 text-gray-600">{p.unit}</td>
                      <td className="px-6 py-4 font-bold text-primary-600">0</td>
                    </tr>
                  ))}
                </tbody>
             </table>
          </div>
        ) : activeSubTab === 'requests' ? (
          <div className="p-6">
            <h3 className="font-bold text-lg mb-6">سجل طلبات التحويل</h3>
            <div className="space-y-4">
               {requests.map(req => (
                 <div key={req.id} className="p-5 border rounded-2xl flex flex-col md:flex-row justify-between items-start md:items-center gap-4 hover:shadow-md transition-all">
                    <div>
                       <div className="flex items-center gap-2 mb-1">
                          <span className="font-bold text-gray-800">من: {stores.find(s => s.id === req.fromStoreId)?.name}</span>
                          <ArrowLeftRight size={14} className="text-gray-400" />
                          <span className="font-bold text-primary-700">إلى: {stores.find(s => s.id === req.toStoreId)?.name}</span>
                       </div>
                       <div className="text-xs text-gray-400">
                          بواسطة: {req.requestedBy} • {new Date(req.date).toLocaleString('ar-EG')}
                       </div>
                       <div className="mt-2 flex gap-1">
                          {req.items.slice(0, 3).map((item, idx) => (
                            <span key={idx} className="bg-gray-100 px-2 py-0.5 rounded text-[10px] text-gray-600 border">
                               {products.find(p => p.id === item.productId)?.name} ({item.quantity})
                            </span>
                          ))}
                          {req.items.length > 3 && <span className="text-[10px] text-gray-400">+{req.items.length - 3} أصناف أخرى</span>}
                       </div>
                    </div>
                    <div className="flex items-center gap-3 w-full md:w-auto">
                       {req.status === 'PENDING' ? (
                         <>
                           <span className="text-xs font-bold text-orange-600 bg-orange-50 px-3 py-1 rounded-full border border-orange-200">بانتظار الموافقة</span>
                           <button 
                             onClick={() => setShowProcessRequest(req)}
                             className="bg-indigo-600 text-white px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 shadow-sm"
                           >
                              مراجعة واعتماد
                           </button>
                         </>
                       ) : (
                         <span className={`text-xs font-bold px-3 py-1 rounded-full border ${req.status === 'APPROVED' ? 'text-green-600 bg-green-50 border-green-200' : 'text-red-600 bg-red-50 border-red-200'}`}>
                           {req.status === 'APPROVED' ? 'تم الاعتماد' : 'تم الرفض'}
                         </span>
                       )}
                    </div>
                 </div>
               ))}
               {requests.length === 0 && <div className="py-20 text-center text-gray-300 italic">لا توجد طلبات تحويل حالياً</div>}
            </div>
          </div>
        ) : (
          <div className="p-20 text-center text-gray-400 italic">سجل حركات المخازن التفصيلي</div>
        )}
      </div>

      {/* Modal: Inventory Move (Tawreed/Sarf/Transfer) */}
      {showMoveModal && (
        <div className="fixed inset-0 z-50 bg-black/60 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-2xl rounded-2xl shadow-2xl animate-in zoom-in-95 overflow-hidden">
            <div className={`p-6 text-white flex justify-between items-center ${moveType === 'ADD' ? 'bg-green-600' : moveType === 'DEDUCT' ? 'bg-red-600' : 'bg-indigo-600'}`}>
              <h3 className="text-xl font-bold flex items-center gap-2">
                {moveType === 'TRANSFER' ? <ArrowRightLeft size={22} /> : moveType === 'ADD' ? <TrendingUp size={22} /> : <TrendingDown size={22} />}
                {moveType === 'TRANSFER' ? 'طلب تحويل داخلي متعدد الأصناف' : moveType === 'ADD' ? 'توريد كمية للمخزن' : 'صرف كمية'}
              </h3>
              <button onClick={() => setShowMoveModal(false)}><X size={24} /></button>
            </div>

            <form onSubmit={handleStockAction} className="p-8 space-y-4 max-h-[80vh] overflow-y-auto custom-scrollbar">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-bold text-gray-600 mb-1">
                    {moveType === 'TRANSFER' ? 'من مخزن (المصدر)' : 'المخزن'}
                  </label>
                  <select name="storeId" required className="w-full border rounded-xl p-3 bg-gray-50 outline-none">
                    <option value="">اختر المخزن...</option>
                    {stores.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                  </select>
                </div>

                {moveType === 'TRANSFER' && (
                  <div>
                    <label className="block text-sm font-bold text-gray-600 mb-1">إلى مخزن (الوجهة)</label>
                    <select name="targetStoreId" required className="w-full border rounded-xl p-3 bg-gray-50 outline-none">
                      <option value="">اختر المخزن...</option>
                      {stores.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                    </select>
                  </div>
                )}
              </div>

              {moveType === 'TRANSFER' ? (
                <div className="border rounded-2xl p-4 bg-gray-50/50 space-y-4">
                   <h4 className="font-bold text-indigo-700 text-sm flex items-center gap-2"><Plus size={16} /> إضافة أصناف للطلب</h4>
                   <div className="flex gap-2 items-end">
                      <div className="flex-1">
                        <label className="block text-[10px] font-bold text-gray-500 mb-1">الصنف</label>
                        <select 
                          value={selectedProductId}
                          onChange={e => setSelectedProductId(e.target.value)}
                          className="w-full border rounded-lg p-2 bg-white"
                        >
                          <option value="">اختر الصنف...</option>
                          {products.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                        </select>
                      </div>
                      <div className="w-24">
                        <label className="block text-[10px] font-bold text-gray-500 mb-1">الكمية</label>
                        <input 
                          type="number" 
                          value={selectedQuantity}
                          onChange={e => setSelectedQuantity(parseFloat(e.target.value))}
                          className="w-full border rounded-lg p-2 bg-white"
                        />
                      </div>
                      <button 
                        type="button" 
                        onClick={addItemToTransfer}
                        className="bg-indigo-600 text-white p-2 rounded-lg"
                      >
                        <Plus size={20} />
                      </button>
                   </div>

                   <div className="space-y-2 max-h-40 overflow-y-auto">
                      {transferItems.map((item, idx) => (
                        <div key={idx} className="bg-white p-3 rounded-xl border flex justify-between items-center shadow-sm">
                           <div>
                              <span className="font-bold text-gray-800">{products.find(p => p.id === item.productId)?.name}</span>
                              <span className="text-xs text-gray-400 mr-2">الكمية: {item.quantity}</span>
                           </div>
                           <button type="button" onClick={() => removeItemFromTransfer(item.productId)} className="text-red-500 hover:bg-red-50 p-1 rounded-md transition-colors">
                              <Trash2 size={16} />
                           </button>
                        </div>
                      ))}
                      {transferItems.length === 0 && <div className="text-center py-4 text-xs text-gray-400 italic">لم يتم إضافة أصناف بعد</div>}
                   </div>
                </div>
              ) : (
                <>
                  <div>
                    <label className="block text-sm font-bold text-gray-600 mb-1">الصنف</label>
                    <select name="productId" required className="w-full border rounded-xl p-3 bg-gray-50">
                      <option value="">اختر الصنف...</option>
                      {products.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                    </select>
                  </div>
                  <div>
                    <label className="block text-sm font-bold text-gray-600 mb-1">الكمية</label>
                    <input name="quantity" type="number" required className="w-full border rounded-xl p-3 bg-gray-50" />
                  </div>
                </>
              )}

              <div>
                <label className="block text-sm font-bold text-gray-600 mb-1">ملاحظات الطلب</label>
                <textarea name="note" className="w-full border rounded-xl p-3 bg-gray-50 h-20 outline-none" placeholder="أي ملاحظات إضافية للمسؤول..."></textarea>
              </div>

              <div className="flex gap-3 pt-4 sticky bottom-0 bg-white">
                <button type="button" onClick={() => setShowMoveModal(false)} className="flex-1 py-4 bg-gray-100 rounded-xl font-bold">إلغاء</button>
                <button type="submit" disabled={loading} className={`flex-1 py-4 text-white rounded-xl font-bold shadow-lg ${moveType === 'ADD' ? 'bg-green-600' : moveType === 'DEDUCT' ? 'bg-red-600' : 'bg-indigo-600'}`}>
                  {loading ? <Loader2 className="animate-spin mx-auto" size={20} /> : moveType === 'TRANSFER' ? 'إرسال طلب التحويل' : 'تأكيد العملية'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Modal: Process Request (Admin View) */}
      {showProcessRequest && (
        <div className="fixed inset-0 z-50 bg-black/60 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-xl rounded-2xl shadow-2xl animate-in zoom-in-95 overflow-hidden">
             <div className="p-6 bg-indigo-700 text-white flex justify-between items-center">
                <h3 className="text-xl font-bold flex items-center gap-2"><Check size={22} /> مراجعة واعتماد التحويل</h3>
                <button onClick={() => setShowProcessRequest(null)}><X size={24} /></button>
             </div>
             <div className="p-8 space-y-6">
                <div className="bg-indigo-50 p-4 rounded-xl border border-indigo-100 grid grid-cols-2 gap-4">
                   <div>
                      <div className="text-[10px] text-indigo-500 font-bold uppercase">من مخزن</div>
                      <div className="font-bold text-indigo-900">{stores.find(s => s.id === showProcessRequest.fromStoreId)?.name}</div>
                   </div>
                   <div>
                      <div className="text-[10px] text-indigo-500 font-bold uppercase">إلى مخزن</div>
                      <div className="font-bold text-indigo-900">{stores.find(s => s.id === showProcessRequest.toStoreId)?.name}</div>
                   </div>
                   <div className="col-span-2">
                      <div className="text-[10px] text-indigo-500 font-bold uppercase">المسؤول عن الطلب</div>
                      <div className="font-bold text-indigo-900">{showProcessRequest.requestedBy}</div>
                   </div>
                </div>

                <div className="space-y-3">
                   <h4 className="font-bold text-gray-700 text-sm">الأصناف المطلوبة (قابلة للتعديل):</h4>
                   {showProcessRequest.items.map((item, idx) => (
                     <div key={idx} className="flex gap-4 items-center bg-gray-50 p-3 rounded-xl border">
                        <div className="flex-1 font-bold text-gray-800">{products.find(p => p.id === item.productId)?.name}</div>
                        <div className="w-24">
                           <input 
                             type="number" 
                             defaultValue={item.quantity} 
                             onChange={(e) => {
                               const updatedItems = [...showProcessRequest.items];
                               updatedItems[idx].quantity = parseFloat(e.target.value);
                               setShowProcessRequest({...showProcessRequest, items: updatedItems});
                             }}
                             className="w-full border rounded-lg p-2 text-center font-bold text-primary-600"
                           />
                        </div>
                     </div>
                   ))}
                </div>

                <div className="flex gap-3 pt-6">
                   <button 
                     onClick={() => processRequest('REJECTED')}
                     className="flex-1 py-4 bg-red-100 text-red-600 rounded-xl font-bold hover:bg-red-200 transition-colors"
                   >
                      رفض الطلب
                   </button>
                   <button 
                     onClick={() => processRequest('APPROVED')}
                     disabled={loading}
                     className="flex-1 py-4 bg-green-600 text-white rounded-xl font-bold shadow-lg hover:bg-green-700 flex items-center justify-center gap-2"
                   >
                      {loading ? <Loader2 className="animate-spin" size={20} /> : <Check size={20} />}
                      اعتماد وتحويل الأرصدة
                   </button>
                </div>
             </div>
          </div>
        </div>
      )}

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 6px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: #f1f1f1; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #0ea5e9; border-radius: 10px; }
      `}</style>
    </div>
  );
};

export default InventoryModule;

import React, { useState, useEffect } from 'react';
import { AR, BLOOD_TYPES } from '../constants.ts';
import { DB } from '../store.ts';
import { LabTest, Patient, LabTestDefinition } from '../types.ts';
import { FlaskConical, Plus, Search, Calendar, FileText, CheckCircle, X, Loader2, Beaker, BookOpen, Clock, Lock, UserPlus } from 'lucide-react';
import SearchableSelect from '../components/SearchableSelect.tsx';

const LabModule: React.FC = () => {
  const [view, setView] = useState<'results' | 'definitions'>('results');
  const [tests, setTests] = useState<any[]>([]);
  const [definitions, setDefinitions] = useState<LabTestDefinition[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [showAddModal, setShowAddModal] = useState(false);
  const [showDefModal, setShowDefModal] = useState(false);
  const [showPatientModal, setShowPatientModal] = useState(false);
  const [showResultModal, setShowResultModal] = useState<any>(null);
  const [patients, setPatients] = useState<Patient[]>([]);

  // State for form controlled components
  const [selectedPatientId, setSelectedPatientId] = useState('');
  const [selectedTestDefId, setSelectedTestDefId] = useState('');

  useEffect(() => {
    loadData();
  }, [view]);

  const loadData = async () => {
    setLoading(true);
    try {
      const p = await DB.getPatients();
      setPatients(p || []);
      const defs = await DB.getLabDefinitions();
      setDefinitions(defs || []);

      if (view === 'results') {
        const t = await DB.getLabTests();
        setTests(t || []);
      }
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleAddTestRequest = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedPatientId || !selectedTestDefId) return alert("يرجى اختيار المريض ونوع التحليل");
    try {
      await DB.addLabTest({
        patientId: selectedPatientId,
        testDefinitionId: selectedTestDefId,
        date: new Date().toISOString().split('T')[0]
      });
      setShowAddModal(false);
      setSelectedPatientId('');
      setSelectedTestDefId('');
      loadData();
    } catch (err) {
      alert("حدث خطأ أثناء حجز التحليل");
    }
  };

  const handleAddDefinition = async (e: React.FormEvent) => {
    e.preventDefault();
    const target = e.target as any;
    try {
      await DB.addLabDefinition({
        name: target.name.value,
        category: target.category.value,
        sampleType: target.sampleType.value,
        normalRangeMale: target.rangeMale.value,
        normalRangeFemale: target.rangeFemale.value,
        normalRangeChild: target.rangeChild.value
      });
      setShowDefModal(false);
      loadData();
    } catch (err) {
      alert("حدث خطأ أثناء حفظ التعريف");
    }
  };

  const handleAddPatient = async (e: React.FormEvent) => {
    e.preventDefault();
    const target = e.target as any;
    try {
      const newP = await DB.addPatient({
        name: target.name.value,
        nationalId: target.nationalId.value,
        phone: target.phone.value,
        bloodType: target.bloodType.value,
        dateOfBirth: target.dateOfBirth.value
      });
      setPatients([...patients, newP]);
      setSelectedPatientId(newP.id);
      setShowPatientModal(false);
    } catch (err) {
      alert("خطأ في إضافة المريض");
    }
  };

  const handleUpdateResult = async (e: React.FormEvent) => {
    e.preventDefault();
    const target = e.target as any;
    try {
      await DB.updateLabResult(showResultModal.id, target.result.value);
      setShowResultModal(null);
      loadData();
    } catch (err) {
      alert("خطأ أثناء تحديث النتيجة");
    }
  };

  const calculateAge = (dob?: string) => {
    if (!dob) return '';
    const birthDate = new Date(dob);
    const today = new Date();
    let age = today.getFullYear() - birthDate.getFullYear();
    const m = today.getMonth() - birthDate.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birthDate.getDate())) {
      age--;
    }
    return `(${age} سنة)`;
  };

  const filteredTests = tests.filter(t => 
    t.lab_test_definitions?.name.includes(searchTerm) || t.patients?.name.includes(searchTerm)
  );

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      {/* Navigation Tabs */}
      <div className="flex gap-2 p-1 bg-gray-200/50 rounded-xl w-fit">
        <button 
          onClick={() => setView('results')}
          className={`px-6 py-2 rounded-lg font-bold transition-all flex items-center gap-2 ${view === 'results' ? 'bg-white shadow-sm text-primary-600' : 'text-gray-500'}`}
        >
          <FlaskConical size={18} /> سجل النتائج
        </button>
        <button 
          onClick={() => setView('definitions')}
          className={`px-6 py-2 rounded-lg font-bold transition-all flex items-center gap-2 ${view === 'definitions' ? 'bg-white shadow-sm text-primary-600' : 'text-gray-500'}`}
        >
          <BookOpen size={18} /> قاموس التحاليل
        </button>
      </div>

      <div className="flex flex-col md:flex-row justify-between items-center gap-4">
        <div className="relative w-full md:w-96">
          <Search className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
          <input 
            type="text" 
            placeholder={view === 'results' ? "بحث بالمريض أو التحليل..." : "بحث في القاموس..."} 
            className="w-full pr-10 pl-4 py-3 border rounded-xl bg-white shadow-sm outline-none focus:ring-2 focus:ring-primary-500"
            value={searchTerm}
            onChange={e => setSearchTerm(e.target.value)}
          />
        </div>

        {view === 'results' ? (
          <button 
            onClick={() => setShowAddModal(true)}
            className="bg-primary-600 text-white px-6 py-3 rounded-xl flex items-center gap-2 hover:bg-primary-700 transition-all font-bold shadow-md"
          >
            <Plus size={20} /> حجز تحليل لمريض
          </button>
        ) : (
          <button 
            onClick={() => setShowDefModal(true)}
            className="bg-indigo-600 text-white px-6 py-3 rounded-xl flex items-center gap-2 hover:bg-indigo-700 transition-all font-bold shadow-md"
          >
            <Plus size={20} /> تعريف تحليل جديد
          </button>
        )}
      </div>

      {view === 'results' ? (
        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden min-h-[400px]">
          {loading ? (
            <div className="flex flex-col items-center justify-center py-20 gap-4 text-gray-400">
              <Loader2 className="animate-spin text-primary-600" size={40} />
              <p className="font-bold">جاري تحميل السجلات...</p>
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full text-right">
                <thead className="bg-gray-50 border-b">
                  <tr>
                    <th className="px-6 py-4 font-bold text-gray-600">التاريخ</th>
                    <th className="px-6 py-4 font-bold text-gray-600">المريض</th>
                    <th className="px-6 py-4 font-bold text-gray-600">التحليل</th>
                    <th className="px-6 py-4 font-bold text-gray-600">الحالة</th>
                    <th className="px-6 py-4 font-bold text-gray-600">النتيجة</th>
                    <th className="px-6 py-4 font-bold text-gray-600">الإجراءات</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-100">
                  {filteredTests.map(test => (
                    <tr key={test.id} className="hover:bg-gray-50 transition-colors">
                      <td className="px-6 py-4 text-gray-500 text-sm font-mono">{test.date}</td>
                      <td className="px-6 py-4">
                        <div className="font-bold text-gray-800">{test.patients?.name}</div>
                        <div className="text-[10px] text-primary-600">{calculateAge(test.patients?.dateOfBirth)}</div>
                      </td>
                      <td className="px-6 py-4">
                        <div className="font-bold text-primary-700">{test.lab_test_definitions?.name}</div>
                        <div className="text-[10px] text-gray-400">عينة: {test.lab_test_definitions?.sampleType}</div>
                      </td>
                      <td className="px-6 py-4">
                        {test.status === 'PENDING' ? (
                          <span className="flex items-center gap-1 text-orange-600 bg-orange-50 px-2 py-1 rounded-lg text-xs font-bold border border-orange-100">
                            <Clock size={12} /> تحت التنفيذ
                          </span>
                        ) : (
                          <span className="flex items-center gap-1 text-green-600 bg-green-50 px-2 py-1 rounded-lg text-xs font-bold border border-green-100">
                            <CheckCircle size={12} /> مكتمل
                          </span>
                        )}
                      </td>
                      <td className="px-6 py-4 font-bold">
                        {test.status === 'COMPLETED' ? (
                          <div className="flex items-center gap-2">
                             <span className="text-primary-600 text-lg">{test.result}</span>
                             <Lock size={12} className="text-gray-300" />
                          </div>
                        ) : '---'}
                      </td>
                      <td className="px-6 py-4">
                        {test.status === 'PENDING' ? (
                          <button 
                            onClick={() => setShowResultModal(test)}
                            className="bg-primary-50 text-primary-600 px-3 py-1 rounded-lg font-bold text-xs hover:bg-primary-600 hover:text-white transition-all"
                          >
                            إدخال النتيجة
                          </button>
                        ) : (
                          <button className="text-gray-400 hover:text-primary-600 transition-colors">
                            <FileText size={18} />
                          </button>
                        )}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {definitions.filter(d => d.name.includes(searchTerm)).map(def => (
            <div key={def.id} className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm hover:border-indigo-300 transition-all">
              <div className="flex justify-between items-start mb-4">
                <div className="bg-indigo-50 text-indigo-600 p-3 rounded-xl"><Beaker size={20} /></div>
                <span className="text-[10px] font-bold bg-gray-100 px-2 py-1 rounded text-gray-500 uppercase">{def.category}</span>
              </div>
              <h4 className="font-bold text-lg mb-1">{def.name}</h4>
              <p className="text-xs text-gray-400 mb-4">نوع العينة: {def.sampleType}</p>

              <div className="space-y-2 border-t pt-4">
                <div className="flex justify-between text-xs">
                  <span className="text-gray-500">للذكور:</span>
                  <span className="font-bold text-indigo-600">{def.normalRangeMale || '---'}</span>
                </div>
                <div className="flex justify-between text-xs">
                  <span className="text-gray-500">للإناث:</span>
                  <span className="font-bold text-pink-600">{def.normalRangeFemale || '---'}</span>
                </div>
                <div className="flex justify-between text-xs">
                  <span className="text-gray-500">للأطفال:</span>
                  <span className="font-bold text-green-600">{def.normalRangeChild || '---'}</span>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Modal: Add Test to Patient */}
      {showAddModal && (
        <div className="fixed inset-0 z-50 bg-black/60 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-lg rounded-2xl shadow-2xl animate-in zoom-in-95">
            <div className="p-6 bg-primary-600 text-white flex justify-between items-center rounded-t-2xl">
              <h3 className="text-xl font-bold flex items-center gap-2"><FlaskConical size={22} /> حجز تحليل جديد</h3>
              <button onClick={() => setShowAddModal(false)}><X size={24} /></button>
            </div>
            <form onSubmit={handleAddTestRequest} className="p-8 space-y-6">
              <div className="relative">
                 <SearchableSelect 
                   label="المريض"
                   placeholder="ابحث عن مريض..."
                   options={patients.map(p => ({ id: p.id, label: `${p.name} ${calculateAge(p.dateOfBirth)}`, subLabel: p.nationalId }))}
                   value={selectedPatientId}
                   onChange={setSelectedPatientId}
                   onAddNew={() => setShowPatientModal(true)}
                   addNewText="إضافة مريض جديد"
                 />
                 <button 
                   type="button" 
                   onClick={() => setShowPatientModal(true)}
                   className="absolute left-0 top-0 mt-1 text-primary-600 font-bold text-xs flex items-center gap-1 hover:underline"
                 >
                   <UserPlus size={14} /> مريض جديد
                 </button>
              </div>

              <SearchableSelect 
                label="نوع التحليل المطلوب"
                placeholder="ابحث عن تحليل من القاموس..."
                options={definitions.map(d => ({ id: d.id, label: d.name, subLabel: d.category }))}
                value={selectedTestDefId}
                onChange={setSelectedTestDefId}
                onAddNew={() => setShowDefModal(true)}
                addNewText="إضافة تعريف تحليل جديد"
              />

              <div className="flex gap-3 pt-4">
                <button type="button" onClick={() => setShowAddModal(false)} className="flex-1 py-4 bg-gray-100 rounded-xl font-bold">إلغاء</button>
                <button type="submit" className="flex-1 py-4 bg-primary-600 text-white rounded-xl font-bold">تأكيد الحجز</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Quick Add Patient Modal */}
      {showPatientModal && (
        <div className="fixed inset-0 z-[60] bg-black/70 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-2xl shadow-2xl animate-in zoom-in-95">
             <div className="p-6 bg-indigo-600 text-white flex justify-between items-center rounded-t-2xl">
                <h3 className="text-xl font-bold flex items-center gap-2"><UserPlus size={22} /> إضافة مريض سريع</h3>
                <button onClick={() => setShowPatientModal(false)}><X size={24} /></button>
             </div>
             <form onSubmit={handleAddPatient} className="p-8 space-y-4">
                <input name="name" required placeholder="اسم المريض بالكامل" className="w-full border rounded-xl p-3 bg-gray-50" />
                <input name="nationalId" required placeholder="الرقم القومي" className="w-full border rounded-xl p-3 bg-gray-50" />
                <input name="phone" required placeholder="رقم الهاتف" className="w-full border rounded-xl p-3 bg-gray-50" />
                <div className="space-y-1">
                   <label className="text-xs font-bold text-gray-500 mr-2">تاريخ الميلاد</label>
                   <input name="dateOfBirth" type="date" required className="w-full border rounded-xl p-3 bg-gray-50" />
                </div>
                <select name="bloodType" className="w-full border rounded-xl p-3 bg-gray-50">
                   {BLOOD_TYPES.map(bt => <option key={bt} value={bt}>{bt}</option>)}
                </select>
                <button type="submit" className="w-full py-4 bg-indigo-600 text-white rounded-xl font-bold shadow-lg">حفظ المريض والمتابعة</button>
             </form>
          </div>
        </div>
      )}

      {/* Modal: Define New Test Type */}
      {showDefModal && (
        <div className="fixed inset-0 z-50 bg-black/60 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-2xl rounded-2xl shadow-2xl animate-in zoom-in-95 overflow-hidden">
            <div className="p-6 bg-indigo-600 text-white flex justify-between items-center">
              <h3 className="text-xl font-bold flex items-center gap-2"><BookOpen size={22} /> تعريف تحليل في القاموس</h3>
              <button onClick={() => setShowDefModal(false)}><X size={24} /></button>
            </div>
            <form onSubmit={handleAddDefinition} className="p-8 grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="md:col-span-2 grid grid-cols-1 md:grid-cols-3 gap-4">
                <div>
                  <label className="block text-xs font-bold text-gray-500 mb-1">اسم التحليل</label>
                  <input name="name" required className="w-full border rounded-lg p-2 bg-gray-50" />
                </div>
                <div>
                  <label className="block text-xs font-bold text-gray-500 mb-1">التصنيف</label>
                  <input name="category" placeholder="مثلاً: كيمياء، دم" className="w-full border rounded-lg p-2 bg-gray-50" />
                </div>
                <div>
                  <label className="block text-xs font-bold text-gray-500 mb-1">نوع العينة</label>
                  <input name="sampleType" placeholder="دم، بول، مسحة" className="w-full border rounded-lg p-2 bg-gray-50" />
                </div>
              </div>

              <div className="md:col-span-2 space-y-4 border-t pt-4">
                <h4 className="font-bold text-sm text-indigo-700">المعدلات الطبيعية (Normal Ranges)</h4>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                  <div>
                    <label className="block text-xs font-bold text-gray-500 mb-1">للذكور</label>
                    <input name="rangeMale" className="w-full border rounded-lg p-2 bg-gray-50 text-xs" />
                  </div>
                  <div>
                    <label className="block text-xs font-bold text-gray-500 mb-1">للإناث</label>
                    <input name="rangeFemale" className="w-full border rounded-lg p-2 bg-gray-50 text-xs" />
                  </div>
                  <div>
                    <label className="block text-xs font-bold text-gray-500 mb-1">للأطفال</label>
                    <input name="rangeChild" className="w-full border rounded-lg p-2 bg-gray-50 text-xs" />
                  </div>
                </div>
              </div>

              <div className="md:col-span-2 flex gap-3 pt-6 border-t">
                <button type="button" onClick={() => setShowDefModal(false)} className="flex-1 py-3 bg-gray-100 rounded-xl font-bold">إلغاء</button>
                <button type="submit" className="flex-1 py-3 bg-indigo-600 text-white rounded-xl font-bold">حفظ التعريف</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Modal: Enter Result */}
      {showResultModal && (
        <div className="fixed inset-0 z-50 bg-black/60 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-2xl shadow-2xl animate-in zoom-in-95">
            <div className="p-6 bg-green-600 text-white flex justify-between items-center rounded-t-2xl">
              <h3 className="text-xl font-bold flex items-center gap-2"><CheckCircle size={22} /> تسجيل نتيجة</h3>
              <button onClick={() => setShowResultModal(null)}><X size={24} /></button>
            </div>
            <form onSubmit={handleUpdateResult} className="p-8 space-y-6">
              <div className="bg-gray-50 p-4 rounded-xl text-center">
                <div className="text-xs text-gray-400">التحليل</div>
                <div className="font-bold text-lg">{showResultModal.lab_test_definitions?.name}</div>
                <div className="text-xs text-primary-600 mt-2">المريض: {showResultModal.patients?.name}</div>
              </div>

              <div>
                <label className="block text-sm font-bold text-gray-600 mb-2">القيمة المقاسة (النتيجة)</label>
                <input name="result" required autoFocus className="w-full border-2 border-primary-100 rounded-xl p-4 text-2xl font-bold text-center outline-none focus:border-primary-500 focus:ring-4 focus:ring-primary-500/10" />
              </div>

              <div className="flex gap-3">
                <button type="button" onClick={() => setShowResultModal(null)} className="flex-1 py-4 bg-gray-100 rounded-xl font-bold">إلغاء</button>
                <button type="submit" className="flex-1 py-4 bg-green-600 text-white rounded-xl font-bold">حفظ وإغلاق</button>
              </div>
              <p className="text-[10px] text-red-500 text-center font-bold">تنبيه: لا يمكن تعديل النتيجة بعد الحفظ لضمان أمان البيانات الطبية.</p>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default LabModule;

import React, { useState, useEffect } from 'react';
import { AR, BLOOD_TYPES } from '../constants.ts';
import { DB } from '../store.ts';
import { LabTest, Patient, LabTestDefinition } from '../types.ts';
import { FlaskConical, Plus, Search, Calendar, FileText, CheckCircle, X, Loader2, Beaker, BookOpen, Clock, Lock, UserPlus } from 'lucide-react';
import SearchableSelect from '../components/SearchableSelect.tsx';

const LabModule: React.FC = () => {
  const [view, setView] = useState<'results' | 'definitions'>('results');
  const [tests, setTests] = useState<any[]>([]);
  const [definitions, setDefinitions] = useState<LabTestDefinition[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [showAddModal, setShowAddModal] = useState(false);
  const [showDefModal, setShowDefModal] = useState(false);
  const [showPatientModal, setShowPatientModal] = useState(false);
  const [showResultModal, setShowResultModal] = useState<any>(null);
  const [patients, setPatients] = useState<Patient[]>([]);

  // State for form controlled components
  const [selectedPatientId, setSelectedPatientId] = useState('');
  const [selectedTestDefId, setSelectedTestDefId] = useState('');

  useEffect(() => {
    loadData();
  }, [view]);

  const loadData = async () => {
    setLoading(true);
    try {
      const p = await DB.getPatients();
      setPatients(p || []);
      const defs = await DB.getLabDefinitions();
      setDefinitions(defs || []);

      if (view === 'results') {
        const t = await DB.getLabTests();
        setTests(t || []);
      }
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleAddTestRequest = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedPatientId || !selectedTestDefId) return alert("يرجى اختيار المريض ونوع التحليل");
    try {
      await DB.addLabTest({
        patientId: selectedPatientId,
        testDefinitionId: selectedTestDefId,
        date: new Date().toISOString().split('T')[0]
      });
      setShowAddModal(false);
      setSelectedPatientId('');
      setSelectedTestDefId('');
      loadData();
    } catch (err) {
      alert("حدث خطأ أثناء حجز التحليل");
    }
  };

  const handleAddDefinition = async (e: React.FormEvent) => {
    e.preventDefault();
    const target = e.target as any;
    try {
      await DB.addLabDefinition({
        name: target.name.value,
        category: target.category.value,
        sampleType: target.sampleType.value,
        normalRangeMale: target.rangeMale.value,
        normalRangeFemale: target.rangeFemale.value,
        normalRangeChild: target.rangeChild.value
      });
      setShowDefModal(false);
      loadData();
    } catch (err) {
      alert("حدث خطأ أثناء حفظ التعريف");
    }
  };

  const handleAddPatient = async (e: React.FormEvent) => {
    e.preventDefault();
    const target = e.target as any;
    try {
      const newP = await DB.addPatient({
        name: target.name.value,
        nationalId: target.nationalId.value,
        phone: target.phone.value,
        bloodType: target.bloodType.value,
        dateOfBirth: target.dateOfBirth.value
      });
      setPatients([...patients, newP]);
      setSelectedPatientId(newP.id);
      setShowPatientModal(false);
    } catch (err) {
      alert("خطأ في إضافة المريض");
    }
  };

  const handleUpdateResult = async (e: React.FormEvent) => {
    e.preventDefault();
    const target = e.target as any;
    try {
      await DB.updateLabResult(showResultModal.id, target.result.value);
      setShowResultModal(null);
      loadData();
    } catch (err) {
      alert("خطأ أثناء تحديث النتيجة");
    }
  };

  const calculateAgeStr = (dob?: string) => {
    if (!dob) return '';
    const birthDate = new Date(dob);
    const today = new Date();
    let age = today.getFullYear() - birthDate.getFullYear();
    const m = today.getMonth() - birthDate.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birthDate.getDate())) {
      age--;
    }
    return `(${age} سنة)`;
  };

  const filteredTests = tests.filter(t => 
    t.lab_test_definitions?.name.includes(searchTerm) || t.patients?.name.includes(searchTerm)
  );

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      {/* Navigation Tabs */}
      <div className="flex gap-2 p-1 bg-gray-200/50 rounded-xl w-fit">
        <button 
          onClick={() => setView('results')}
          className={`px-6 py-2 rounded-lg font-bold transition-all flex items-center gap-2 ${view === 'results' ? 'bg-white shadow-sm text-primary-600' : 'text-gray-500'}`}
        >
          <FlaskConical size={18} /> سجل النتائج
        </button>
        <button 
          onClick={() => setView('definitions')}
          className={`px-6 py-2 rounded-lg font-bold transition-all flex items-center gap-2 ${view === 'definitions' ? 'bg-white shadow-sm text-primary-600' : 'text-gray-500'}`}
        >
          <BookOpen size={18} /> قاموس التحاليل
        </button>
      </div>

      <div className="flex flex-col md:flex-row justify-between items-center gap-4">
        <div className="relative w-full md:w-96">
          <Search className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
          <input 
            type="text" 
            placeholder={view === 'results' ? "بحث بالمريض أو التحليل..." : "بحث في القاموس..."} 
            className="w-full pr-10 pl-4 py-3 border rounded-xl bg-white shadow-sm outline-none focus:ring-2 focus:ring-primary-500"
            value={searchTerm}
            onChange={e => setSearchTerm(e.target.value)}
          />
        </div>

        {view === 'results' ? (
          <button 
            onClick={() => setShowAddModal(true)}
            className="bg-primary-600 text-white px-6 py-3 rounded-xl flex items-center gap-2 hover:bg-primary-700 transition-all font-bold shadow-md"
          >
            <Plus size={20} /> حجز تحليل لمريض
          </button>
        ) : (
          <button 
            onClick={() => setShowDefModal(true)}
            className="bg-indigo-600 text-white px-6 py-3 rounded-xl flex items-center gap-2 hover:bg-indigo-700 transition-all font-bold shadow-md"
          >
            <Plus size={20} /> تعريف تحليل جديد
          </button>
        )}
      </div>

      {view === 'results' ? (
        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden min-h-[400px]">
          {loading ? (
            <div className="flex flex-col items-center justify-center py-20 gap-4 text-gray-400">
              <Loader2 className="animate-spin text-primary-600" size={40} />
              <p className="font-bold">جاري تحميل السجلات...</p>
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full text-right">
                <thead className="bg-gray-50 border-b">
                  <tr>
                    <th className="px-6 py-4 font-bold text-gray-600">التاريخ</th>
                    <th className="px-6 py-4 font-bold text-gray-600">المريض</th>
                    <th className="px-6 py-4 font-bold text-gray-600">التحليل</th>
                    <th className="px-6 py-4 font-bold text-gray-600">الحالة</th>
                    <th className="px-6 py-4 font-bold text-gray-600">النتيجة</th>
                    <th className="px-6 py-4 font-bold text-gray-600">الإجراءات</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-100">
                  {filteredTests.map(test => (
                    <tr key={test.id} className="hover:bg-gray-50 transition-colors">
                      <td className="px-6 py-4 text-gray-500 text-sm font-mono">{test.date}</td>
                      <td className="px-6 py-4">
                        <div className="font-bold text-gray-800">{test.patients?.name}</div>
                        <div className="text-[10px] text-primary-600">{calculateAgeStr(test.patients?.date_of_birth || test.patients?.dateOfBirth)}</div>
                      </td>
                      <td className="px-6 py-4">
                        <div className="font-bold text-primary-700">{test.lab_test_definitions?.name}</div>
                        <div className="text-[10px] text-gray-400">عينة: {test.lab_test_definitions?.sampleType}</div>
                      </td>
                      <td className="px-6 py-4">
                        {test.status === 'PENDING' ? (
                          <span className="flex items-center gap-1 text-orange-600 bg-orange-50 px-2 py-1 rounded-lg text-xs font-bold border border-orange-100">
                            <Clock size={12} /> تحت التنفيذ
                          </span>
                        ) : (
                          <span className="flex items-center gap-1 text-green-600 bg-green-50 px-2 py-1 rounded-lg text-xs font-bold border border-green-100">
                            <CheckCircle size={12} /> مكتمل
                          </span>
                        )}
                      </td>
                      <td className="px-6 py-4 font-bold">
                        {test.status === 'COMPLETED' ? (
                          <div className="flex items-center gap-2">
                             <span className="text-primary-600 text-lg">{test.result}</span>
                             <Lock size={12} className="text-gray-300" />
                          </div>
                        ) : '---'}
                      </td>
                      <td className="px-6 py-4">
                        {test.status === 'PENDING' ? (
                          <button 
                            onClick={() => setShowResultModal(test)}
                            className="bg-primary-50 text-primary-600 px-3 py-1 rounded-lg font-bold text-xs hover:bg-primary-600 hover:text-white transition-all"
                          >
                            إدخال النتيجة
                          </button>
                        ) : (
                          <button className="text-gray-400 hover:text-primary-600 transition-colors">
                            <FileText size={18} />
                          </button>
                        )}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {definitions.filter(d => d.name.includes(searchTerm)).map(def => (
            <div key={def.id} className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm hover:border-indigo-300 transition-all">
              <div className="flex justify-between items-start mb-4">
                <div className="bg-indigo-50 text-indigo-600 p-3 rounded-xl"><Beaker size={20} /></div>
                <span className="text-[10px] font-bold bg-gray-100 px-2 py-1 rounded text-gray-500 uppercase">{def.category}</span>
              </div>
              <h4 className="font-bold text-lg mb-1">{def.name}</h4>
              <p className="text-xs text-gray-400 mb-4">نوع العينة: {def.sampleType}</p>

              <div className="space-y-2 border-t pt-4">
                <div className="flex justify-between text-xs">
                  <span className="text-gray-500">للذكور:</span>
                  <span className="font-bold text-indigo-600">{def.normalRangeMale || '---'}</span>
                </div>
                <div className="flex justify-between text-xs">
                  <span className="text-gray-500">للإناث:</span>
                  <span className="font-bold text-pink-600">{def.normalRangeFemale || '---'}</span>
                </div>
                <div className="flex justify-between text-xs">
                  <span className="text-gray-500">للأطفال:</span>
                  <span className="font-bold text-green-600">{def.normalRangeChild || '---'}</span>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Modal: Add Test to Patient */}
      {showAddModal && (
        <div className="fixed inset-0 z-50 bg-black/60 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-lg rounded-2xl shadow-2xl animate-in zoom-in-95">
            <div className="p-6 bg-primary-600 text-white flex justify-between items-center rounded-t-2xl">
              <h3 className="text-xl font-bold flex items-center gap-2"><FlaskConical size={22} /> حجز تحليل جديد</h3>
              <button onClick={() => setShowAddModal(false)}><X size={24} /></button>
            </div>
            <form onSubmit={handleAddTestRequest} className="p-8 space-y-6">
              <div className="relative group">
                 <div className="flex items-end gap-2">
                    <div className="flex-1">
                       <SearchableSelect 
                         label="اسم المريض"
                         placeholder="ابحث عن مريض..."
                         options={patients.map(p => ({ id: p.id, label: `${p.name} ${calculateAgeStr(p.date_of_birth || p.dateOfBirth)}`, subLabel: p.nationalId }))}
                         value={selectedPatientId}
                         onChange={setSelectedPatientId}
                         onAddNew={() => setShowPatientModal(true)}
                         addNewText="إضافة مريض جديد"
                       />
                    </div>
                    <button 
                      type="button" 
                      onClick={() => setShowPatientModal(true)}
                      title="مريض جديد"
                      className="mb-2 p-3 bg-indigo-50 text-indigo-600 rounded-xl hover:bg-indigo-600 hover:text-white transition-all border border-indigo-100"
                    >
                      <UserPlus size={22} />
                    </button>
                 </div>
              </div>

              <SearchableSelect 
                label="نوع التحليل المطلوب"
                placeholder="ابحث عن تحليل من القاموس..."
                options={definitions.map(d => ({ id: d.id, label: d.name, subLabel: d.category }))}
                value={selectedTestDefId}
                onChange={setSelectedTestDefId}
                onAddNew={() => setShowDefModal(true)}
                addNewText="إضافة تعريف تحليل جديد"
              />

              <div className="flex gap-3 pt-4">
                <button type="button" onClick={() => setShowAddModal(false)} className="flex-1 py-4 bg-gray-100 rounded-xl font-bold">إلغاء</button>
                <button type="submit" className="flex-1 py-4 bg-primary-600 text-white rounded-xl font-bold shadow-lg hover:bg-primary-700">تأكيد الحجز</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Quick Add Patient Modal */}
      {showPatientModal && (
        <div className="fixed inset-0 z-[60] bg-black/70 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-2xl shadow-2xl animate-in zoom-in-95">
             <div className="p-6 bg-indigo-600 text-white flex justify-between items-center rounded-t-2xl">
                <h3 className="text-xl font-bold flex items-center gap-2"><UserPlus size={22} /> إضافة مريض سريع</h3>
                <button onClick={() => setShowPatientModal(false)}><X size={24} /></button>
             </div>
             <form onSubmit={handleAddPatient} className="p-8 space-y-4">
                <input name="name" required placeholder="اسم المريض بالكامل" className="w-full border rounded-xl p-3 bg-gray-50 focus:ring-2 focus:ring-indigo-500 outline-none" />
                <input name="nationalId" required placeholder="الرقم القومي" className="w-full border rounded-xl p-3 bg-gray-50 focus:ring-2 focus:ring-indigo-500 outline-none" />
                <input name="phone" required placeholder="رقم الهاتف" className="w-full border rounded-xl p-3 bg-gray-50 focus:ring-2 focus:ring-indigo-500 outline-none" />
                <div className="space-y-1">
                   <label className="text-xs font-bold text-gray-500 mr-2">تاريخ الميلاد</label>
                   <input name="dateOfBirth" type="date" required className="w-full border rounded-xl p-3 bg-gray-50 focus:ring-2 focus:ring-indigo-500 outline-none" />
                </div>
                <select name="bloodType" className="w-full border rounded-xl p-3 bg-gray-50">
                   {BLOOD_TYPES.map(bt => <option key={bt} value={bt}>{bt}</option>)}
                </select>
                <button type="submit" className="w-full py-4 bg-indigo-600 text-white rounded-xl font-bold shadow-lg hover:bg-indigo-700">حفظ المريض والمتابعة</button>
             </form>
          </div>
        </div>
      )}

      {/* Modal: Define New Test Type */}
      {showDefModal && (
        <div className="fixed inset-0 z-50 bg-black/60 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-2xl rounded-2xl shadow-2xl animate-in zoom-in-95 overflow-hidden">
            <div className="p-6 bg-indigo-600 text-white flex justify-between items-center">
              <h3 className="text-xl font-bold flex items-center gap-2"><BookOpen size={22} /> تعريف تحليل في القاموس</h3>
              <button onClick={() => setShowDefModal(false)}><X size={24} /></button>
            </div>
            <form onSubmit={handleAddDefinition} className="p-8 grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="md:col-span-2 grid grid-cols-1 md:grid-cols-3 gap-4">
                <div>
                  <label className="block text-xs font-bold text-gray-500 mb-1">اسم التحليل</label>
                  <input name="name" required className="w-full border rounded-lg p-2 bg-gray-50" />
                </div>
                <div>
                  <label className="block text-xs font-bold text-gray-500 mb-1">التصنيف</label>
                  <input name="category" placeholder="مثلاً: كيمياء، دم" className="w-full border rounded-lg p-2 bg-gray-50" />
                </div>
                <div>
                  <label className="block text-xs font-bold text-gray-500 mb-1">نوع العينة</label>
                  <input name="sampleType" placeholder="دم، بول، مسحة" className="w-full border rounded-lg p-2 bg-gray-50" />
                </div>
              </div>

              <div className="md:col-span-2 space-y-4 border-t pt-4">
