                      ))}
                      {transferItems.length === 0 && <div className="text-center py-6 text-xs text-gray-400 italic bg-white/50 rounded-xl border-2 border-dashed border-gray-200">لم يتم إضافة أي أصناف للطلب بعد</div>}
