    if (savedUser) {
      try {
        const user = JSON.parse(savedUser);
        setCurrentUser(user);
        setIsAuthenticated(true);
      } catch (e) {
        localStorage.removeItem('dialysis_user');
      }
    }
  }, []);

  const handleLogout = () => {
    setIsAuthenticated(false);
    setCurrentUser(null);
    localStorage.removeItem('dialysis_user');
    localStorage.removeItem('last_activity');
  };

  const handleLoginSuccess = (user: any) => {
    localStorage.setItem('dialysis_user', JSON.stringify(user));
    setCurrentUser(user);
    setIsAuthenticated(true);
  };

  useEffect(() => {
    if (!isAuthenticated) return;

    const resetTimer = () => {
      lastActivityRef.current = Date.now();
      localStorage.setItem('last_activity', lastActivityRef.current.toString());
    };

    const events = ['mousedown', 'mousemove', 'keypress', 'scroll', 'touchstart', 'click'];
    events.forEach(event => window.addEventListener(event, resetTimer));

    const interval = setInterval(() => {
      const now = Date.now();
      if (now - lastActivityRef.current > INACTIVITY_LIMIT) {
        handleLogout(); 
      }
    }, 10000);

    return () => {
      events.forEach(event => window.removeEventListener(event, resetTimer));
      clearInterval(interval);
    };
  }, [isAuthenticated]);

  if (!isAuthenticated) {
    return <LoginModule onLoginSuccess={handleLoginSuccess} />;
  }

  // مصفوفة الصلاحيات المطلوبة لكل موديول
  const tabPermissions: Record<string, Permission> = {
    dashboard: 'VIEW_DASHBOARD',
    reception: 'MANAGE_RECEPTION',
    patients: 'MANAGE_PATIENTS',
    lab: 'MANAGE_LAB',
    billing: 'MANAGE_BILLING',
    employees: 'MANAGE_PAYROLL',
    inventory: 'MANAGE_INVENTORY',
    finance: 'MANAGE_FINANCE',
    users: 'MANAGE_USERS',
    setup: 'SYSTEM_SETUP'
  };

  const hasPermission = (tab: string) => {
    const required = tabPermissions[tab];
    return currentUser?.permissions?.includes(required);
  };

  const renderModule = () => {
    if (!hasPermission(activeTab)) {
      return (
        <div className="flex flex-col items-center justify-center py-20 bg-white rounded-3xl border-2 border-dashed border-gray-100">
           <div className="w-20 h-20 bg-red-50 text-red-500 rounded-full flex items-center justify-center mb-4">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                 <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 15v2m0 0v2m0-2h2m-2 0H10m10-7V7a2 2 0 00-2-2H6a2 2 0 00-2 2v4a2 2 0 002 2h10l4 4V5a2 2 0 00-2-2H6a2 2 0 00-2 2v4a2 2 0 002 2h10l4 4z" />
              </svg>
           </div>
           <h3 className="text-xl font-bold text-gray-800">عذراً، لا تملك صلاحية الوصول</h3>
           <p className="text-gray-500 mt-2">يرجى مراجعة مسؤول النظام لمنحك الصلاحيات المطلوبة.</p>
           <button 
             onClick={() => setActiveTab('dashboard')}
             className="mt-6 px-6 py-2 bg-primary-600 text-white rounded-xl font-bold"
           >
             العودة للرئيسية
           </button>
        </div>
      );
    }

    switch (activeTab) {
      case 'dashboard': return <DashboardModule />;
      case 'reception': return <ReceptionModule />;
      case 'patients': return <PatientModule />;
      case 'lab': return <LabModule />;
      case 'billing': return <BillingModule />;
      case 'employees': return <PayrollModule />;
      case 'inventory': return <InventoryModule />;
      case 'finance': return <FinanceModule />;
      case 'users': return <UsersModule />;
      case 'setup': return <SetupModule />;
      default: return <DashboardModule />;
    }
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} user={currentUser} onLogout={handleLogout}>
      <div className="flex justify-between items-center mb-6 no-print">
        <div className="flex items-center gap-3">
          <div className="w-2 h-2 bg-green-500 rounded-full animate-pulse shadow-[0_0_8px_rgba(34,197,94,0.6)]"></div>
          <div className="text-gray-500 text-sm font-medium">
            مرحباً، <span className="text-primary-600 font-bold">{currentUser?.name}</span>
          </div>
        </div>
      </div>
      {renderModule()}
    </Layout>
  );
};

export default App;

