  const loadData = async () => {
    setLoading(true);
    try {
      const p = await DB.getProducts();
      const s = await DB.getStores();
      setProducts(p || []);
      setStores(s || []);
      const reqs = await DB.getTransferRequests();
      setRequests(reqs || []);
    } catch (err) {
      console.error(err);
