  | 'VIEW_NOTIFICATIONS'
  | 'MANAGE_RECEPTION'
  | 'MANAGE_PATIENTS' 
  | 'MANAGE_LAB'
  | 'MANAGE_BILLING' 
  | 'MANAGE_PAYROLL' 
  | 'MANAGE_INVENTORY' 
  | 'MANAGE_FINANCE' 
  | 'MANAGE_USERS' 
  | 'SYSTEM_SETUP'
  | string; // للسماح بصلاحيات ديناميكية مثل STORE_ACCESS_ID

export interface User {
  id: string;
  name: string;
  username: string;
  password?: string;
  permissions: Permission[];
}

