import React, { useState, useEffect, useRef } from 'react';
import Layout from './components/Layout.tsx';
import DashboardModule from './modules/Dashboard.tsx';
import NotificationsModule from './modules/Notifications.tsx';
import ReceptionModule from './modules/Reception.tsx';
import PatientModule from './modules/Patients.tsx';
import LabModule from './modules/Lab.tsx';
import BillingModule from './modules/Billing.tsx';
import PayrollModule from './modules/Payroll.tsx';
import InventoryModule from './modules/Inventory.tsx';
import FinanceModule from './modules/Finance.tsx';
import SetupModule from './modules/Setup.tsx';
import UsersModule from './modules/Users.tsx';
import LoginModule from './modules/Login.tsx';
import { Permission } from './types.ts';
import { ShieldAlert } from 'lucide-react';

const INACTIVITY_LIMIT = 60 * 60 * 1000;

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const lastActivityRef = useRef<number>(Date.now());
  const [currentUser, setCurrentUser] = useState<any>(null);
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(false);

  useEffect(() => {
    const savedUser = localStorage.getItem('dialysis_user');
    if (savedUser) {
      try {
        const user = JSON.parse(savedUser);
        setCurrentUser(user);
        setIsAuthenticated(true);
      } catch (e) {
        localStorage.removeItem('dialysis_user');
      }
    }
  }, []);

  const handleLogout = () => {
    setIsAuthenticated(false);
    setCurrentUser(null);
    localStorage.removeItem('dialysis_user');
    localStorage.removeItem('last_activity');
  };

  const handleLoginSuccess = (user: any) => {
    localStorage.setItem('dialysis_user', JSON.stringify(user));
    setCurrentUser(user);
    setIsAuthenticated(true);
  };

  useEffect(() => {
    if (!isAuthenticated) return;
    const resetTimer = () => { lastActivityRef.current = Date.now(); };
    const events = ['mousedown', 'mousemove', 'keypress', 'scroll', 'touchstart', 'click'];
    events.forEach(event => window.addEventListener(event, resetTimer));
    const interval = setInterval(() => { if (Date.now() - lastActivityRef.current > INACTIVITY_LIMIT) handleLogout(); }, 10000);
    return () => {
      events.forEach(event => window.removeEventListener(event, resetTimer));
      clearInterval(interval);
    };
  }, [isAuthenticated]);

  if (!isAuthenticated) return <LoginModule onLoginSuccess={handleLoginSuccess} />;

  const tabPermissions: Record<string, Permission> = {
    dashboard: 'VIEW_DASHBOARD',
    notifications: 'VIEW_NOTIFICATIONS',
    reception: 'MANAGE_RECEPTION',
    patients: 'MANAGE_PATIENTS',
    lab: 'MANAGE_LAB',
    billing: 'MANAGE_BILLING',
    employees: 'MANAGE_PAYROLL',
    inventory: 'MANAGE_INVENTORY',
    finance: 'MANAGE_FINANCE',
    users: 'MANAGE_USERS',
    setup: 'SYSTEM_SETUP'
  };

  const hasPermission = (tab: string) => currentUser?.permissions?.includes(tabPermissions[tab]);

  const renderModule = () => {
    if (!hasPermission(activeTab)) {
      return (
        <div className="flex flex-col items-center justify-center py-20 bg-white rounded-3xl border-2 border-dashed border-red-100">
           <ShieldAlert size={64} className="text-red-500 mb-6" />
           <h3 className="text-2xl font-bold text-gray-800">لا تملك صلاحية الوصول</h3>
           <p className="text-gray-500 mt-2">يرجى مراجعة الإدارة لمنحك صلاحية ({tabPermissions[activeTab]}).</p>
           <button onClick={() => setActiveTab('dashboard')} className="mt-8 px-10 py-3 bg-primary-600 text-white rounded-xl font-bold shadow-lg">العودة للرئيسية</button>
        </div>
      );
    }
    switch (activeTab) {
      case 'dashboard': return <DashboardModule />;
      case 'notifications': return <NotificationsModule />;
      case 'reception': return <ReceptionModule />;
      case 'patients': return <PatientModule />;
      case 'lab': return <LabModule />;
      case 'billing': return <BillingModule />;
      case 'employees': return <PayrollModule />;
      case 'inventory': return <InventoryModule />;
      case 'finance': return <FinanceModule />;
      case 'users': return <UsersModule />;
      case 'setup': return <SetupModule />;
      default: return <DashboardModule />;
    }
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} user={currentUser} onLogout={handleLogout}>
      {renderModule()}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { AR, PERMISSIONS_MAP } from '../constants.ts';
import { DB } from '../store.ts';
import { User, Permission, Store, FinancialAccount } from '../types.ts';
import { UserCog, UserPlus, Search, Trash2, Key, UserCheck, Shield, Check, X, Loader2, Lock, Package, Wallet } from 'lucide-react';

const UsersModule: React.FC = () => {
  const [searchTerm, setSearchTerm] = useState('');
  const [showAddModal, setShowAddModal] = useState(false);
  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [newUser, setNewUser] = useState<Partial<User>>({ permissions: [] });

  const [availableStores, setAvailableStores] = useState<Store[]>([]);
  const [availableAccounts, setAvailableAccounts] = useState<FinancialAccount[]>([]);

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    try {
      const [u, s, a] = await Promise.all([
        DB.getUsers(),
        DB.getStores(),
        // نفترض أن DB.getAccounts موجود
        Promise.resolve([]) // DB.accounts كبديل مؤقت إذا لم يكن هناك ميثود جلب
      ]);
      setUsers(u || []);
      setAvailableStores(s || []);
      // لتوضيح الفكرة، سنستخدم حسابات افتراضية إذا كانت فارغة
      setAvailableAccounts(a.length ? a : [{id: '1', name: 'الخزينة الرئيسية', balance: 0, type: 'CASH'}]);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const togglePermission = (perm: Permission) => {
    const current = newUser.permissions || [];
    if (current.includes(perm)) {
      setNewUser({ ...newUser, permissions: current.filter(p => p !== perm) });
    } else {
      setNewUser({ ...newUser, permissions: [...current, perm] });
    }
  };

  const handleAddUser = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newUser.permissions?.length) return alert("يرجى اختيار صلاحية واحدة على الأقل");
    setSubmitting(true);
    try {
      await DB.addUser({
        name: newUser.name || '',
        username: newUser.username || '',
        password: newUser.password,
        permissions: newUser.permissions
      });
      await loadData();
      setShowAddModal(false);
      setNewUser({ permissions: [] });
    } catch (err) {
      alert("حدث خطأ أثناء إضافة المستخدم.");
    } finally {
      setSubmitting(false);
    }
  };

  const filteredUsers = users.filter(u => 
    u.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    u.username.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <div className="flex justify-between items-center gap-4">
        <div className="relative w-96">
          <Search className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
          <input 
            type="text" placeholder="بحث..." 
            className="w-full pr-10 pl-4 py-3 border rounded-xl outline-none"
            value={searchTerm} onChange={e => setSearchTerm(e.target.value)}
          />
        </div>
        <button 
          onClick={() => setShowAddModal(true)}
          className="bg-primary-600 text-white px-6 py-3 rounded-xl flex items-center gap-2 font-bold shadow-md"
        >
          <UserPlus size={20} /> {AR.newUser}
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {filteredUsers.map(user => (
          <div key={user.id} className="bg-white rounded-2xl shadow-sm border p-6">
            <div className="flex justify-between items-start mb-6">
              <div className="flex items-center gap-4">
                <div className="w-14 h-14 bg-primary-600 text-white rounded-xl flex items-center justify-center font-bold text-xl uppercase">{user.name[0]}</div>
                <div>
                  <h4 className="font-bold text-lg">{user.name}</h4>
                  <p className="text-gray-400 text-sm">@{user.username}</p>
                </div>
              </div>
              <button onClick={() => DB.deleteUser(user.id).then(loadData)} className="text-red-400 hover:text-red-600"><Trash2 size={18} /></button>
            </div>
            <div className="flex flex-wrap gap-2">
              {user.permissions?.map(perm => (
                <span key={perm} className="px-3 py-1 bg-gray-50 text-gray-600 text-[10px] font-bold rounded-lg border flex items-center gap-1">
                  <Shield size={10} /> {PERMISSIONS_MAP[perm] || (perm.startsWith('STORE_') ? 'دخول مخزن' : perm.startsWith('ACC_') ? 'دخول خزينة' : perm)}
                </span>
              ))}
            </div>
          </div>
        ))}
      </div>

      {showAddModal && (
        <div className="fixed inset-0 z-50 bg-black/60 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-3xl rounded-3xl shadow-2xl flex flex-col max-h-[90vh] overflow-hidden">
            <div className="p-6 bg-primary-600 text-white flex justify-between items-center">
              <h3 className="text-xl font-bold flex items-center gap-2"><UserCheck size={22} /> إنشاء حساب مستخدم</h3>
              <button onClick={() => setShowAddModal(false)}><X size={24} /></button>
            </div>

            <div className="p-8 overflow-y-auto custom-scrollbar space-y-8">
              <form id="addUserForm" onSubmit={handleAddUser} className="space-y-6">
                <div className="grid grid-cols-2 gap-4">
                  <input required placeholder="الاسم بالكامل" className="w-full border rounded-xl p-3 bg-gray-50" onChange={e => setNewUser({...newUser, name: e.target.value})} />
                  <input required placeholder="اسم الدخول" className="w-full border rounded-xl p-3 bg-gray-50" onChange={e => setNewUser({...newUser, username: e.target.value})} />
                  <input required type="password" placeholder="كلمة المرور" className="w-full border rounded-xl p-3 bg-gray-50" onChange={e => setNewUser({...newUser, password: e.target.value})} />
                </div>

                <div className="space-y-4">
                  <h4 className="font-black text-gray-800 border-r-4 border-primary-600 pr-3">الصلاحيات الإدارية العامة</h4>
                  <div className="grid grid-cols-2 md:grid-cols-3 gap-2">
                    {Object.entries(PERMISSIONS_MAP).map(([key, val]) => (
                      <button key={key} type="button" onClick={() => togglePermission(key as Permission)} className={`p-3 rounded-xl border text-xs font-bold transition-all ${newUser.permissions?.includes(key as Permission) ? 'bg-primary-600 text-white border-primary-600' : 'bg-white hover:bg-primary-50'}`}>
                        {val}
                      </button>
                    ))}
                  </div>
                </div>

                <div className="space-y-4">
                  <h4 className="font-black text-gray-800 border-r-4 border-amber-600 pr-3 flex items-center gap-2">
                     <Package size={18} className="text-amber-600" /> صلاحيات المخازن
                  </h4>
