import React, { useState, useEffect } from 'react';
import { AR, PERMISSIONS_MAP } from '../constants.ts';
import { DB } from '../store.ts';
import { User, Permission, Store, FinancialAccount } from '../types.ts';
import { UserPlus, Search, Trash2, UserCheck, Shield, Check, X, Loader2, Package, Wallet } from 'lucide-react';

const UsersModule: React.FC = () => {
  const [searchTerm, setSearchTerm] = useState('');
  const [showAddModal, setShowAddModal] = useState(false);
  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [newUser, setNewUser] = useState<Partial<User>>({ permissions: [] });

  const [availableStores, setAvailableStores] = useState<Store[]>([]);
  const [availableAccounts, setAvailableAccounts] = useState<FinancialAccount[]>([]);

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    try {
      const [u, s, a] = await Promise.all([
        DB.getUsers(),
        DB.getStores(),
        DB.getAccounts()
      ]);
      setUsers(u || []);
      setAvailableStores(s || []);
      setAvailableAccounts(a || []);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const togglePermission = (perm: Permission) => {
    const current = newUser.permissions || [];
    if (current.includes(perm)) {
      setNewUser({ ...newUser, permissions: current.filter(p => p !== perm) });
    } else {
      setNewUser({ ...newUser, permissions: [...current, perm] });
    }
  };

  const handleAddUser = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newUser.permissions?.length) return alert("يرجى اختيار صلاحية واحدة على الأقل");
    setSubmitting(true);
    try {
      await DB.addUser({
        name: newUser.name || '',
        username: newUser.username || '',
        password: newUser.password,
        permissions: newUser.permissions
      });
      await loadData();
      setShowAddModal(false);
      setNewUser({ permissions: [] });
    } catch (err) {
      alert("حدث خطأ أثناء إضافة المستخدم. تأكد من إعداد الجداول في Supabase.");
    } finally {
      setSubmitting(false);
    }
  };

  const filteredUsers = users.filter(u => 
    u.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    u.username.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <div className="flex justify-between items-center gap-4">
        <div className="relative w-96">
          <Search className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
          <input 
            type="text" placeholder="بحث عن مستخدم..." 
            className="w-full pr-10 pl-4 py-3 border rounded-xl outline-none"
            value={searchTerm} onChange={e => setSearchTerm(e.target.value)}
          />
        </div>
        <button onClick={() => setShowAddModal(true)} className="bg-primary-600 text-white px-6 py-3 rounded-xl flex items-center gap-2 font-bold shadow-md">
          <UserPlus size={20} /> {AR.newUser}
        </button>
      </div>

      {loading ? (
        <div className="flex justify-center py-20"><Loader2 className="animate-spin" size={40} /></div>
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          {filteredUsers.map(user => (
            <div key={user.id} className="bg-white rounded-2xl shadow-sm border p-6 hover:shadow-md transition-all">
              <div className="flex justify-between items-start mb-6">
                <div className="flex items-center gap-4">
                  <div className="w-14 h-14 bg-primary-600 text-white rounded-xl flex items-center justify-center font-bold text-xl uppercase">{user.name[0]}</div>
                  <div>
                    <h4 className="font-bold text-lg">{user.name}</h4>
                    <p className="text-gray-400 text-sm">@{user.username}</p>
                  </div>
                </div>
                <button onClick={() => DB.deleteUser(user.id).then(loadData)} className="text-red-400 hover:text-red-600 p-2"><Trash2 size={18} /></button>
              </div>
              <div className="flex flex-wrap gap-2">
                {user.permissions?.map(perm => (
                  <span key={perm} className="px-3 py-1 bg-gray-50 text-gray-600 text-[10px] font-bold rounded-lg border flex items-center gap-1">
                    <Shield size={10} /> 
                    {PERMISSIONS_MAP[perm] || 
                     (perm.startsWith('STORE_ACCESS_') ? `مخزن: ${availableStores.find(s => `STORE_ACCESS_${s.id}` === perm)?.name || 'غير معروف'}` : 
                      perm.startsWith('ACC_ACCESS_') ? `خزينة: ${availableAccounts.find(a => `ACC_ACCESS_${a.id}` === perm)?.name || 'غير معروف'}` : 
                      perm)}
                  </span>
                ))}
              </div>
            </div>
          ))}
        </div>
      )}

      {showAddModal && (
        <div className="fixed inset-0 z-50 bg-black/60 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-3xl rounded-3xl shadow-2xl flex flex-col max-h-[90vh] overflow-hidden">
            <div className="p-6 bg-primary-600 text-white flex justify-between items-center">
              <h3 className="text-xl font-bold flex items-center gap-2"><UserCheck size={22} /> إنشاء حساب مستخدم</h3>
              <button onClick={() => setShowAddModal(false)}><X size={24} /></button>
            </div>
            <div className="p-8 overflow-y-auto custom-scrollbar space-y-8">
              <form id="addUserForm" onSubmit={handleAddUser} className="space-y-6">
                <div className="grid grid-cols-2 gap-4">
                  <input required placeholder="الاسم بالكامل" className="w-full border rounded-xl p-3 bg-gray-50" onChange={e => setNewUser({...newUser, name: e.target.value})} />
                  <input required placeholder="اسم الدخول" className="w-full border rounded-xl p-3 bg-gray-50" onChange={e => setNewUser({...newUser, username: e.target.value})} />
                  <input required type="password" placeholder="كلمة المرور" className="w-full border rounded-xl p-3 bg-gray-50" onChange={e => setNewUser({...newUser, password: e.target.value})} />
                </div>
                <div className="space-y-4">
                  <h4 className="font-black text-gray-800 border-r-4 border-primary-600 pr-3">الصلاحيات الإدارية العامة</h4>
                  <div className="grid grid-cols-2 md:grid-cols-3 gap-2">
                    {Object.entries(PERMISSIONS_MAP).map(([key, val]) => (
                      <button key={key} type="button" onClick={() => togglePermission(key as Permission)} className={`p-3 rounded-xl border text-xs font-bold transition-all ${newUser.permissions?.includes(key as Permission) ? 'bg-primary-600 text-white border-primary-600' : 'bg-white hover:bg-primary-50'}`}>
                        {val}
                      </button>
                    ))}
                  </div>
                </div>
                <div className="space-y-4">
                  <h4 className="font-black text-gray-800 border-r-4 border-amber-600 pr-3 flex items-center gap-2"><Package size={18} className="text-amber-600" /> صلاحيات المخازن المحددة</h4>
                  <div className="grid grid-cols-2 md:grid-cols-3 gap-2">
                    {availableStores.map(store => {
                      const perm = `STORE_ACCESS_${store.id}`;
                      return (
                        <button key={store.id} type="button" onClick={() => togglePermission(perm)} className={`p-3 rounded-xl border text-xs font-bold transition-all flex items-center justify-between ${newUser.permissions?.includes(perm) ? 'bg-amber-600 text-white border-amber-600' : 'bg-white hover:bg-amber-50'}`}>
                          <span>{store.name}</span>
                          {newUser.permissions?.includes(perm) && <Check size={14} />}
                        </button>
                      );
                    })}
                  </div>
                </div>
                <div className="space-y-4">
                  <h4 className="font-black text-gray-800 border-r-4 border-emerald-600 pr-3 flex items-center gap-2"><Wallet size={18} className="text-emerald-600" /> صلاحيات الخزائن المحددة</h4>
                  <div className="grid grid-cols-2 md:grid-cols-3 gap-2">
                    {availableAccounts.map(acc => {
                      const perm = `ACC_ACCESS_${acc.id}`;
                      return (
                        <button key={acc.id} type="button" onClick={() => togglePermission(perm)} className={`p-3 rounded-xl border text-xs font-bold transition-all flex items-center justify-between ${newUser.permissions?.includes(perm) ? 'bg-emerald-600 text-white border-emerald-600' : 'bg-white hover:bg-emerald-50'}`}>
                          <span>{acc.name}</span>
                          {newUser.permissions?.includes(perm) && <Check size={14} />}
                        </button>
                      );
                    })}
                  </div>
                </div>
              </form>
            </div>
            <div className="p-6 border-t bg-gray-50 flex gap-3">
              <button type="button" onClick={() => setShowAddModal(false)} className="flex-1 py-4 bg-white border rounded-xl font-bold">إلغاء</button>
              <button form="addUserForm" type="submit" disabled={submitting} className="flex-1 py-4 bg-primary-600 text-white rounded-xl font-bold">
                 {submitting ? <Loader2 className="animate-spin mx-auto" /> : 'حفظ المستخدم'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default UsersModule;

import { 
  Patient, DialysisSession, Service, Invoice, Product, 
  Store, StockTransaction, Employee, FinancialAccount, 
  Transaction, FundingEntity, ShiftRecord, LabTest, LabTestDefinition, AuditLog,
  User, Permission, TransferRequest
} from './types.ts';
import { supabase } from './supabase.ts';

export class DB {
  // --- Auth ---
  static async login(username: string, password: string): Promise<User | null> {
    const { data, error } = await supabase
      .from('system_users')
      .select('*')
      .eq('username', username)
      .eq('password', password)
      .single();

    if (error || !data) return null;
    await this.log('تسجيل دخول', `دخل المستخدم ${data.name} إلى النظام`);
    return data as User;
  }

  // --- Patients ---
  static async getPatients() {
    const { data, error } = await supabase.from('patients').select('*').order('createdAt', { ascending: false });
    if (error) { console.error(error); throw error; }
    return data;
  }

  static async addPatient(p: Partial<Patient>) {
    const { data, error } = await supabase.from('patients').insert([p]).select();
    if (error) { console.error(error); throw error; }
    await this.log('إضافة مريض', `تمت إضافة المريض ${p.name}`);
    return data[0];
  }

  // --- Financial Accounts ---
  static async getAccounts() {
    const { data, error } = await supabase.from('financial_accounts').select('*').order('name');
    if (error) { console.error(error); throw error; }
    return data;
  }

  static async addAccount(acc: Partial<FinancialAccount>) {
    const { data, error } = await supabase.from('financial_accounts').insert([acc]).select();
    if (error) { console.error(error); throw error; }
    return data[0];
  }

  static async deleteAccount(id: string) {
    const { error } = await supabase.from('financial_accounts').delete().eq('id', id);
    if (error) throw error;
  }

  // --- Inventory & Stores ---
