              ) : activeTab === 'products' ? (
                <div className="space-y-4">
                  <input name="name" required placeholder="اسم الصنف (مثلاً: فلتر غسيل)" className="w-full border rounded-xl p-3 bg-gray-50 outline-none" />
                  <input name="unit" required placeholder="الوحدة (قطعة، علبة، لتر)" className="w-full border rounded-xl p-3 bg-gray-50 outline-none" />
                  <div className="grid grid-cols-2 gap-3">
                    <input name="minStock" type="number" placeholder="حد الطلب" className="w-full border rounded-xl p-3 bg-gray-50 outline-none" />
                    <input name="price" type="number" step="0.01" placeholder="سعر الشراء" className="w-full border rounded-xl p-3 bg-gray-50 outline-none" />
                  </div>
