import React, { useState, useEffect } from 'react';
import { AR } from '../constants.ts';
import { DB } from '../store.ts';
import { Product, Store, StockTransaction, TransferRequest } from '../types.ts';
import { 
  Package, ArrowLeftRight, TrendingUp, TrendingDown, ClipboardList, 
  Plus, Search, ArrowRightLeft, Loader2, X, Check, Bell, 
  AlertCircle, Trash2, MapPin, CheckCircle, Clock, FileText, ShoppingCart, DollarSign, Calculator, ArrowDownRight
} from 'lucide-react';

const InventoryModule: React.FC = () => {
  const [activeSubTab, setActiveSubTab] = useState<'stock' | 'transfers' | 'requests'>('stock');
  const [showMoveModal, setShowMoveModal] = useState(false);
  const [moveType, setMoveType] = useState<'ADD' | 'DEDUCT' | 'TRANSFER'>('ADD');

  const [loading, setLoading] = useState(false);
  const [products, setProducts] = useState<Product[]>([]);
  const [stores, setStores] = useState<Store[]>([]);
  const [requests, setRequests] = useState<TransferRequest[]>([]);

  const [voucherItems, setVoucherItems] = useState<{ productId: string, quantity: number, price: number }[]>([]);
  const [selectedProductId, setSelectedProductId] = useState('');
  const [selectedQuantity, setSelectedQuantity] = useState(1);
  const [selectedPrice, setSelectedPrice] = useState(0);

  const [documentNumber, setDocumentNumber] = useState('');
  const [voucherNote, setVoucherNote] = useState('');
  const [targetStoreId, setTargetStoreId] = useState('');

  useEffect(() => { loadData(); }, [activeSubTab]);

  const loadData = async () => {
    setLoading(true);
    try {
      const [p, s, r] = await Promise.all([DB.getProducts(), DB.getStores(), DB.getTransferRequests()]);
      setProducts(p || []);
      setStores(s || []);
      setRequests(r || []);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const generateDocNumber = (type: string) => {
    const year = new Date().getFullYear();
    const random = Math.floor(1000 + Math.random() * 9000);
    return `INV-${type}-${year}-${random}`;
  };

  const openModal = (type: 'ADD' | 'DEDUCT' | 'TRANSFER') => {
    setMoveType(type);
    setVoucherItems([]);
    setDocumentNumber(generateDocNumber(type));
    setVoucherNote('');
    if (type === 'TRANSFER') {
      setTargetStoreId(stores.find(s => !s.isMain)?.id || '');
    }
    setShowMoveModal(true);
  };

  const addItemToVoucher = () => {
    if (!selectedProductId || selectedQuantity <= 0) return;
    if (voucherItems.find(i => i.productId === selectedProductId)) return alert("الصنف مضاف بالفعل");
    const p = products.find(prod => prod.id === selectedProductId);
    setVoucherItems([...voucherItems, { productId: selectedProductId, quantity: selectedQuantity, price: selectedPrice || p?.price || 0 }]);
    setSelectedProductId('');
    setSelectedQuantity(1);
    setSelectedPrice(0);
  };

  const removeItemFromVoucher = (pid: string) => setVoucherItems(voucherItems.filter(i => i.productId !== pid));

  const handleVoucherAction = async (e: React.FormEvent) => {
    e.preventDefault();
    if (voucherItems.length === 0) return alert("يرجى إضافة أصناف أولاً");
    setLoading(true);
    try {
      const storeId = (e.target as any).storeId.value;
      if (moveType === 'TRANSFER') {
        await DB.createTransferRequest({
          fromStoreId: storeId,
          toStoreId: targetStoreId,
          items: voucherItems.map(i => ({ productId: i.productId, quantity: i.quantity })),
          status: 'PENDING',
          date: new Date().toISOString().split('T')[0],
          note: `${documentNumber} | ${voucherNote}`
        });
      } else {
        for (const item of voucherItems) {
          await DB.addStockTransaction({
            productId: item.productId,
            storeId: storeId,
            type: moveType,
            quantity: item.quantity,
            date: new Date().toISOString().split('T')[0],
            note: `${documentNumber} | ${voucherNote}`
          });
        }
      }
      setShowMoveModal(false);
      setVoucherItems([]);
      alert("تمت العملية بنجاح برقم مستند: " + documentNumber);
      loadData();
    } catch (err) {
      alert("حدث خطأ أثناء تنفيذ العملية المخزنية.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 no-print">
        <div className="flex gap-2 p-1 bg-gray-200/50 rounded-xl w-fit">
          <button onClick={() => setActiveSubTab('stock')} className={`px-6 py-2 rounded-lg font-bold transition-all ${activeSubTab === 'stock' ? 'bg-white shadow-sm text-primary-600' : 'text-gray-500'}`}>الأرصدة</button>
          <button onClick={() => setActiveSubTab('requests')} className={`px-6 py-2 rounded-lg font-bold transition-all ${activeSubTab === 'requests' ? 'bg-white shadow-sm text-indigo-600' : 'text-gray-500'}`}>طلبات التحويل ({requests.filter(r => r.status === 'PENDING').length})</button>
        </div>

        <div className="flex gap-2">
           <button 
             onClick={() => openModal('TRANSFER')}
             className="bg-indigo-600 text-white px-5 py-3 rounded-xl text-sm font-bold flex items-center gap-2 hover:bg-indigo-700 shadow-md transition-all"
           >
             <ArrowLeftRight size={18} /> طلب تحويل داخلي
           </button>
           <button onClick={() => openModal('DEDUCT')} className="bg-orange-600 text-white px-5 py-3 rounded-xl text-sm font-bold flex items-center gap-2 shadow-md hover:bg-orange-700 transition-all">
             <TrendingDown size={18} /> إذن صـــرف
           </button>
           <button onClick={() => openModal('ADD')} className="bg-green-600 text-white px-5 py-3 rounded-xl text-sm font-bold flex items-center gap-2 shadow-md hover:bg-green-700 transition-all">
             <TrendingUp size={18} /> فاتورة توريد
           </button>
        </div>
      </div>

      <div className="bg-white rounded-3xl shadow-sm border overflow-hidden min-h-[400px]">
        {activeSubTab === 'stock' ? (
          <div className="p-8">
             <h3 className="font-bold text-xl text-gray-800 mb-6 flex items-center gap-2">الأرصدة الحالية بالمخازن</h3>
             <table className="w-full text-right">
                <thead className="bg-gray-50 border-b">
                  <tr><th className="px-6 py-4 font-bold text-gray-600 text-xs">الصنف</th><th className="px-6 py-4 font-bold text-gray-600 text-xs">الوحدة</th><th className="px-6 py-4 font-bold text-gray-600 text-xs text-center">الرصيد التقديري</th></tr>
                </thead>
                <tbody className="divide-y">
                  {products.map(p => (
                    <tr key={p.id} className="hover:bg-gray-50">
                      <td className="px-6 py-4 font-bold text-gray-700">{p.name}</td>
                      <td className="px-6 py-4 text-gray-500">{p.unit}</td>
                      <td className="px-6 py-4 font-black text-primary-700 text-center text-xl">0</td>
                    </tr>
                  ))}
                  {products.length === 0 && (
                    <tr><td colSpan={3} className="py-20 text-center text-gray-300 italic">لا توجد أصناف معرفة في النظام</td></tr>
                  )}
                </tbody>
             </table>
          </div>
        ) : (
          <div className="p-8">
             <h3 className="font-bold text-xl text-gray-800 mb-6">طلبات التحويل بين المخازن</h3>
             {requests.length === 0 ? (
               <div className="py-20 text-center text-gray-300 italic">لا توجد طلبات تحويل حالياً</div>
             ) : (
               <div className="space-y-4">
                  {requests.map(req => (
                    <div key={req.id} className="p-5 border rounded-2xl flex justify-between items-center bg-gray-50/50">
                       <div>
                          <div className="font-bold text-gray-800">طلب رقم: {req.id.slice(0, 8)}...</div>
                          <div className="text-xs text-gray-500">من: {stores.find(s => s.id === req.fromStoreId)?.name} | إلى: {stores.find(s => s.id === req.toStoreId)?.name}</div>
                       </div>
                       <div className={`px-4 py-1.5 rounded-full text-xs font-bold border ${req.status === 'PENDING' ? 'bg-yellow-50 text-yellow-700 border-yellow-200' : 'bg-green-50 text-green-700 border-green-200'}`}>
                          {req.status === 'PENDING' ? 'قيد الانتظار' : 'تم التنفيذ'}
                       </div>
                    </div>
                  ))}
               </div>
             )}
          </div>
        )}
      </div>

      {showMoveModal && (
        <div className="fixed inset-0 z-50 bg-black/60 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-5xl rounded-3xl shadow-2xl flex flex-col max-h-[95vh] overflow-hidden">
            <div className={`p-6 text-white flex justify-between items-center ${moveType === 'ADD' ? 'bg-green-600' : moveType === 'TRANSFER' ? 'bg-indigo-600' : 'bg-orange-600'}`}>
              <div>
                <h3 className="text-xl font-bold">{moveType === 'ADD' ? 'تسجيل توريد (فاتورة شراء)' : moveType === 'TRANSFER' ? 'إنشاء طلب تحويل مخزني' : 'إصدار إذن صرف مخزني'}</h3>
                <p className="text-[10px] opacity-80 mt-1">رقم المستند التلقائي: {documentNumber}</p>
              </div>
              <button onClick={() => setShowMoveModal(false)}><X size={24} /></button>
            </div>

            <form onSubmit={handleVoucherAction} className="p-8 space-y-6 overflow-y-auto flex-1">
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 bg-gray-50 p-6 rounded-3xl border">
                <div>
                  <label className="block text-xs font-bold text-gray-500 uppercase mb-1">
                    {moveType === 'TRANSFER' ? 'مخزن المصدر (الذي سيخرج منه الصنف)' : 'المخزن المعني'}
                  </label>
                  <select name="storeId" required className="w-full border rounded-xl p-3 bg-white font-bold outline-none focus:ring-2 focus:ring-primary-500">
                    <option value="">-- اختر المخزن --</option>
                    {stores.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                  </select>
                </div>
                {moveType === 'TRANSFER' && (
                  <div>
                    <label className="block text-xs font-bold text-indigo-600 uppercase mb-1">المخزن المستلم (ثابت)</label>
                    <div className="w-full border-2 border-indigo-100 rounded-xl p-3 bg-indigo-50 font-bold text-indigo-800 flex items-center gap-2">
                       <MapPin size={16} /> {stores.find(s => s.id === targetStoreId)?.name || 'غير محدد'}
                    </div>
                    <p className="text-[10px] text-indigo-400 mt-1">* يتم تحديد المخزن المستلم تلقائياً بناءً على وجهة الصرف.</p>
                  </div>
                )}
                <div className="md:col-span-1">
                   <label className="block text-xs font-bold text-gray-500 uppercase mb-1">رقم المستند (تم توليده)</label>
                   <input type="text" value={documentNumber} readOnly className="w-full border rounded-xl p-3 bg-gray-100 font-mono text-sm text-gray-500" />
                </div>
              </div>

              {/* إضافة أصناف */}
              <div className="bg-primary-50/50 p-6 rounded-3xl border-2 border-dashed border-primary-200">
                 <div className="grid grid-cols-12 gap-4 items-end">
                    <div className="col-span-12 md:col-span-6">
                       <label className="block text-xs font-bold text-primary-700 mb-1">اختيار الصنف</label>
                       <select value={selectedProductId} onChange={e => setSelectedProductId(e.target.value)} className="w-full border rounded-xl p-3 bg-white font-bold outline-none">
                         <option value="">-- اختر صنفاً --</option>
                         {products.map(p => <option key={p.id} value={p.id}>{p.name} ({p.unit})</option>)}
                       </select>
                    </div>
                    <div className="col-span-6 md:col-span-2">
                       <label className="block text-xs font-bold text-primary-700 mb-1">الكمية</label>
                       <input type="number" value={selectedQuantity} onChange={e => setSelectedQuantity(parseFloat(e.target.value))} className="w-full border rounded-xl p-3 bg-white text-center font-bold outline-none" />
                    </div>
                    {moveType === 'ADD' && (
                      <div className="col-span-6 md:col-span-2">
                        <label className="block text-xs font-bold text-primary-700 mb-1">السعر</label>
                        <input type="number" placeholder="سعر الشراء" value={selectedPrice} onChange={e => setSelectedPrice(parseFloat(e.target.value))} className="w-full border rounded-xl p-3 bg-white text-center outline-none" />
                      </div>
                    )}
                    <div className={`col-span-12 md:col-span-${moveType === 'ADD' ? '2' : '4'}`}>
                       <button type="button" onClick={addItemToVoucher} className="w-full py-3 bg-primary-600 text-white rounded-xl font-bold shadow-lg hover:bg-primary-700 transition-all">إضافة</button>
                    </div>
                 </div>
              </div>

              <div className="border rounded-3xl overflow-hidden shadow-inner bg-white">
                 <table className="w-full text-right">
                    <thead className="bg-gray-100">
                       <tr><th className="px-6 py-3 font-bold text-xs uppercase">اسم الصنف</th><th className="px-6 py-3 font-bold text-center text-xs">الكمية</th>{moveType === 'ADD' && <th className="px-6 py-3 text-center text-xs">السعر</th>}<th className="px-6 py-3 text-left text-xs">حذف</th></tr>
                    </thead>
                    <tbody className="divide-y">
                       {voucherItems.map((item, idx) => (
                         <tr key={idx} className="hover:bg-gray-50">
                            <td className="px-6 py-3 font-bold">{products.find(p => p.id === item.productId)?.name}</td>
                            <td className="px-6 py-3 text-center font-black text-primary-600">{item.quantity}</td>
                            {moveType === 'ADD' && <td className="px-6 py-3 text-center text-emerald-600 font-bold">{item.price} ج.م</td>}
                            <td className="px-6 py-3 text-left"><button type="button" onClick={() => removeItemFromVoucher(item.productId)} className="text-red-400 p-2 hover:bg-red-50 rounded-lg transition-all"><Trash2 size={16} /></button></td>
                         </tr>
                       ))}
                       {voucherItems.length === 0 && (
                         <tr><td colSpan={moveType === 'ADD' ? 4 : 3} className="py-10 text-center text-gray-300 italic">القائمة فارغة، أضف أصنافاً للبدء</td></tr>
                       )}
                    </tbody>
                 </table>
              </div>

              <div>
                <label className="block text-xs font-bold text-gray-500 mb-1">ملاحظات إضافية</label>
                <textarea value={voucherNote} onChange={e => setVoucherNote(e.target.value)} className="w-full border rounded-2xl p-4 bg-gray-50 outline-none h-20 focus:bg-white transition-all" placeholder="اكتب أي ملاحظات تخص هذا المستند..."></textarea>
              </div>
            </form>

            <div className="p-8 border-t bg-gray-50 flex gap-4">
              <button onClick={() => setShowMoveModal(false)} className="flex-1 py-4 bg-white border-2 rounded-2xl font-bold text-gray-500 hover:bg-gray-100 transition-all">إلغاء</button>
              <button onClick={handleVoucherAction} className={`flex-[2] py-4 text-white rounded-2xl font-bold shadow-xl transition-all ${moveType === 'ADD' ? 'bg-green-600 hover:bg-green-700' : moveType === 'TRANSFER' ? 'bg-indigo-600 hover:bg-indigo-700' : 'bg-orange-600 hover:bg-orange-700'}`}>
                {moveType === 'TRANSFER' ? 'إرسال طلب التحويل للمخزن المستلم' : 'تأكيد وحفظ المستند'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default InventoryModule;

import React, { useState, useEffect } from 'react';
import { AR, BLOOD_TYPES } from '../constants.ts';
import { DB } from '../store.ts';
import { LabTest, Patient, LabTestDefinition } from '../types.ts';
import { FlaskConical, Plus, Search, Calendar, FileText, CheckCircle, X, Loader2, Beaker, BookOpen, Clock, Lock, UserPlus } from 'lucide-react';
import SearchableSelect from '../components/SearchableSelect.tsx';

const LabModule: React.FC = () => {
  const [view, setView] = useState<'results' | 'definitions'>('results');
  const [tests, setTests] = useState<any[]>([]);
  const [definitions, setDefinitions] = useState<LabTestDefinition[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [showAddModal, setShowAddModal] = useState(false);
  const [showDefModal, setShowDefModal] = useState(false);
  const [showPatientModal, setShowPatientModal] = useState(false);
  const [showResultModal, setShowResultModal] = useState<any>(null);
  const [patients, setPatients] = useState<Patient[]>([]);

  // State for form controlled components
  const [selectedPatientId, setSelectedPatientId] = useState('');
  const [selectedTestDefId, setSelectedTestDefId] = useState('');

  useEffect(() => {
    loadData();
  }, [view]);

  const loadData = async () => {
    setLoading(true);
    try {
      const p = await DB.getPatients();
      setPatients(p || []);
      const defs = await DB.getLabDefinitions();
      setDefinitions(defs || []);

      if (view === 'results') {
        const t = await DB.getLabTests();
        setTests(t || []);
      }
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleAddTestRequest = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedPatientId || !selectedTestDefId) return alert("يرجى اختيار المريض ونوع التحليل");
    try {
      await DB.addLabTest({
        patientId: selectedPatientId,
        testDefinitionId: selectedTestDefId,
        date: new Date().toISOString().split('T')[0]
      });
      setShowAddModal(false);
      setSelectedPatientId('');
      setSelectedTestDefId('');
      loadData();
    } catch (err) {
      alert("حدث خطأ أثناء حجز التحليل");
    }
  };

  const handleAddDefinition = async (e: React.FormEvent) => {
    e.preventDefault();
    const target = e.target as any;
    try {
      await DB.addLabDefinition({
        name: target.name.value,
        category: target.category.value,
        sampleType: target.sampleType.value,
        normalRangeMale: target.rangeMale.value,
        normalRangeFemale: target.rangeFemale.value,
        normalRangeChild: target.rangeChild.value
      });
      setShowDefModal(false);
      loadData();
    } catch (err) {
      alert("حدث خطأ أثناء حفظ التعريف");
    }
  };

  const handleAddPatient = async (e: React.FormEvent) => {
    e.preventDefault();
    const target = e.target as any;
    try {
      const newP = await DB.addPatient({
        name: target.name.value,
        nationalId: target.nationalId.value,
        phone: target.phone.value,
        bloodType: target.bloodType.value,
        dateOfBirth: target.dateOfBirth.value
      });
      setPatients([...patients, newP]);
      setSelectedPatientId(newP.id);
      setShowPatientModal(false);
    } catch (err) {
      alert("خطأ في إضافة المريض");
    }
  };

  const handleUpdateResult = async (e: React.FormEvent) => {
    e.preventDefault();
    const target = e.target as any;
    try {
      await DB.updateLabResult(showResultModal.id, target.result.value);
      setShowResultModal(null);
      loadData();
    } catch (err) {
      alert("خطأ أثناء تحديث النتيجة");
    }
  };

  const calculateAgeStr = (dob?: string) => {
    if (!dob) return '';
    const birthDate = new Date(dob);
    const today = new Date();
    let age = today.getFullYear() - birthDate.getFullYear();
    const m = today.getMonth() - birthDate.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birthDate.getDate())) {
      age--;
    }
    return `(${age} سنة)`;
  };

  const filteredTests = tests.filter(t => 
    t.lab_test_definitions?.name.includes(searchTerm) || t.patients?.name.includes(searchTerm)
  );

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      {/* Navigation Tabs */}
      <div className="flex gap-2 p-1 bg-gray-200/50 rounded-xl w-fit">
        <button 
          onClick={() => setView('results')}
          className={`px-6 py-2 rounded-lg font-bold transition-all flex items-center gap-2 ${view === 'results' ? 'bg-white shadow-sm text-primary-600' : 'text-gray-500'}`}
        >
          <FlaskConical size={18} /> سجل النتائج
        </button>
        <button 
          onClick={() => setView('definitions')}
          className={`px-6 py-2 rounded-lg font-bold transition-all flex items-center gap-2 ${view === 'definitions' ? 'bg-white shadow-sm text-primary-600' : 'text-gray-500'}`}
        >
          <BookOpen size={18} /> قاموس التحاليل
        </button>
      </div>

      <div className="flex flex-col md:flex-row justify-between items-center gap-4">
        <div className="relative w-full md:w-96">
          <Search className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
          <input 
            type="text" 
            placeholder={view === 'results' ? "بحث بالمريض أو التحليل..." : "بحث في القاموس..."} 
            className="w-full pr-10 pl-4 py-3 border rounded-xl bg-white shadow-sm outline-none focus:ring-2 focus:ring-primary-500"
            value={searchTerm}
            onChange={e => setSearchTerm(e.target.value)}
          />
        </div>

        {view === 'results' ? (
          <button 
            onClick={() => setShowAddModal(true)}
            className="bg-primary-600 text-white px-6 py-3 rounded-xl flex items-center gap-2 hover:bg-primary-700 transition-all font-bold shadow-md"
          >
            <Plus size={20} /> حجز تحليل لمريض
          </button>
        ) : (
          <button 
            onClick={() => setShowDefModal(true)}
            className="bg-indigo-600 text-white px-6 py-3 rounded-xl flex items-center gap-2 hover:bg-indigo-700 transition-all font-bold shadow-md"
          >
            <Plus size={20} /> تعريف تحليل جديد
          </button>
        )}
      </div>

      {view === 'results' ? (
        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden min-h-[400px]">
          {loading ? (
            <div className="flex flex-col items-center justify-center py-20 gap-4 text-gray-400">
              <Loader2 className="animate-spin text-primary-600" size={40} />
              <p className="font-bold">جاري تحميل السجلات...</p>
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full text-right">
                <thead className="bg-gray-50 border-b">
                  <tr>
                    <th className="px-6 py-4 font-bold text-gray-600">التاريخ</th>
                    <th className="px-6 py-4 font-bold text-gray-600">المريض</th>
                    <th className="px-6 py-4 font-bold text-gray-600">التحليل</th>
                    <th className="px-6 py-4 font-bold text-gray-600">الحالة</th>
                    <th className="px-6 py-4 font-bold text-gray-600">النتيجة</th>
                    <th className="px-6 py-4 font-bold text-gray-600">الإجراءات</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-100">
                  {filteredTests.map(test => (
                    <tr key={test.id} className="hover:bg-gray-50 transition-colors">
                      <td className="px-6 py-4 text-gray-500 text-sm font-mono">{test.date}</td>
                      <td className="px-6 py-4">
                        <div className="font-bold text-gray-800">{test.patients?.name}</div>
                        {/* Fix: Access the dateOfBirth property defined in the Patient interface */}
                        <div className="text-[10px] text-primary-600">{calculateAgeStr(test.patients?.dateOfBirth)}</div>
                      </td>
                      <td className="px-6 py-4">
                        <div className="font-bold text-primary-700">{test.lab_test_definitions?.name}</div>
                        <div className="text-[10px] text-gray-400">عينة: {test.lab_test_definitions?.sampleType}</div>
                      </td>
                      <td className="px-6 py-4">
                        {test.status === 'PENDING' ? (
                          <span className="flex items-center gap-1 text-orange-600 bg-orange-50 px-2 py-1 rounded-lg text-xs font-bold border border-orange-100">
                            <Clock size={12} /> تحت التنفيذ
                          </span>
                        ) : (
                          <span className="flex items-center gap-1 text-green-600 bg-green-50 px-2 py-1 rounded-lg text-xs font-bold border border-green-100">
                            <CheckCircle size={12} /> مكتمل
                          </span>
                        )}
                      </td>
                      <td className="px-6 py-4 font-bold">
                        {test.status === 'COMPLETED' ? (
                          <div className="flex items-center gap-2">
                             <span className="text-primary-600 text-lg">{test.result}</span>
                             <Lock size={12} className="text-gray-300" />
                          </div>
                        ) : '---'}
                      </td>
                      <td className="px-6 py-4">
                        {test.status === 'PENDING' ? (
                          <button 
                            onClick={() => setShowResultModal(test)}
                            className="bg-primary-50 text-primary-600 px-3 py-1 rounded-lg font-bold text-xs hover:bg-primary-600 hover:text-white transition-all"
                          >
                            إدخال النتيجة
                          </button>
                        ) : (
                          <button className="text-gray-400 hover:text-primary-600 transition-colors">
                            <FileText size={18} />
                          </button>
                        )}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {definitions.filter(d => d.name.includes(searchTerm)).map(def => (
            <div key={def.id} className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm hover:border-indigo-300 transition-all">
              <div className="flex justify-between items-start mb-4">
                <div className="bg-indigo-50 text-indigo-600 p-3 rounded-xl"><Beaker size={20} /></div>
                <span className="text-[10px] font-bold bg-gray-100 px-2 py-1 rounded text-gray-500 uppercase">{def.category}</span>
              </div>
              <h4 className="font-bold text-lg mb-1">{def.name}</h4>
              <p className="text-xs text-gray-400 mb-4">نوع العينة: {def.sampleType}</p>

              <div className="space-y-2 border-t pt-4">
                <div className="flex justify-between text-xs">
                  <span className="text-gray-500">للذكور:</span>
                  <span className="font-bold text-indigo-600">{def.normalRangeMale || '---'}</span>
                </div>
                <div className="flex justify-between text-xs">
                  <span className="text-gray-500">للإناث:</span>
                  <span className="font-bold text-pink-600">{def.normalRangeFemale || '---'}</span>
                </div>
                <div className="flex justify-between text-xs">
                  <span className="text-gray-500">للأطفال:</span>
                  <span className="font-bold text-green-600">{def.normalRangeChild || '---'}</span>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Modal: Add Test to Patient */}
      {showAddModal && (
        <div className="fixed inset-0 z-50 bg-black/60 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-lg rounded-2xl shadow-2xl animate-in zoom-in-95">
            <div className="p-6 bg-primary-600 text-white flex justify-between items-center rounded-t-2xl">
              <h3 className="text-xl font-bold flex items-center gap-2"><FlaskConical size={22} /> حجز تحليل جديد</h3>
              <button onClick={() => setShowAddModal(false)}><X size={24} /></button>
            </div>
            <form onSubmit={handleAddTestRequest} className="p-8 space-y-6">
              <div className="relative group">
                 <div className="flex items-end gap-2">
                    <div className="flex-1">
                       <SearchableSelect 
                         label="اسم المريض"
                         placeholder="ابحث عن مريض..."
                         /* Fix: Use dateOfBirth instead of date_of_birth on line 295 to match the Patient interface */
                         options={patients.map(p => ({ id: p.id, label: `${p.name} ${calculateAgeStr(p.dateOfBirth)}`, subLabel: p.nationalId }))}
                         value={selectedPatientId}
                         onChange={setSelectedPatientId}
                         onAddNew={() => setShowPatientModal(true)}
                         addNewText="إضافة مريض جديد"
                       />
                    </div>
                    <button 
                      type="button" 
                      onClick={() => setShowPatientModal(true)}
                      title="مريض جديد"
                      className="mb-2 p-3 bg-indigo-50 text-indigo-600 rounded-xl hover:bg-indigo-600 hover:text-white transition-all border border-indigo-100"
                    >
                      <UserPlus size={22} />
                    </button>
                 </div>
              </div>

              <SearchableSelect 
                label="نوع التحليل المطلوب"
                placeholder="ابحث عن تحليل من القاموس..."
                options={definitions.map(d => ({ id: d.id, label: d.name, subLabel: d.category }))}
                value={selectedTestDefId}
                onChange={setSelectedTestDefId}
                onAddNew={() => setShowDefModal(true)}
                addNewText="إضافة تعريف تحليل جديد"
              />

              <div className="flex gap-3 pt-4">
                <button type="button" onClick={() => setShowAddModal(false)} className="flex-1 py-4 bg-gray-100 rounded-xl font-bold">إلغاء</button>
                <button type="submit" className="flex-1 py-4 bg-primary-600 text-white rounded-xl font-bold shadow-lg hover:bg-primary-700">تأكيد الحجز</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Quick Add Patient Modal */}
      {showPatientModal && (
        <div className="fixed inset-0 z-[60] bg-black/70 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-2xl shadow-2xl animate-in zoom-in-95">
             <div className="p-6 bg-indigo-600 text-white flex justify-between items-center rounded-t-2xl">
                <h3 className="text-xl font-bold flex items-center gap-2"><UserPlus size={22} /> إضافة مريض سريع</h3>
                <button onClick={() => setShowPatientModal(false)}><X size={24} /></button>
             </div>
             <form onSubmit={handleAddPatient} className="p-8 space-y-4">
                <input name="name" required placeholder="اسم المريض بالكامل" className="w-full border rounded-xl p-3 bg-gray-50 focus:ring-2 focus:ring-indigo-500 outline-none" />
                <input name="nationalId" required placeholder="الرقم القومي" className="w-full border rounded-xl p-3 bg-gray-50 focus:ring-2 focus:ring-indigo-500 outline-none" />
                <input name="phone" required placeholder="رقم الهاتف" className="w-full border rounded-xl p-3 bg-gray-50 focus:ring-2 focus:ring-indigo-500 outline-none" />
                <div className="space-y-1">
                   <label className="text-xs font-bold text-gray-500 mr-2">تاريخ الميلاد</label>
                   <input name="dateOfBirth" type="date" required className="w-full border rounded-xl p-3 bg-gray-50 focus:ring-2 focus:ring-indigo-500 outline-none" />
