          </h3>
          <button onClick={() => setShowModal(true)} className="bg-primary-600 text-white px-6 py-2 rounded-xl text-sm font-bold flex items-center gap-2 shadow-sm">
            <Plus size={16} /> {AR.add}
          </button>
        </div>

        <div className="p-6">
          {loading && !showModal ? (
