              className="w-full pr-10 pl-4 py-3 border rounded-xl outline-none focus:ring-2 focus:ring-primary-500 shadow-sm"
              value={searchTerm} onChange={e => setSearchTerm(e.target.value)}
            />
          </div>
          <button 
            onClick={loadData} 
            className="p-3 bg-white border rounded-xl text-gray-400 hover:text-primary-600 transition-colors shadow-sm"
            title="تحديث القائمة"
          >
            <RefreshCw className={loading ? "animate-spin" : ""} size={20} />
          </button>
        </div>

        <div className="flex items-center gap-4 w-full md:w-auto">
           <div className="text-left hidden md:block">
              <span className="text-[10px] font-bold text-gray-400 uppercase">إجمالي الحسابات</span>
              <p className="font-bold text-primary-600 leading-none">{users.length} مستخدم</p>
           </div>
