  const [userData, setUserData] = useState<Partial<User>>({ permissions: [] });

  const [availableStores, setAvailableStores] = useState<Store[]>([]);
  const [availableAccounts, setAvailableAccounts] = useState<FinancialAccount[]>([]);
  const [errorInfo, setErrorInfo] = useState<string | null>(null);

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    setErrorInfo(null);
    try {
      const [u, s, a] = await Promise.all([
        DB.getUsers(),
        DB.getStores(),
        DB.getAccounts()
      ]);

      console.log("Raw Users from DB:", u); // للتصحيح في المتصفح

      // معالجة البيانات لضمان عدم وجود أخطاء في العرض
      const userList = Array.isArray(u) ? u : [];
      const sanitizedUsers = userList.map(user => {
        // معالجة الصلاحيات سواء كانت مصفوفة أو نصاً مفصولاً بفواصل
        let perms: Permission[] = [];
        if (Array.isArray(user.permissions)) {
          perms = user.permissions;
        } else if (typeof user.permissions === 'string') {
          perms = (user.permissions as string).split(',').map(p => p.trim()) as Permission[];
        }

        return {
          ...user,
          id: user.id || Math.random().toString(),
          name: user.name || 'مستخدم بدون اسم',
          username: user.username || 'unknown',
          permissions: perms
        };
      });

      setUsers(sanitizedUsers);
