                      <Package size={16} className="text-amber-600" /> صلاحيات المخازن
                    </h4>
                    <div className="space-y-3 max-h-60 overflow-y-auto custom-scrollbar p-3 bg-gray-50 rounded-3xl border-2 border-dashed">
                      {availableStores.map(store => {
                        const perm = `STORE_ACCESS_${store.id}`;
                        const isSelected = userData.permissions?.includes(perm);
                        return (
                          <button key={store.id} type="button" onClick={() => togglePermission(perm)} className={`w-full p-4 rounded-xl border-2 text-xs font-bold transition-all flex items-center justify-between ${isSelected ? 'bg-amber-600 text-white border-amber-600 shadow-md' : 'bg-white hover:bg-amber-50 border-transparent text-gray-500'}`}>
