                        const isSelected = userData.permissions?.includes(perm);
                        return (
                          <button key={acc.id} type="button" onClick={() => togglePermission(perm)} className={`w-full p-4 rounded-xl border-2 text-xs font-bold transition-all flex items-center justify-between ${isSelected ? 'bg-emerald-600 text-white border-emerald-600 shadow-md' : 'bg-white hover:bg-emerald-50 border-transparent text-gray-500'}`}>
