        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #cbd5e1; }
      `}</style>
    </div>
  );
};

export default UsersModule;

import { 
  Patient, DialysisSession, Service, Invoice, Product, 
  Store, StockTransaction, Employee, FinancialAccount, 
  Transaction, FundingEntity, ShiftRecord, LabTest, LabTestDefinition, AuditLog,
  User, Permission, TransferRequest
} from './types.ts';
import { supabase } from './supabase.ts';

export class DB {
  // --- Auth ---
  static async login(username: string, password: string): Promise<User | null> {
    const { data, error } = await supabase
      .from('system_users')
      .select('*')
      .eq('username', username)
      .eq('password', password)
      .single();

    if (error || !data) return null;
    await this.log('تسجيل دخول', `دخل المستخدم ${data.name} إلى النظام`);
    return data as User;
  }

  // --- Patients ---
  static async getPatients() {
    const { data, error } = await supabase.from('patients').select('*').order('createdAt', { ascending: false });
    if (error) { console.error(error); return []; }
    return data || [];
  }

  static async addPatient(p: Partial<Patient>) {
    const { data, error } = await supabase.from('patients').insert([p]).select();
    if (error) { console.error(error); throw error; }
    await this.log('إضافة مريض', `تمت إضافة المريض ${p.name}`);
    return data[0];
  }

  // --- Financial Accounts ---
  static async getAccounts() {
    const { data, error } = await supabase.from('financial_accounts').select('*').order('name');
    if (error) { console.error(error); return []; }
    return data || [];
  }

  static async addAccount(acc: Partial<FinancialAccount>) {
    const { data, error } = await supabase.from('financial_accounts').insert([acc]).select();
    if (error) { console.error(error); throw error; }
    return data[0];
  }

  static async deleteAccount(id: string) {
    const { error } = await supabase.from('financial_accounts').delete().eq('id', id);
    if (error) throw error;
  }

  // --- Inventory & Stores ---
  static async getProducts() {
    const { data, error } = await supabase.from('products').select('*').order('name');
    if (error) { console.error(error); return []; }
    return data || [];
  }

  static async addProduct(p: Partial<Product>) {
    const { data, error } = await supabase.from('products').insert([p]).select();
    if (error) throw error;
    return data[0];
  }

  static async deleteProduct(id: string) {
    const { error } = await supabase.from('products').delete().eq('id', id);
    if (error) throw error;
  }

  static async getStores() {
    const { data, error } = await supabase.from('stores').select('*').order('name');
    if (error) { console.error(error); return []; }
    return data || [];
  }

  static async addStore(s: Partial<Store>) {
    const { data, error } = await supabase.from('stores').insert([s]).select();
    if (error) throw error;
    return data[0];
  }

  static async deleteStore(id: string) {
    const { error } = await supabase.from('stores').delete().eq('id', id);
    if (error) throw error;
  }

  static async addStockTransaction(tx: Partial<StockTransaction>) {
    const { data, error } = await supabase.from('stock_transactions').insert([tx]).select();
    if (error) { console.error(error); throw error; }
    return data[0];
  }

  static async createTransferRequest(req: Partial<TransferRequest>) {
    const { data, error } = await supabase.from('transfer_requests').insert([req]).select();
    if (error) { console.error(error); throw error; }
    return data[0];
  }

  static async getTransferRequests() {
    const { data, error } = await supabase.from('transfer_requests').select('*').order('date', { ascending: false });
    if (error) { console.error(error); return []; }
    return data || [];
  }

  // --- Users ---
  static async getUsers() {
    try {
      const { data, error } = await supabase
        .from('system_users')
        .select('*');

      if (error) {
        console.error("Supabase error fetching users:", error);
        return []; 
      }
      return data || [];
    } catch (e) {
      console.error("Connection error while fetching users:", e);
      return [];
    }
  }

  static async addUser(u: Partial<User>) {
    const { data, error } = await supabase.from('system_users').insert([u]).select();
    if (error) { console.error(error); throw error; }
    return data[0];
  }

  static async updateUser(id: string, u: Partial<User>) {
    const updateData = { ...u };
    if (!updateData.password) {
      delete updateData.password;
    }
    const { data, error } = await supabase.from('system_users').update(updateData).eq('id', id).select();
    if (error) { console.error(error); throw error; }
    return data[0];
  }

  static async deleteUser(id: string) {
    const { error } = await supabase.from('system_users').delete().eq('id', id);
    if (error) throw error;
  }

  // --- Funding Entities ---
  static async getFundingEntities() {
    const { data, error } = await supabase.from('funding_entities').select('*').order('name');
    if (error) { console.error(error); return []; }
    return data || [];
  }

  static async addFundingEntity(name: string) {
    const { data, error } = await supabase.from('funding_entities').insert([{ name }]).select();
    if (error) throw error;
    return data[0];
  }

  static async deleteFundingEntity(id: string) {
    const { error } = await supabase.from('funding_entities').delete().eq('id', id);
    if (error) throw error;
  }

  // --- Services ---
  static async getServices() {
    const { data, error } = await supabase.from('services').select('*').order('name');
    if (error) { console.error(error); return []; }
    return data || [];
  }

  static async addService(s: Partial<Service>) {
    const { data, error } = await supabase.from('services').insert([s]).select();
    if (error) throw error;
    return data[0];
  }

  static async deleteService(id: string) {
    const { error } = await supabase.from('services').delete().eq('id', id);
    if (error) throw error;
  }

  // --- Sessions ---
  static async getSessions() {
    const { data, error } = await supabase.from('dialysis_sessions').select('*, patients(name)').order('createdAt', { ascending: false });
    if (error) { console.error(error); return []; }
    return data || [];
  }

  static async addSession(session: Partial<DialysisSession>) {
    const { data, error } = await supabase.from('dialysis_sessions').insert([session]).select();
    if (error) throw error;
    return data[0];
  }

  // --- Finance Txs ---
  static async getTransactions() {
    const { data, error } = await supabase.from('transactions').select('*').order('date', { ascending: false });
    if (error) { console.error(error); return []; }
    return data || [];
  }

  static async addFinanceTx(tx: Partial<Transaction>) {
    const { data, error } = await supabase.from('transactions').insert([tx]).select();
    if (error) throw error;
    return data[0];
  }

  // --- Lab ---
  static async getLabDefinitions() {
    const { data, error } = await supabase.from('lab_test_definitions').select('*').order('name');
    if (error) { console.error(error); return []; }
    return data || [];
  }

  static async addLabDefinition(def: Partial<LabTestDefinition>) {
    const { data, error } = await supabase.from('lab_test_definitions').insert([def]).select();
    if (error) throw error;
    return data[0];
  }

  static async getLabTests() {
    const { data, error } = await supabase
      .from('lab_tests')
      .select('*, patients(name, dateOfBirth), lab_test_definitions(name, sampleType)')
      .order('date', { ascending: false });
    if (error) { console.error(error); return []; }
    return data || [];
  }

  static async addLabTest(test: Partial<LabTest>) {
    const { data, error } = await supabase.from('lab_tests').insert([{ ...test, status: 'PENDING' }]).select();
    if (error) throw error;
    return data[0];
  }

  static async updateLabResult(id: string, result: string) {
    const { data, error } = await supabase.from('lab_tests').update({ result, status: 'COMPLETED' }).eq('id', id).select();
    if (error) throw error;
    return data[0];
  }

  // --- Employees & Payroll ---
  static async getEmployees() {
    const { data, error } = await supabase.from('employees').select('*').order('name');
    if (error) { console.error(error); return []; }
    return data || [];
  }

  static async getShifts() {
    const { data, error } = await supabase.from('shift_records').select('*');
    if (error) { console.error(error); return []; }
    return data || [];
  }

  static async resetShifts() {
    const { error } = await supabase.from('shift_records').delete().neq('id', '0');
    if (error) throw error;
  }

  // --- Logging ---
  static async log(action: string, details: string) {
    try {
      const userStr = localStorage.getItem('dialysis_user');
      const user = userStr ? JSON.parse(userStr) : { name: 'Unknown' };
      await supabase.from('audit_logs').insert([{
        userId: user.name,
        action,
        details,
        timestamp: new Date().toISOString()
      }]);
    } catch (e) {
      console.warn("Logging failed", e);
    }
  }
}

import React, { useState, useEffect } from 'react';
import { AR, PERMISSIONS_MAP } from '../constants.ts';
import { DB } from '../store.ts';
import { User, Permission, Store, FinancialAccount } from '../types.ts';
import { 
  UserPlus, Search, Trash2, UserCheck, Shield, Check, X, 
  Loader2, Package, Wallet, Edit, AlertCircle, RefreshCw, 
  Key, ShieldAlert, Fingerprint, Activity
} from 'lucide-react';

const UsersModule: React.FC = () => {
  const [searchTerm, setSearchTerm] = useState('');
  const [showModal, setShowModal] = useState(false);
  const [editingUserId, setEditingUserId] = useState<string | null>(null);
  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [userData, setUserData] = useState<Partial<User>>({ permissions: [] });

  const [availableStores, setAvailableStores] = useState<Store[]>([]);
  const [availableAccounts, setAvailableAccounts] = useState<FinancialAccount[]>([]);
  const [errorInfo, setErrorInfo] = useState<string | null>(null);

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    setErrorInfo(null);
    try {
      const [u, s, a] = await Promise.all([
        DB.getUsers(),
        DB.getStores(),
        DB.getAccounts()
      ]);

      console.log("Supabase Users Response:", u);

      const userList = Array.isArray(u) ? u : [];
      const sanitizedUsers = userList.map(user => {
        let perms: Permission[] = [];
        if (Array.isArray(user.permissions)) {
          perms = user.permissions;
        } else if (typeof user.permissions === 'string') {
          perms = (user.permissions as string).split(',').map(p => p.trim()) as Permission[];
        }

        return {
          ...user,
          id: user.id || Math.random().toString(),
          name: user.name || 'مستخدم بدون اسم',
          username: user.username || 'unknown',
          permissions: perms
        };
      });

      setUsers(sanitizedUsers);
      setAvailableStores(s || []);
      setAvailableAccounts(a || []);

      if (userList.length === 0) {
        setErrorInfo("تم الاتصال ولكن لم يتم استلام أي سجلات. تأكد من تفعيل صلاحيات الوصول (RLS) للجدول system_users في Supabase.");
      }
    } catch (err: any) {
      console.error("Critical error in UsersModule:", err);
      setErrorInfo(err.message || "فشل الاتصال بقاعدة البيانات.");
    } finally {
      setLoading(false);
    }
  };

  const togglePermission = (perm: Permission) => {
    const current = userData.permissions || [];
    if (current.includes(perm)) {
      setUserData({ ...userData, permissions: current.filter(p => p !== perm) });
    } else {
      setUserData({ ...userData, permissions: [...current, perm] });
    }
  };

  const handleOpenAdd = () => {
    setEditingUserId(null);
    setUserData({ permissions: [], name: '', username: '', password: '' });
    setShowModal(true);
  };

  const handleOpenEdit = (user: User) => {
    setEditingUserId(user.id);
    setUserData({ 
      name: user.name, 
      username: user.username, 
      permissions: [...(user.permissions || [])],
      password: '' 
    });
    setShowModal(true);
  };

  const handleSaveUser = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!userData.permissions?.length) return alert("يرجى اختيار صلاحية واحدة على الأقل");
    setSubmitting(true);
    try {
      if (editingUserId) {
        await DB.updateUser(editingUserId, userData);
      } else {
        await DB.addUser({
          name: userData.name || '',
          username: userData.username || '',
          password: userData.password,
          permissions: userData.permissions
        });
      }
      await loadData();
      setShowModal(false);
    } catch (err) {
      alert("حدث خطأ أثناء حفظ بيانات المستخدم.");
    } finally {
      setSubmitting(false);
    }
  };

  const handleDeleteUser = async (id: string) => {
    if (!confirm("هل أنت متأكد من حذف هذا المستخدم نهائياً؟")) return;
    try {
      await DB.deleteUser(id);
      await loadData();
    } catch (err) {
      alert("خطأ أثناء الحذف");
    }
  };

  const filteredUsers = users.filter(u => 
    (u.name && u.name.toLowerCase().includes(searchTerm.toLowerCase())) || 
    (u.username && u.username.toLowerCase().includes(searchTerm.toLowerCase()))
  );

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      {/* Header & Controls */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div className="flex items-center gap-4 w-full md:w-auto">
          <div className="relative w-full md:w-96">
            <Search className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
            <input 
              type="text" placeholder="بحث باسم الموظف أو اسم الدخول..." 
              className="w-full pr-10 pl-4 py-3 border rounded-xl outline-none focus:ring-2 focus:ring-primary-500 shadow-sm"
              value={searchTerm} onChange={e => setSearchTerm(e.target.value)}
            />
          </div>
          <button 
            onClick={loadData} 
            className="p-3 bg-white border rounded-xl text-gray-400 hover:text-primary-600 transition-colors shadow-sm"
            title="تحديث القائمة"
          >
            <RefreshCw className={loading ? "animate-spin" : ""} size={20} />
          </button>
        </div>

        <div className="flex items-center gap-4 w-full md:w-auto">
           <div className="text-left hidden md:block">
              <span className="text-[10px] font-bold text-gray-400">المستخدمين المسجلين</span>
              <p className="font-black text-primary-600 text-xl leading-none">{users.length}</p>
           </div>
           <button onClick={handleOpenAdd} className="bg-primary-600 text-white px-8 py-3 rounded-xl flex items-center gap-2 font-bold shadow-lg shadow-primary-600/20 hover:bg-primary-700 transition-all w-full md:w-auto justify-center">
             <UserPlus size={20} /> حساب جديد
           </button>
        </div>
      </div>

      {/* Main Content Area */}
      {loading ? (
        <div className="flex flex-col items-center justify-center py-40 gap-4">
          <Loader2 className="animate-spin text-primary-600" size={48} />
          <p className="text-gray-400 font-bold">جاري جلب البيانات من السيرفر...</p>
        </div>
      ) : filteredUsers.length === 0 ? (
        <div className="bg-white p-20 rounded-[2rem] border border-dashed border-gray-200 flex flex-col items-center justify-center text-gray-400 text-center">
          <div className="p-8 bg-gray-50 rounded-full mb-6">
            <ShieldAlert size={64} className="opacity-20" />
          </div>
          <h3 className="text-xl font-black text-gray-700">لا تظهر أي بيانات!</h3>
          <p className="text-sm mt-2 max-w-lg text-gray-500 font-medium">
            {errorInfo || "تأكد من وجود مستخدمين في جدول system_users وأن صلاحيات Supabase (RLS) تسمح بالقراءة."}
          </p>
          <div className="flex gap-3 mt-8">
            <button onClick={loadData} className="px-6 py-3 bg-gray-100 text-gray-600 rounded-xl font-bold flex items-center gap-2">
              <RefreshCw size={18} /> تحديث الصفحة
            </button>
            <button onClick={handleOpenAdd} className="px-6 py-3 bg-primary-600 text-white rounded-xl font-bold">إضافة مستخدم الآن</button>
          </div>
        </div>
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          {filteredUsers.map(user => (
            <div key={user.id} className="bg-white rounded-[2rem] shadow-sm border border-gray-100 p-8 hover:shadow-xl hover:border-primary-100 transition-all group relative overflow-hidden">
              <div className="absolute top-0 left-0 w-32 h-32 bg-primary-50 rounded-br-[120px] -z-0 opacity-40 group-hover:bg-primary-100 transition-colors"></div>

              <div className="relative z-10">
                <div className="flex justify-between items-start mb-6">
                  <div className="flex items-center gap-5">
                    <div className="w-16 h-16 bg-primary-600 text-white rounded-2xl flex items-center justify-center font-black text-2xl uppercase shadow-lg shadow-primary-600/20 group-hover:scale-105 transition-transform border-4 border-white">
                      {user.name ? user.name[0] : '?'}
                    </div>
                    <div>
                      <h4 className="font-black text-xl text-gray-800 tracking-tight">{user.name}</h4>
                      <div className="flex items-center gap-2 text-gray-400 mt-1">
                        <span className="text-xs font-mono bg-gray-100 px-2 py-0.5 rounded-md flex items-center gap-1">
                          <Fingerprint size={12} /> @{user.username}
                        </span>
                        <span className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></span>
                        <span className="text-[10px] font-bold text-green-600">نشط</span>
                      </div>
                    </div>
                  </div>
                  <div className="flex gap-2">
                    <button onClick={() => handleOpenEdit(user)} className="bg-primary-50 text-primary-600 p-3 rounded-xl hover:bg-primary-600 hover:text-white transition-all border border-primary-100">
                      <Edit size={18} />
                    </button>
                    <button onClick={() => handleDeleteUser(user.id)} className="bg-red-50 text-red-600 p-3 rounded-xl hover:bg-red-600 hover:text-white transition-all border border-red-100">
                      <Trash2 size={18} />
                    </button>
                  </div>
                </div>

                <div className="space-y-4 pt-4 border-t border-gray-50">
                  <div className="flex items-center justify-between">
                    <h5 className="text-[10px] font-black text-gray-400 flex items-center gap-1.5">
                      <Key size={12} /> الصلاحيات والوصول
                    </h5>
                    <span className="text-[10px] font-bold text-primary-600 bg-primary-50 px-3 py-1 rounded-full">
                      {user.permissions?.length || 0} ميزة
                    </span>
                  </div>

                  <div className="flex flex-wrap gap-2">
                    {user.permissions && user.permissions.length > 0 ? user.permissions.map(perm => {
                      const isStore = perm.startsWith('STORE_ACCESS_');
                      const isAcc = perm.startsWith('ACC_ACCESS_');

                      let label = PERMISSIONS_MAP[perm];
                      let icon = <Shield size={10} />;
                      let colorClass = "bg-gray-50 text-gray-600 border-gray-100";

                      if (isStore) {
                        const store = availableStores.find(s => `STORE_ACCESS_${s.id}` === perm);
                        label = `مخزن: ${store?.name || 'وصول مخزن'}`;
                        icon = <Package size={10} />;
                        colorClass = "bg-amber-50 text-amber-600 border-amber-100";
                      } else if (isAcc) {
                        const acc = availableAccounts.find(a => `ACC_ACCESS_${a.id}` === perm);
                        label = `خزينة: ${acc?.name || 'وصول مالي'}`;
                        icon = <Wallet size={10} />;
                        colorClass = "bg-emerald-50 text-emerald-600 border-emerald-100";
                      }

                      return (
                        <span key={perm} className={`px-3 py-2 ${colorClass} text-[10px] font-bold rounded-xl border flex items-center gap-2 shadow-sm transition-all hover:scale-105`}>
                          {icon}
