                      );
                    }) : (
                      <div className="w-full flex items-center gap-2 p-4 bg-gray-50 rounded-2xl border border-dashed text-gray-400">
                        <Activity size={14} />
                        <span className="text-xs font-bold">لا توجد صلاحيات مسندة</span>
                      </div>
                    )}
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Modal: Add/Edit User */}
      {showModal && (
        <div className="fixed inset-0 z-50 bg-black/60 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-4xl rounded-[2.5rem] shadow-2xl flex flex-col max-h-[95vh] overflow-hidden animate-in zoom-in-95 duration-300">
            <div className="p-10 bg-primary-600 text-white flex justify-between items-center relative overflow-hidden">
              <div className="absolute top-0 right-0 w-64 h-64 bg-white/10 rounded-full -mr-32 -mt-32"></div>
              <div className="relative z-10">
                <h3 className="text-3xl font-black flex items-center gap-4">
                  {editingUserId ? <Edit size={32} /> : <UserPlus size={32} />}
                  {editingUserId ? "تعديل الحساب" : "مستخدم جديد"}
                </h3>
                <p className="text-primary-100 text-sm mt-2 opacity-80">تحكم في هوية الموظف وصلاحياته في النظام.</p>
              </div>
              <button onClick={() => setShowModal(false)} className="relative z-10 p-3 hover:bg-white/20 rounded-full transition-all active:scale-90"><X size={32} /></button>
            </div>

            <div className="p-12 overflow-y-auto custom-scrollbar space-y-12 flex-1">
              <form id="userForm" onSubmit={handleSaveUser} className="space-y-12">
                <section className="space-y-8">
                  <h4 className="font-black text-gray-800 text-sm border-r-4 border-primary-600 pr-4 flex items-center gap-3">
                    <Activity size={20} className="text-primary-600" /> المعلومات الأمنية
                  </h4>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                    <div className="space-y-3">
                      <label className="text-xs font-black text-gray-500 mr-2 font-bold">اسم الموظف الكامل</label>
                      <input required placeholder="الاسم" className="w-full border-2 border-gray-100 rounded-2xl p-4 bg-gray-50 focus:bg-white focus:border-primary-500 outline-none transition-all font-bold" value={userData.name} onChange={e => setUserData({...userData, name: e.target.value})} />
                    </div>
                    <div className="space-y-3">
                      <label className="text-xs font-black text-gray-500 mr-2 font-bold">اسم الدخول للنظام</label>
                      <input required placeholder="username" className="w-full border-2 border-gray-100 rounded-2xl p-4 bg-gray-50 focus:bg-white focus:border-primary-500 outline-none transition-all font-mono font-bold" value={userData.username} onChange={e => setUserData({...userData, username: e.target.value})} />
                    </div>
                    <div className="space-y-3 md:col-span-2">
                      <label className="text-xs font-black text-gray-500 mr-2 font-bold">
                        كلمة المرور السرية 
                        {editingUserId && <span className="text-primary-500 mr-2 font-normal text-[10px]">(اتركها فارغة لعدم التغيير)</span>}
                      </label>
                      <input type="password" placeholder="••••••••" className="w-full border-2 border-gray-100 rounded-2xl p-4 bg-gray-50 focus:bg-white focus:border-primary-500 outline-none transition-all font-mono" value={userData.password} onChange={e => setUserData({...userData, password: e.target.value})} />
                    </div>
                  </div>
                </section>

                <section className="space-y-8">
                  <h4 className="font-black text-gray-800 text-sm border-r-4 border-blue-600 pr-4 flex items-center gap-3">
                    <Shield size={20} className="text-blue-600" /> صلاحيات النظام الموحدة
                  </h4>
                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                    {Object.entries(PERMISSIONS_MAP).map(([key, val]) => (
                      <button key={key} type="button" onClick={() => togglePermission(key as Permission)} className={`p-5 rounded-2xl border-2 text-xs font-black transition-all text-right flex items-center justify-between group ${userData.permissions?.includes(key as Permission) ? 'bg-primary-600 text-white border-primary-600 shadow-xl shadow-primary-600/20' : 'bg-white hover:bg-primary-50 border-gray-100 text-gray-600'}`}>
                        <span>{val}</span>
                        {userData.permissions?.includes(key as Permission) ? <Check size={20} /> : <div className="w-5 h-5 rounded-full border-2 border-gray-200 group-hover:border-primary-300 transition-all"></div>}
                      </button>
                    ))}
                  </div>
                </section>

                <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
                  <section className="space-y-6">
                    <h4 className="font-black text-gray-800 text-[10px] border-r-4 border-amber-600 pr-4 flex items-center gap-3">
