import { 
  Patient, DialysisSession, Service, Invoice, Product, 
  Store, StockTransaction, Employee, FinancialAccount, 
  Transaction, FundingEntity, ShiftRecord, LabTest, LabTestDefinition, AuditLog,
  User, Permission, TransferRequest
} from './types.ts';
import { supabase } from './supabase.ts';

// دالة مساعدة لمعالجة أخطاء Supabase
const handleError = (error: any, fallbackMessage: string) => {
  console.error("Database Error:", error);
  // الخطأ 42P01 يعني أن الجدول غير موجود (Relation does not exist)
  if (error.code === '42P01' || (error.message && error.message.toLowerCase().includes('not found'))) {
    throw new Error(`SCHEMA_ERROR: الجدول غير موجود في قاعدة البيانات. يرجى التوجه للإعدادات وتشغيل كود SQL.`);
  }
  throw new Error(error.message || fallbackMessage);
};

export class DB {
  // --- Auth ---
  static async login(username: string, password: string): Promise<User | null> {
    try {
      const { data, error } = await supabase
        .from('system_users')
        .select('*')
        .eq('username', username)
        .eq('password', password)
        .single();

      if (error || !data) return null;
      await this.log('تسجيل دخول', `دخل المستخدم ${data.name} إلى النظام`);
      return data as User;
    } catch (e) {
      return null;
    }
  }

  // --- Patients ---
  static async getPatients() {
    try {
      const { data, error } = await supabase.from('patients').select('*').order('createdAt', { ascending: false });
      if (error) return handleError(error, "فشل جلب المرضى");
      return data || [];
    } catch (e) { return []; }
  }

  static async addPatient(p: Partial<Patient>) {
    const { data, error } = await supabase.from('patients').insert([p]).select();
    if (error) return handleError(error, "فشل إضافة المريض");
    await this.log('إضافة مريض', `تمت إضافة المريض ${p.name}`);
    return data?.[0];
  }

  // --- Financial Accounts ---
  static async getAccounts() {
    try {
      const { data, error } = await supabase.from('financial_accounts').select('*').order('name');
      if (error) return handleError(error, "فشل جلب الحسابات");
      return data || [];
    } catch (e) { return []; }
  }

  static async addAccount(acc: Partial<FinancialAccount>) {
    const { data, error } = await supabase.from('financial_accounts').insert([acc]).select();
    if (error) return handleError(error, "فشل إضافة الحساب المالي");
    return data?.[0];
  }

  static async deleteAccount(id: string) {
    const { error } = await supabase.from('financial_accounts').delete().eq('id', id);
    if (error) return handleError(error, "فشل حذف الحساب");
  }

  // --- Inventory & Stores ---
  static async getProducts() {
    try {
      const { data, error } = await supabase.from('products').select('*').order('name');
      if (error) return handleError(error, "فشل جلب الأصناف");
      return data || [];
    } catch (e) { return []; }
  }

  static async addProduct(p: Partial<Product>) {
    const { data, error } = await supabase.from('products').insert([p]).select();
    if (error) return handleError(error, "فشل إضافة الصنف");
    return data?.[0];
  }

  static async deleteProduct(id: string) {
    const { error } = await supabase.from('products').delete().eq('id', id);
    if (error) return handleError(error, "فشل حذف الصنف");
  }

  static async getStores() {
    try {
      const { data, error } = await supabase.from('stores').select('*').order('name');
      if (error) return handleError(error, "فشل جلب المخازن");
      return data || [];
    } catch (e: any) {
      if (e.message?.includes('SCHEMA_ERROR')) throw e;
      return [];
    }
  }

  static async addStore(s: Partial<Store>) {
    const { data, error } = await supabase.from('stores').insert([s]).select();
    if (error) return handleError(error, "فشل إضافة المخزن");
    return data?.[0];
  }

  static async deleteStore(id: string) {
    const { error } = await supabase.from('stores').delete().eq('id', id);
    if (error) return handleError(error, "فشل حذف المخزن");
  }

  static async addStockTransaction(tx: Partial<StockTransaction>) {
    const { data, error } = await supabase.from('stock_transactions').insert([tx]).select();
    if (error) return handleError(error, "فشل تسجيل الحركة");
    return data?.[0];
  }

  // --- Users ---
  static async getUsers() {
    try {
      const { data, error } = await supabase.from('system_users').select('*');
      if (error) return handleError(error, "فشل جلب المستخدمين");
      return data || [];
    } catch (e) { return []; }
  }

  static async addUser(u: Partial<User>) {
    const { data, error } = await supabase.from('system_users').insert([u]).select();
    if (error) return handleError(error, "فشل إضافة المستخدم");
    return data?.[0];
  }

  static async updateUser(id: string, u: Partial<User>) {
    const updateData = { ...u };
    if (!updateData.password) delete updateData.password;
    const { data, error } = await supabase.from('system_users').update(updateData).eq('id', id).select();
    if (error) return handleError(error, "فشل تحديث المستخدم");
    return data?.[0];
  }

  static async deleteUser(id: string) {
    const { error } = await supabase.from('system_users').delete().eq('id', id);
    if (error) return handleError(error, "فشل حذف المستخدم");
  }

  // --- Services ---
  static async getServices() {
    try {
      const { data, error } = await supabase.from('services').select('*').order('name');
      if (error) return handleError(error, "فشل جلب الخدمات");
      return data || [];
    } catch (e) { return []; }
  }

  static async addService(s: Partial<Service>) {
    const { data, error } = await supabase.from('services').insert([s]).select();
    if (error) return handleError(error, "فشل إضافة الخدمة");
    return data?.[0];
  }

  // --- Funding Entities ---
  static async getFundingEntities() {
    try {
      const { data, error } = await supabase.from('funding_entities').select('*').order('name');
      if (error) return handleError(error, "فشل جلب جهات التمويل");
      return data || [];
    } catch (e) { return []; }
  }

  static async addFundingEntity(name: string) {
    const { data, error } = await supabase.from('funding_entities').insert([{ name }]).select();
    if (error) return handleError(error, "فشل إضافة جهة التمويل");
    return data?.[0];
  }

  // --- Transactions ---
  static async getTransactions() {
    try {
      const { data, error } = await supabase.from('transactions').select('*').order('date', { ascending: false });
      if (error) return handleError(error, "فشل جلب المعاملات");
      return data || [];
    } catch (e) { return []; }
  }

  static async addFinanceTx(tx: Partial<Transaction>) {
    const { data, error } = await supabase.from('transactions').insert([tx]).select();
    if (error) return handleError(error, "فشل تسجيل المعاملة");
    return data?.[0];
  }

  // --- Logging ---
  static async log(action: string, details: string) {
    try {
      const userStr = localStorage.getItem('dialysis_user');
      const user = userStr ? JSON.parse(userStr) : { name: 'Unknown' };
      await supabase.from('audit_logs').insert([{
        userId: user.name,
        action,
        details,
        timestamp: new Date().toISOString()
      }]);
    } catch (e) {}
  }

  // --- Sessions & Lab & Employees ---
  static async getSessions() { try { const { data, error } = await supabase.from('dialysis_sessions').select('*, patients(name)'); if(error) return []; return data || []; } catch(e) {return [];} }
  static async addSession(s: any) { const { data, error } = await supabase.from('dialysis_sessions').insert([s]).select(); if(error) return handleError(error, "خطأ"); return data?.[0]; }
  static async getLabDefinitions() { try { const { data, error } = await supabase.from('lab_test_definitions').select('*'); if(error) return []; return data || []; } catch(e) {return [];} }
  static async addLabDefinition(d: any) { const { data, error } = await supabase.from('lab_test_definitions').insert([d]).select(); if(error) return handleError(error, "خطأ"); return data?.[0]; }
  static async getLabTests() { try { const { data, error } = await supabase.from('lab_tests').select('*, patients(name), lab_test_definitions(name)'); if(error) return []; return data || []; } catch(e) {return [];} }
  static async addLabTest(t: any) { const { data, error } = await supabase.from('lab_tests').insert([t]).select(); if(error) return handleError(error, "خطأ"); return data?.[0]; }
  static async updateLabResult(id: string, result: string) { const { data, error } = await supabase.from('lab_tests').update({ result, status: 'COMPLETED' }).eq('id', id).select(); if(error) return handleError(error, "خطأ"); return data?.[0]; }
  static async getEmployees() { try { const { data, error } = await supabase.from('employees').select('*'); if(error) return []; return data || []; } catch(e) {return [];} }
  static async getShifts() { try { const { data, error } = await supabase.from('shift_records').select('*'); if(error) return []; return data || []; } catch(e) {return [];} }
  static async resetShifts() { const { error } = await supabase.from('shift_records').delete().neq('id', '00000000-0000-0000-0000-000000000000'); if(error) return handleError(error, "خطأ"); }
  static async createTransferRequest(r: any) { const { data, error } = await supabase.from('transfer_requests').insert([r]).select(); if(error) return handleError(error, "خطأ"); return data?.[0]; }
  static async getTransferRequests() { try { const { data, error } = await supabase.from('transfer_requests').select('*'); if(error) return []; return data || []; } catch(e) {return [];} }
}

import React, { useState, useEffect } from 'react';
import { AR } from '../constants';
import { DB } from '../store';
import { Service, Store, Product, FundingEntity, FinancialAccount } from '../types';
import { Package, Store as StoreIcon, CreditCard, Tag, Plus, Trash2, X, Loader2, Wallet, Layers, Info, Barcode, AlertCircle, CheckCircle, Database } from 'lucide-react';

const SetupModule: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'services' | 'stores' | 'products' | 'funding' | 'accounts'>('services');
  const [loading, setLoading] = useState(false);
  const [showModal, setShowModal] = useState(false);
  const [submitError, setSubmitError] = useState<string | null>(null);
  const [isSchemaError, setIsSchemaError] = useState(false);

  const [services, setServices] = useState<Service[]>([]);
  const [stores, setStores] = useState<Store[]>([]);
  const [products, setProducts] = useState<Product[]>([]);
  const [funding, setFunding] = useState<FundingEntity[]>([]);
  const [accounts, setAccounts] = useState<FinancialAccount[]>([]);

  useEffect(() => {
    loadData();
  }, [activeTab]);

  const loadData = async () => {
    setLoading(true);
    setSubmitError(null);
    setIsSchemaError(false);
    try {
      if (activeTab === 'services') setServices(await DB.getServices());
      if (activeTab === 'stores') setStores(await DB.getStores());
      if (activeTab === 'products') setProducts(await DB.getProducts());
      if (activeTab === 'funding') setFunding(await DB.getFundingEntities());
      if (activeTab === 'accounts') setAccounts(await DB.getAccounts());
    } catch (err: any) {
      console.error(err);
      setSubmitError(err.message);
      if (err.message?.includes('SCHEMA_ERROR')) {
        setIsSchemaError(true);
      }
    } finally {
      setLoading(false);
    }
  };

  const handleAddItem = async (e: React.FormEvent) => {
    e.preventDefault();
    const target = e.target as any;
    setLoading(true);
    setSubmitError(null);

    try {
      if (activeTab === 'services') {
        await DB.addService({ 
          name: target.name.value, 
          price: parseFloat(target.price.value) || 0, 
          category: target.category.value 
        });
      } else if (activeTab === 'stores') {
        await DB.addStore({ 
          name: target.name.value, 
          isMain: target.isMain.checked 
        });
      } else if (activeTab === 'products') {
        await DB.addProduct({ 
          name: target.name.value, 
          unit: target.unit.value, 
          minStock: parseInt(target.minStock.value) || 0, 
          price: parseFloat(target.price.value) || 0,
          category: target.category.value,
          barcode: target.barcode.value,
          description: target.description.value
        });
      } else if (activeTab === 'funding') {
        await DB.addFundingEntity(target.name.value);
      } else if (activeTab === 'accounts') {
        await DB.addAccount({ 
          name: target.name.value, 
          type: target.type.value, 
          balance: 0 
        });
      }

      setShowModal(false);
      await loadData();
    } catch (err: any) {
      console.error("Setup Module Error:", err);
      setSubmitError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm(AR.confirmation)) return;
    try {
      if (activeTab === 'services') await DB.deleteService(id);
      if (activeTab === 'stores') await DB.deleteStore(id);
      if (activeTab === 'products') await DB.deleteProduct(id);
      if (activeTab === 'funding') await DB.deleteFundingEntity(id);
      if (activeTab === 'accounts') await DB.deleteAccount(id);
      await loadData();
    } catch (err: any) {
      alert(err.message || "حدث خطأ أثناء الحذف");
    }
  };

  return (
    <div className="space-y-6">
      {/* عرض خطأ المخطط بشكل بارز */}
      {isSchemaError && (
        <div className="bg-red-50 border-2 border-red-200 p-8 rounded-[2rem] text-center animate-in zoom-in-95">
          <div className="bg-red-100 text-red-600 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-4 border-4 border-white shadow-sm">
            <Database size={40} />
          </div>
          <h2 className="text-2xl font-black text-red-700 mb-2">قاعدة البيانات غير جاهزة!</h2>
          <p className="text-red-600 max-w-xl mx-auto font-bold text-sm">
            الجداول المطلوبة للنظام غير موجودة في مشروع Supabase الخاص بك.
            يرجى نسخ كود SQL من ملف <span className="underline">supabase.ts</span> وتشغيله في SQL Editor بموقع Supabase.
          </p>
          <button 
            onClick={loadData}
            className="mt-6 px-10 py-3 bg-red-600 text-white rounded-xl font-bold shadow-lg shadow-red-600/20 hover:bg-red-700 transition-all flex items-center justify-center gap-2 mx-auto"
          >
            <AlertCircle size={20} /> تحديث الاتصال بعد الإصلاح
          </button>
        </div>
      )}

      {!isSchemaError && (
        <>
          <div className="flex flex-wrap gap-2 p-1 bg-gray-200/50 rounded-xl w-fit no-print">
            <button onClick={() => setActiveTab('services')} className={`flex items-center gap-2 px-6 py-2 rounded-lg font-bold transition-all ${activeTab === 'services' ? 'bg-white shadow-sm text-primary-600' : 'text-gray-500 hover:text-gray-700'}`}>
              <Tag size={18} /> {AR.services}
            </button>
            <button onClick={() => setActiveTab('stores')} className={`flex items-center gap-2 px-6 py-2 rounded-lg font-bold transition-all ${activeTab === 'stores' ? 'bg-white shadow-sm text-primary-600' : 'text-gray-500 hover:text-gray-700'}`}>
              <StoreIcon size={18} /> {AR.stores}
            </button>
            <button onClick={() => setActiveTab('products')} className={`flex items-center gap-2 px-6 py-2 rounded-lg font-bold transition-all ${activeTab === 'products' ? 'bg-white shadow-sm text-primary-600' : 'text-gray-500 hover:text-gray-700'}`}>
              <Package size={18} /> {AR.products}
            </button>
            <button onClick={() => setActiveTab('funding')} className={`flex items-center gap-2 px-6 py-2 rounded-lg font-bold transition-all ${activeTab === 'funding' ? 'bg-white shadow-sm text-primary-600' : 'text-gray-500 hover:text-gray-700'}`}>
              <CreditCard size={18} /> {AR.funding}
            </button>
            <button onClick={() => setActiveTab('accounts')} className={`flex items-center gap-2 px-6 py-2 rounded-lg font-bold transition-all ${activeTab === 'accounts' ? 'bg-white shadow-sm text-primary-600' : 'text-gray-500 hover:text-gray-700'}`}>
              <Wallet size={18} /> الخزائن والبنك
            </button>
          </div>

          <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden min-h-[400px]">
            <div className="p-6 border-b flex justify-between items-center bg-gray-50/20">
              <h3 className="font-bold text-lg">
                {activeTab === 'services' && 'إدارة الخدمات والأسعار'}
                {activeTab === 'stores' && 'إدارة المخازن'}
                {activeTab === 'products' && 'دليل الأصناف الطبي'}
                {activeTab === 'funding' && 'جهات التعاقد'}
                {activeTab === 'accounts' && 'تعريف الخزائن والحسابات'}
              </h3>
              <button onClick={() => { setSubmitError(null); setShowModal(true); }} className="bg-primary-600 text-white px-6 py-2 rounded-xl text-sm font-bold flex items-center gap-2 shadow-sm hover:bg-primary-700 transition-colors">
                <Plus size={16} /> {AR.add}
              </button>
            </div>

            <div className="p-6">
              {loading && !showModal ? (
                <div className="flex justify-center py-20"><Loader2 className="animate-spin text-primary-600" size={40} /></div>
              ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                  {activeTab === 'accounts' && accounts.map(acc => (
                    <div key={acc.id} className="p-4 border rounded-xl flex justify-between items-center bg-white group hover:border-primary-300">
                      <div className="flex items-center gap-3">
                        <div className="p-2 bg-emerald-50 text-emerald-600 rounded-lg"><Wallet size={20} /></div>
                        <div>
                          <div className="font-bold text-gray-800">{acc.name}</div>
                          <div className="text-[10px] text-gray-400 uppercase">{acc.type === 'CASH' ? 'خزينة نقدية' : 'حساب بنكي'}</div>
                        </div>
                      </div>
                      <button onClick={() => handleDelete(acc.id)} className="p-2 text-gray-400 hover:text-red-600 opacity-0 group-hover:opacity-100"><Trash2 size={16} /></button>
                    </div>
                  ))}
                  {activeTab === 'services' && services.map(s => (
                    <div key={s.id} className="p-4 border rounded-xl flex justify-between items-center bg-white group hover:border-primary-300">
                      <div><div className="font-bold">{s.name}</div><div className="text-sm text-primary-600 font-bold">{s.price} ج.م</div></div>
                      <button onClick={() => handleDelete(s.id)} className="p-2 text-red-400 opacity-0 group-hover:opacity-100"><Trash2 size={16} /></button>
                    </div>
                  ))}
                  {activeTab === 'stores' && stores.map(st => (
                    <div key={st.id} className="p-4 border rounded-xl flex justify-between items-center bg-white group hover:border-primary-300">
                      <div><div className="font-bold">{st.name}</div><div className="text-xs text-gray-400">{st.isMain ? 'مخزن رئيسي' : 'مخزن فرعي'}</div></div>
                      <button onClick={() => handleDelete(st.id)} className="p-2 text-red-400 opacity-0 group-hover:opacity-100"><Trash2 size={16} /></button>
                    </div>
                  ))}
                  {activeTab === 'products' && products.map(p => (
                    <div key={p.id} className="p-4 border rounded-xl flex justify-between items-center bg-white group shadow-sm hover:shadow-md transition-all hover:border-primary-300">
                      <div className="flex items-center gap-3">
                        <div className="p-2 bg-blue-50 text-blue-600 rounded-lg"><Layers size={20} /></div>
                        <div className="flex-1">
                          <div className="font-bold text-gray-800">{p.name}</div>
                          <div className="text-[10px] text-gray-400 font-bold">الوحدة: {p.unit} | التصنيف: {p.category || 'غير محدد'}</div>
                          <div className="text-[9px] text-primary-600">الباركود: {p.barcode || '---'}</div>
                        </div>
                      </div>
                      <button onClick={() => handleDelete(p.id)} className="p-2 text-red-400 opacity-0 group-hover:opacity-100 transition-all"><Trash2 size={16} /></button>
                    </div>
                  ))}
                  {activeTab === 'funding' && funding.map(f => (
                    <div key={f.id} className="p-4 border rounded-xl flex justify-between items-center bg-white group hover:border-primary-300">
                      <div className="font-bold text-gray-800">{f.name}</div>
                      <button onClick={() => handleDelete(f.id)} className="p-2 text-red-400 opacity-0 group-hover:opacity-100"><Trash2 size={16} /></button>
                    </div>
                  ))}
                  {((activeTab === 'services' && services.length === 0) || 
                    (activeTab === 'stores' && stores.length === 0) || 
                    (activeTab === 'products' && products.length === 0) || 
                    (activeTab === 'funding' && funding.length === 0) || 
                    (activeTab === 'accounts' && accounts.length === 0)) && !loading && (
                    <div className="col-span-full py-10 text-center text-gray-300 italic">لا توجد بيانات مسجلة. يرجى التأكد من تشغيل كود SQL لإنشاء الجداول.</div>
                  )}
                </div>
              )}
            </div>
          </div>
        </>
      )}

      {showModal && (
        <div className="fixed inset-0 z-50 bg-black/60 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-lg rounded-2xl shadow-2xl animate-in zoom-in-95 overflow-hidden">
            <div className="p-6 bg-primary-600 text-white flex justify-between items-center">
              <h3 className="text-xl font-bold flex items-center gap-2"><Plus size={22} /> إضافة جديد</h3>
              <button onClick={() => setShowModal(false)}><X size={24} /></button>
            </div>

            {submitError && (
              <div className="p-4 bg-red-50 text-red-700 text-xs font-bold border-b border-red-100 flex items-center gap-2">
                <AlertCircle size={16} /> {submitError}
              </div>
            )}

            <form onSubmit={handleAddItem} className="p-8 space-y-4 max-h-[70vh] overflow-y-auto custom-scrollbar">
              {activeTab === 'accounts' ? (
                <>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-gray-500 mr-2">اسم الخزينة أو البنك</label>
                    <input name="name" required placeholder="مثلاً: خزينة الاستقبال" className="w-full border rounded-xl p-3 bg-gray-50 outline-none focus:ring-2 focus:ring-primary-500" />
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-gray-500 mr-2">نوع الحساب</label>
                    <select name="type" className="w-full border rounded-xl p-3 bg-gray-50 outline-none focus:ring-2 focus:ring-primary-500">
                      <option value="CASH">خزينة نقدية</option>
                      <option value="BANK">حساب بنكي</option>
                    </select>
                  </div>
                </>
              ) : activeTab === 'services' ? (
                <>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-gray-500 mr-2">اسم الخدمة</label>
                    <input name="name" required placeholder="اسم الخدمة" className="w-full border rounded-xl p-3 bg-gray-50 outline-none focus:ring-2 focus:ring-primary-500" />
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-gray-500 mr-2">السعر (ج.م)</label>
                    <input name="price" type="number" step="0.01" required placeholder="0.00" className="w-full border rounded-xl p-3 bg-gray-50 outline-none focus:ring-2 focus:ring-primary-500" />
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-gray-500 mr-2">التصنيف</label>
                    <select name="category" className="w-full border rounded-xl p-3 bg-gray-50 outline-none">
                      <option value="DIALYSIS">جلسة غسيل</option>
                      <option value="LAB">تحاليل</option>
                      <option value="PHARMACY">صيدلية</option>
                      <option value="OTHER">أخرى</option>
                    </select>
                  </div>
                </>
              ) : activeTab === 'stores' ? (
                <>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-gray-500 mr-2">اسم المخزن</label>
                    <input name="name" required placeholder="مثلاً: مخزن الدور الأول" className="w-full border rounded-xl p-3 bg-gray-50 outline-none focus:ring-2 focus:ring-primary-500" />
                  </div>
                  <label className="flex items-center gap-3 p-4 bg-gray-50 rounded-xl cursor-pointer border border-transparent hover:border-primary-200 transition-all mt-4">
                    <input name="isMain" type="checkbox" className="w-5 h-5 accent-primary-600" />
                    <span className="font-bold text-gray-700 text-sm">مخزن رئيسي؟</span>
                  </label>
                </>
              ) : activeTab === 'products' ? (
                <div className="space-y-4">
                  <div className="space-y-1">
                    <label className="text-[10px] font-bold text-gray-400 mr-2 uppercase">الاسم العلمي / التجاري</label>
                    <input name="name" required placeholder="مثلاً: فلتر غسيل 1.8" className="w-full border rounded-xl p-3 bg-gray-50 outline-none focus:ring-2 focus:ring-primary-500 font-bold" />
                  </div>

                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-1">
                      <label className="text-[10px] font-bold text-gray-400 mr-2 uppercase">الوحدة</label>
                      <input name="unit" required placeholder="قطعة، لتر، علبة" className="w-full border rounded-xl p-3 bg-gray-50 outline-none focus:ring-2 focus:ring-primary-500" />
                    </div>
                    <div className="space-y-1">
                      <label className="text-[10px] font-bold text-gray-400 mr-2 uppercase">التصنيف</label>
                      <select name="category" className="w-full border rounded-xl p-3 bg-gray-50 outline-none">
                        <option value="MEDICINE">أدوية</option>
                        <option value="CONSUMABLE">مستهلكات طبية</option>
                        <option value="FLUID">محاليل</option>
                        <option value="OTHER">أخرى</option>
                      </select>
                    </div>
                  </div>

                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-1">
                      <label className="text-[10px] font-bold text-gray-400 mr-2 uppercase">حد الطلب</label>
                      <input name="minStock" type="number" placeholder="10" className="w-full border rounded-xl p-3 bg-gray-50 outline-none focus:ring-2 focus:ring-primary-500" />
