  }

  static async addFinanceTx(tx: Partial<Transaction>) {
    const { data, error } = await supabase.from('transactions').insert([tx]).select();
    if (error) return handleError(error, "فشل تسجيل المعاملة");
    return data?.[0];
  }

  static async log(action: string, details: string) {
    try {
      const userStr = localStorage.getItem('dialysis_user');
      const user = userStr ? JSON.parse(userStr) : { name: 'Unknown' };
      await supabase.from('audit_logs').insert([{
        user_id: user.name,
        action,
        details,
        timestamp: new Date().toISOString()
      }]);
    } catch (e) {}
  }

  static async getSessions() { try { const { data, error } = await supabase.from('dialysis_sessions').select('*, patients(name)'); if(error) return []; return data || []; } catch(e) {return [];} }
  static async addSession(s: any) { const { data, error } = await supabase.from('dialysis_sessions').insert([s]).select(); if(error) return handleError(error, "خطأ"); return data?.[0]; }
  static async getLabDefinitions() { try { const { data, error } = await supabase.from('lab_test_definitions').select('*'); if(error) return []; return data || []; } catch(e) {return [];} }
  static async addLabDefinition(d: any) { const { data, error } = await supabase.from('lab_test_definitions').insert([d]).select(); if(error) return handleError(error, "خطأ"); return data?.[0]; }
  static async getLabTests() { try { const { data, error } = await supabase.from('lab_tests').select('*, patients(name), lab_test_definitions(name)'); if(error) return []; return data || []; } catch(e) {return [];} }
  static async addLabTest(t: any) { const { data, error } = await supabase.from('lab_tests').insert([t]).select(); if(error) return handleError(error, "خطأ"); return data?.[0]; }
  static async updateLabResult(id: string, result: string) { const { data, error } = await supabase.from('lab_tests').update({ result, status: 'COMPLETED' }).eq('id', id).select(); if(error) return handleError(error, "خطأ"); return data?.[0]; }
  static async getEmployees() { try { const { data, error } = await supabase.from('employees').select('*'); if(error) return []; return data || []; } catch(e) {return [];} }
  static async getShifts() { try { const { data, error } = await supabase.from('shift_records').select('*'); if(error) return []; return data || []; } catch(e) {return [];} }
  static async resetShifts() { const { error } = await supabase.from('shift_records').delete().neq('id', '00000000-0000-0000-0000-000000000000'); if(error) return handleError(error, "خطأ"); }
  static async createTransferRequest(r: any) { const { data, error } = await supabase.from('transfer_requests').insert([r]).select(); if(error) return handleError(error, "خطأ"); return data?.[0]; }
  static async getTransferRequests() { try { const { data, error } = await supabase.from('transfer_requests').select('*'); if(error) return []; return data || []; } catch(e) {return [];} }
}

import React, { useState, useEffect } from 'react';
import { AR } from '../constants';
import { DB } from '../store';
import { Service, Store, Product, FundingEntity, FinancialAccount } from '../types';
import { Package, Store as StoreIcon, CreditCard, Tag, Plus, Trash2, X, Loader2, Wallet, Layers, Info, Barcode, AlertCircle, CheckCircle, Database } from 'lucide-react';

const SetupModule: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'services' | 'stores' | 'products' | 'funding' | 'accounts'>('services');
  const [loading, setLoading] = useState(false);
  const [showModal, setShowModal] = useState(false);
  const [submitError, setSubmitError] = useState<string | null>(null);
  const [isSchemaError, setIsSchemaError] = useState(false);

  const [services, setServices] = useState<Service[]>([]);
  const [stores, setStores] = useState<Store[]>([]);
  const [products, setProducts] = useState<Product[]>([]);
  const [funding, setFunding] = useState<FundingEntity[]>([]);
  const [accounts, setAccounts] = useState<FinancialAccount[]>([]);

  useEffect(() => {
    loadData();
  }, [activeTab]);

  const loadData = async () => {
    setLoading(true);
    setSubmitError(null);
    setIsSchemaError(false);
    try {
      if (activeTab === 'services') setServices(await DB.getServices());
      if (activeTab === 'stores') setStores(await DB.getStores());
      if (activeTab === 'products') setProducts(await DB.getProducts());
      if (activeTab === 'funding') setFunding(await DB.getFundingEntities());
      if (activeTab === 'accounts') setAccounts(await DB.getAccounts());
    } catch (err: any) {
      console.error(err);
      setSubmitError(err.message);
      if (err.message?.includes('SCHEMA_ERROR')) {
        setIsSchemaError(true);
      }
    } finally {
      setLoading(false);
    }
  };

  const handleAddItem = async (e: React.FormEvent) => {
    e.preventDefault();
    const target = e.target as any;
    setLoading(true);
    setSubmitError(null);

    try {
      if (activeTab === 'services') {
        await DB.addService({ 
          name: target.name.value, 
          price: parseFloat(target.price.value) || 0, 
          category: target.category.value 
        });
      } else if (activeTab === 'stores') {
        await DB.addStore({ 
          name: target.name.value, 
          is_main: target.is_main.checked 
        });
      } else if (activeTab === 'products') {
        await DB.addProduct({ 
          name: target.name.value, 
          unit: target.unit.value, 
          min_stock: parseInt(target.min_stock.value) || 0, 
          price: parseFloat(target.price.value) || 0,
          category: target.category.value,
          barcode: target.barcode.value,
          description: target.description.value
        });
      } else if (activeTab === 'funding') {
        await DB.addFundingEntity(target.name.value);
      } else if (activeTab === 'accounts') {
        await DB.addAccount({ 
          name: target.name.value, 
          type: target.type.value, 
          balance: 0 
        });
      }

      setShowModal(false);
      await loadData();
    } catch (err: any) {
      console.error("Setup Module Error:", err);
      setSubmitError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm(AR.confirmation)) return;
    try {
      if (activeTab === 'services') await DB.deleteService(id);
      if (activeTab === 'stores') await DB.deleteStore(id);
      if (activeTab === 'products') await DB.deleteProduct(id);
      if (activeTab === 'funding') await DB.deleteFundingEntity(id);
      if (activeTab === 'accounts') await DB.deleteAccount(id);
      await loadData();
    } catch (err: any) {
      alert(err.message || "حدث خطأ أثناء الحذف");
    }
  };

