                      {p.name}
                      {/* Use date_of_birth to match Patient interface */}
                      <span className="text-primary-500 text-[10px] mr-1">({calculateAge(p.date_of_birth)})</span>
                    </div>
                    <div className="text-xs text-gray-400">{p.phone}</div>
