} from './types.ts';
import { supabase } from './supabase.ts';

const handleError = (error: any, fallbackMessage: string) => {
  console.error("Database Error Details:", error);
  const msg = error.message?.toLowerCase() || "";

  // التحقق من أخطاء الجداول أو الحقول المفقودة أو مشاكل الذاكرة المؤقتة (Schema Cache)
  if (
    error.code === '42P01' || 
    error.code === '42703' || 
    msg.includes('not found') || 
    msg.includes('schema cache') || 
    msg.includes('column')
  ) {
    throw new Error(`SCHEMA_ERROR: خطأ في قاعدة البيانات (حقل أو جدول مفقود). 
يرجى تشغيل كود SQL المحدث من ملف supabase.ts في SQL Editor بـ Supabase لإعادة بناء الجداول.`);
  }

  throw new Error(error.message || fallbackMessage);
};

