const handleError = (error: any, fallbackMessage: string) => {
  console.error("Database Error Details:", error);
  const msg = error.message?.toLowerCase() || "";
  const code = error.code;

  // 42P01: undefined_table (الجدول غير موجود)
  // 42703: undefined_column (الحقل غير موجود)
  // PGRST107: Schema cache error (خطأ في الذاكرة المؤقتة للمخطط)
  if (
    code === '42P01' || 
    code === '42703' || 
    code === 'PGRST107' ||
    msg.includes('not found') || 
    msg.includes('schema cache') || 
    msg.includes('column')
  ) {
    throw new Error(`SCHEMA_ERROR: خطأ في بنية قاعدة البيانات. 
الجدول أو الحقل المطلوب غير موجود. يرجى التوجه لصفحة الإعدادات وتشغيل كود SQL المحدث.`);
  }

  throw new Error(error.message || fallbackMessage);
};

