{`-- 1. تنظيف الجداول القديمة
DROP TABLE IF EXISTS stock_transactions, transfer_requests, lab_tests, lab_test_definitions, dialysis_sessions, transactions, shift_records, employees, patients, products, stores, financial_accounts, funding_entities, services, system_users, audit_logs CASCADE;

-- 2. تفعيل الإضافات
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";

-- 3. إنشاء الجداول
CREATE TABLE stores (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
