} from 'lucide-react';

const UsersModule: React.FC = () => {
  const [searchTerm, setSearchTerm] = useState('');
  const [showModal, setShowModal] = useState(false);
  const [editingUserId, setEditingUserId] = useState<string | null>(null);
  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [userData, setUserData] = useState<Partial<User>>({ permissions: [] });

  const [availableStores, setAvailableStores] = useState<Store[]>([]);
  const [availableAccounts, setAvailableAccounts] = useState<FinancialAccount[]>([]);
  const [isSchemaError, setIsSchemaError] = useState(false);

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    setIsSchemaError(false);
    try {
      const [u, s, a] = await Promise.all([
        DB.getUsers(),
        DB.getStores(),
        DB.getAccounts()
      ]);

      const userList = Array.isArray(u) ? u : [];
      setUsers(userList);
      setAvailableStores(s || []);
      setAvailableAccounts(a || []);
    } catch (err: any) {
      console.error("UsersModule Error:", err);
      if (err.message?.includes('SCHEMA_ERROR')) {
        setIsSchemaError(true);
      }
    } finally {
      setLoading(false);
    }
  };

  const togglePermission = (perm: Permission) => {
    const current = userData.permissions || [];
    if (current.includes(perm)) {
      setUserData({ ...userData, permissions: current.filter(p => p !== perm) });
    } else {
      setUserData({ ...userData, permissions: [...current, perm] });
    }
  };

  const handleSaveUser = async (e: React.FormEvent) => {
    e.preventDefault();
    setSubmitting(true);
    try {
      if (editingUserId) {
        await DB.updateUser(editingUserId, userData);
      } else {
        await DB.addUser(userData);
      }
      await loadData();
      setShowModal(false);
    } catch (err) {
      alert("حدث خطأ أثناء حفظ بيانات المستخدم.");
    } finally {
      setSubmitting(false);
    }
  };

  if (isSchemaError) {
    return (
      <div className="max-w-4xl mx-auto space-y-6 animate-in zoom-in-95">
        <div className="bg-red-50 border-2 border-red-200 p-12 rounded-[3rem] text-center shadow-2xl shadow-red-500/5">
          <div className="bg-red-100 text-red-600 w-24 h-24 rounded-3xl flex items-center justify-center mx-auto mb-8 border-4 border-white shadow-lg">
            <Database size={48} />
          </div>
          <h2 className="text-3xl font-black text-red-700 mb-4">قاعدة البيانات غير مهيأة!</h2>
          <p className="text-red-600 max-w-2xl mx-auto font-bold text-lg mb-10 leading-relaxed">
            النظام لم يجد جدول المستخدمين في قاعدة البيانات. هذا يعني أنك بحاجة لتشغيل كود الـ SQL المحدث في Supabase SQL Editor.
          </p>
          <button 
            onClick={() => window.location.reload()} 
            className="px-12 py-5 bg-red-600 text-white rounded-2xl font-black shadow-2xl shadow-red-600/30 hover:bg-red-700 hover:-translate-y-1 transition-all flex items-center justify-center gap-3 mx-auto text-lg"
          >
            <RefreshCw size={24} /> إعادة محاولة الاتصال
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div className="relative w-full md:w-96">
