                            <span className="text-xs font-black">{val}</span>
                            {userData.permissions?.includes(key as Permission) && <Check size={18} />}
                         </button>
                      ))}
                   </div>
                </div>
             </form>
             <div className="p-10 border-t bg-gray-50 flex gap-4 shrink-0">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 py-5 bg-white border-2 rounded-2xl font-black text-gray-500">إلغاء</button>
                <button type="submit" disabled={submitting} className="flex-[2] py-5 bg-primary-600 text-white rounded-2xl font-black shadow-xl shadow-primary-600/30 hover:bg-primary-700 disabled:opacity-70">
                   {submitting ? 'جاري الحفظ...' : 'حفظ بيانات الحساب'}
                </button>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

