const handleError = (error: any, fallbackMessage: string) => {
  console.error("Database Error Details:", error);
  const msg = error.message?.toLowerCase() || "";
  const code = error.code;

  // 42P01: undefined_table, 42703: undefined_column, PGRST107: Schema cache error
  if (
    code === '42P01' || 
    code === '42703' || 
    code === 'PGRST107' ||
    msg.includes('not found') || 
    msg.includes('schema cache') || 
    msg.includes('column')
  ) {
    throw new Error(`SCHEMA_ERROR: خطأ في بنية قاعدة البيانات. يرجى التوجه لصفحة الإعدادات وتشغيل كود SQL المحدث لإعادة بناء الجداول.`);
  }

  throw new Error(error.message || fallbackMessage);
};

export class DB {
  static async login(username: string, password: string): Promise<User | null> {
    try {
      const { data, error } = await supabase
        .from('system_users')
        .select('*')
        .eq('username', username)
        .eq('password', password)
        .single();
      if (error || !data) return null;
      await this.log('تسجيل دخول', `دخل المستخدم ${data.name} إلى النظام`);
      return data as User;
    } catch (e) { return null; }
