  const [selectedQuantity, setSelectedQuantity] = useState(1);
  const [selectedPrice, setSelectedPrice] = useState(0);

  const [documentNumber, setDocumentNumber] = useState('');
  const [voucherNote, setVoucherNote] = useState('');
  const [targetStoreId, setTargetStoreId] = useState('');

  // Get current user permissions
  const currentUser = JSON.parse(localStorage.getItem('dialysis_user') || '{}');
  const userPerms = currentUser.permissions || [];

  useEffect(() => { loadData(); }, [activeSubTab]);

  const loadData = async () => {
    setLoading(true);
    try {
      const [p, s, r, tx] = await Promise.all([
        DB.getProducts(), 
        DB.getStores(), 
        DB.getTransferRequests(),
        DB.getStockTransactions()
      ]);
      setProducts(p || []);
      setStores(s || []);
      setRequests(r || []);
      setStockTransactions(tx || []);
    } catch (err) {
      console.error("Error in Inventory loadData:", err);
    } finally {
      setLoading(false);
    }
  };

  // Helper to calculate current stock for a product in a specific store
  const calculateStock = (productId: string, storeId: string) => {
    let balance = 0;
    stockTransactions.forEach(tx => {
      if (tx.product_id !== productId) return;

      if (tx.type === 'ADD' && tx.store_id === storeId) {
        balance += tx.quantity;
      } else if (tx.type === 'DEDUCT' && tx.store_id === storeId) {
        balance -= tx.quantity;
      } else if (tx.type === 'TRANSFER') {
        if (tx.store_id === storeId) balance -= tx.quantity;
        if (tx.target_store_id === storeId) balance += tx.quantity;
      }
    });
    return balance;
  };

  // Helper to calculate total stock across all visible stores for a product
  const calculateTotalStock = (productId: string) => {
    return visibleStores.reduce((acc, store) => acc + calculateStock(productId, store.id), 0);
  };

  // Filter stores that the user can VIEW or MANAGE
  const visibleStores = stores.filter(s => 
    userPerms.includes('SYSTEM_SETUP') || 
    userPerms.includes('MANAGE_INVENTORY') || 
    userPerms.includes(`STORE_VIEW:${s.id}`) || 
    userPerms.includes(`STORE_MANAGE:${s.id}`)
  );

  // Filter stores that the user can MANAGE
  const manageableStores = stores.filter(s => 
    userPerms.includes('SYSTEM_SETUP') || 
    userPerms.includes('MANAGE_INVENTORY') || 
    userPerms.includes(`STORE_MANAGE:${s.id}`)
  );

  const generateDocNumber = (type: string) => {
    const year = new Date().getFullYear();
    const prefix = type === 'ADD' ? 'REC' : type === 'DEDUCT' ? 'OUT' : 'TRF';
    const random = Math.floor(10000 + Math.random() * 90000);
    return `${prefix}-${year}-${random}`;
  };

  const openModal = (type: 'ADD' | 'DEDUCT' | 'TRANSFER') => {
    if (manageableStores.length === 0) {
      return alert("لا تملك صلاحية إدارة أي مخزن حالياً. يرجى مراجعة الإدارة.");
    }
    setMoveType(type);
    setVoucherItems([]);
    setDocumentNumber(generateDocNumber(type));
    setVoucherNote('');
    setTargetStoreId('');
    setShowMoveModal(true);
  };

  const addItemToVoucher = () => {
    if (!selectedProductId || selectedQuantity <= 0) return;
    if (voucherItems.find(i => i.productId === selectedProductId)) return alert("هذا الصنف مضاف بالفعل في القائمة");
    const p = products.find(prod => prod.id === selectedProductId);
    setVoucherItems([...voucherItems, { productId: selectedProductId, quantity: selectedQuantity, price: selectedPrice || p?.price || 0 }]);
    setSelectedProductId('');
    setSelectedQuantity(1);
    setSelectedPrice(0);
  };

  const removeItemFromVoucher = (pid: string) => setVoucherItems(voucherItems.filter(i => i.productId !== pid));

  const handleVoucherAction = async (e: React.FormEvent) => {
    e.preventDefault();
    if (voucherItems.length === 0) return alert("يرجى إضافة أصناف أولاً للمستند");

    const target = e.target as any;
    const storeId = target.storeId.value;

    if (!storeId) return alert("يرجى اختيار المخزن");
    if (moveType === 'TRANSFER' && !targetStoreId) return alert("يرجى اختيار المخزن المستلم");
    if (moveType === 'TRANSFER' && storeId === targetStoreId) return alert("لا يمكن التحويل لنفس المخزن");

    setLoading(true);
    try {
      if (moveType === 'TRANSFER') {
        // Here we create the StockTransaction directly for immediate balance update
        // (In a more complex system, this might go to a 'pending' state first)
        for (const item of voucherItems) {
          await DB.addStockTransaction({
            product_id: item.productId,
            store_id: storeId,
            target_store_id: targetStoreId,
            type: 'TRANSFER',
            quantity: item.quantity,
            date: new Date().toISOString().split('T')[0],
            note: `${documentNumber} | ${voucherNote}`
          });
        }
      } else {
        for (const item of voucherItems) {
          await DB.addStockTransaction({
            product_id: item.productId,
            store_id: storeId,
            type: moveType,
            quantity: item.quantity,
            date: new Date().toISOString().split('T')[0],
            note: `${documentNumber} | ${voucherNote}`
          });
        }
      }
      setShowMoveModal(false);
      setVoucherItems([]);
      alert(`تم تنفيذ العملية بنجاح. رقم المستند: ${documentNumber}`);
      loadData();
    } catch (err) {
      alert("حدث خطأ أثناء تنفيذ العملية.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 no-print">
        <div className="flex gap-2 p-1 bg-gray-200/50 rounded-xl w-fit">
          <button onClick={() => setActiveSubTab('stock')} className={`px-6 py-2 rounded-lg font-bold transition-all ${activeSubTab === 'stock' ? 'bg-white shadow-sm text-primary-600' : 'text-gray-500'}`}>الأرصدة المتاحة</button>
          <button onClick={() => setActiveSubTab('requests')} className={`px-6 py-2 rounded-lg font-bold transition-all ${activeSubTab === 'requests' ? 'bg-white shadow-sm text-indigo-600' : 'text-gray-500'}`}>طلبات التحويل ({requests.filter(r => r.status === 'PENDING').length})</button>
        </div>

        <div className="flex gap-2">
           <button onClick={() => openModal('TRANSFER')} className="bg-indigo-600 text-white px-5 py-3 rounded-xl text-sm font-bold flex items-center gap-2 hover:bg-indigo-700 shadow-md transition-all"><ArrowLeftRight size={18} /> تحويل داخلي</button>
           <button onClick={() => openModal('DEDUCT')} className="bg-orange-600 text-white px-5 py-3 rounded-xl text-sm font-bold flex items-center gap-2 shadow-md hover:bg-orange-700 transition-all"><TrendingDown size={18} /> إذن صـــرف</button>
           <button onClick={() => openModal('ADD')} className="bg-green-600 text-white px-5 py-3 rounded-xl text-sm font-bold flex items-center gap-2 shadow-md hover:bg-green-700 transition-all"><TrendingUp size={18} /> توريد</button>
        </div>
      </div>

      <div className="bg-white rounded-3xl shadow-sm border overflow-hidden min-h-[400px]">
        {loading && activeSubTab === 'stock' ? (
          <div className="flex flex-col items-center justify-center py-40 gap-4 text-gray-400">
             <Loader2 className="animate-spin text-primary-600" size={40} />
             <p className="font-bold">جاري تحميل المخزون...</p>
          </div>
        ) : activeSubTab === 'stock' ? (
          <div className="p-8">
             <div className="flex justify-between items-center mb-6">
               <h3 className="font-bold text-xl text-gray-800">الأرصدة في المخازن المصرح لك بمشاهدتها</h3>
               <div className="flex items-center gap-4 text-xs">
                 <div className="flex items-center gap-1"><div className="w-3 h-3 bg-rose-50 border border-rose-200 rounded"></div> نواقص (أقل من حد الطلب)</div>
                 <div className="flex items-center gap-1"><div className="w-3 h-3 bg-white border border-gray-200 rounded"></div> متوفر</div>
               </div>
             </div>
             <div className="overflow-x-auto">
               <table className="w-full text-right">
                  <thead className="bg-gray-50 border-b">
                    <tr>
                      <th className="px-6 py-4 font-bold text-gray-600 text-xs">الصنف</th>
                      <th className="px-6 py-4 font-bold text-gray-600 text-xs">التصنيف</th>
                      <th className="px-6 py-4 font-bold text-gray-600 text-xs text-center">الإجمالي العام</th>
                      {visibleStores.map(s => <th key={s.id} className="px-6 py-4 font-bold text-gray-600 text-xs text-center">{s.name}</th>)}
                    </tr>
                  </thead>
                  <tbody className="divide-y">
                    {products.map(p => {
                      const totalStock = calculateTotalStock(p.id);
                      const isLowStock = totalStock <= (p.min_stock || 0);

                      return (
                        <tr key={p.id} className={`transition-colors ${isLowStock ? 'bg-rose-50/50 hover:bg-rose-50' : 'hover:bg-gray-50'}`}>
                          <td className="px-6 py-4 font-bold text-gray-700">
                             <div className="flex items-center gap-2">
                               {isLowStock && <AlertTriangle size={14} className="text-rose-500" />}
                               <span>{p.name} <span className="text-[10px] text-gray-400 font-normal">({p.unit})</span></span>
                             </div>
                          </td>
                          <td className="px-6 py-4 text-xs text-gray-400">{p.category || '---'}</td>
                          <td className={`px-6 py-4 font-black text-center ${isLowStock ? 'text-rose-600' : 'text-primary-800'}`}>
                            {totalStock}
                            {isLowStock && <span className="block text-[8px] font-bold">حد الطلب: {p.min_stock}</span>}
                          </td>
                          {visibleStores.map(s => {
                            const storeQty = calculateStock(p.id, s.id);
                            return (
                              <td key={s.id} className={`px-6 py-4 font-black text-center ${storeQty === 0 ? 'text-gray-300' : 'text-primary-700'}`}>
                                {storeQty}
                              </td>
                            );
                          })}
                        </tr>
                      );
                    })}
                    {products.length === 0 && (
                      <tr><td colSpan={visibleStores.length + 3} className="py-20 text-center text-gray-300 italic">لا توجد أصناف معرفة</td></tr>
                    )}
                  </tbody>
               </table>
             </div>
          </div>
        ) : (
          <div className="p-8 text-center text-gray-400 italic">سجل طلبات التحويل المخصص للمخازن التي تديرها</div>
        )}
      </div>

      {showMoveModal && (
        <div className="fixed inset-0 z-50 bg-black/60 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-5xl rounded-3xl shadow-2xl flex flex-col max-h-[95vh] overflow-hidden animate-in zoom-in-95">
            <div className={`p-6 text-white flex justify-between items-center ${moveType === 'ADD' ? 'bg-green-600' : moveType === 'TRANSFER' ? 'bg-indigo-600' : 'bg-orange-600'}`}>
              <div className="flex items-center gap-4">
                <h3 className="text-xl font-bold">{moveType === 'ADD' ? 'توريد' : moveType === 'TRANSFER' ? 'تحويل' : 'صرف'} مخزني</h3>
              </div>
              <button onClick={() => setShowMoveModal(false)} className="p-2 hover:bg-white/20 rounded-full transition-all"><X size={24} /></button>
            </div>

            <form onSubmit={handleVoucherAction} className="p-8 space-y-6 overflow-y-auto flex-1 custom-scrollbar">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6 bg-gray-50 p-6 rounded-3xl border">
                <div>
                  <label className="block text-xs font-bold text-gray-500 uppercase mb-2">المخزن (المصرح لك بإدارته)</label>
                  <select name="storeId" required className="w-full border rounded-xl p-3 bg-white font-bold outline-none">
                    <option value="">-- اختر المخزن --</option>
                    {manageableStores.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                  </select>
                </div>

                {moveType === 'TRANSFER' && (
                  <div>
                    <label className="block text-xs font-bold text-indigo-600 uppercase mb-2">مخزن الوجهة</label>
                    <select value={targetStoreId} onChange={e => setTargetStoreId(e.target.value)} required className="w-full border rounded-xl p-3 bg-white font-bold outline-none">
                      <option value="">-- اختر الوجهة --</option>
                      {stores.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                    </select>
                  </div>
                )}
              </div>

              {/* Items Section */}
              <div className="bg-primary-50/50 p-6 rounded-3xl border-2 border-dashed border-primary-200">
                 <div className="grid grid-cols-12 gap-4 items-end">
                    <div className="col-span-12 md:col-span-6">
                       <label className="block text-xs font-bold text-primary-700 mb-2">الصنف</label>
                       <select value={selectedProductId} onChange={e => setSelectedProductId(e.target.value)} className="w-full border rounded-xl p-3 bg-white outline-none">
                         <option value="">-- ابحث عن صنف... --</option>
                         {products.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                       </select>
                    </div>
                    <div className="col-span-6 md:col-span-3">
                       <label className="block text-xs font-bold text-primary-700 mb-2">الكمية</label>
                       <input type="number" min="0.1" step="0.1" value={selectedQuantity} onChange={e => setSelectedQuantity(parseFloat(e.target.value))} className="w-full border rounded-xl p-3 bg-white text-center font-bold outline-none" />
                    </div>
                    <div className="col-span-12 md:col-span-3">
                       <button type="button" onClick={addItemToVoucher} className="w-full py-3 bg-primary-600 text-white rounded-xl font-bold shadow-lg">إضافة</button>
                    </div>
                 </div>
              </div>

              <div className="border rounded-3xl overflow-hidden shadow-inner bg-white">
                 <table className="w-full text-right">
                    <thead className="bg-gray-100">
                       <tr>
                         <th className="px-6 py-3 font-bold text-gray-500">الصنف</th>
                         <th className="px-6 py-3 text-center font-bold text-gray-500">الكمية</th>
                         <th className="px-6 py-3 text-left font-bold text-gray-500">حذف</th>
                       </tr>
                    </thead>
                    <tbody className="divide-y">
                       {voucherItems.map((item, idx) => (
                         <tr key={idx}>
                            <td className="px-6 py-3 font-bold">{products.find(p => p.id === item.productId)?.name}</td>
                            <td className="px-6 py-3 text-center font-black text-primary-600">{item.quantity}</td>
                            <td className="px-6 py-3 text-left">
                               <button type="button" onClick={() => removeItemFromVoucher(item.productId)} className="text-red-400 p-2"><Trash2 size={16} /></button>
                            </td>
                         </tr>
                       ))}
                    </tbody>
                 </table>
              </div>
            </form>

            <div className="p-8 border-t bg-gray-50 flex gap-4">
              <button onClick={() => setShowMoveModal(false)} className="flex-1 py-4 bg-white border-2 rounded-2xl font-bold text-gray-500">إلغاء</button>
              <button onClick={handleVoucherAction} className={`flex-[2] py-4 text-white rounded-2xl font-bold shadow-xl ${moveType === 'ADD' ? 'bg-green-600' : moveType === 'TRANSFER' ? 'bg-indigo-600' : 'bg-orange-600'}`}>تأكيد الحفظ</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default InventoryModule;

import { 
  Patient, DialysisSession, Service, Invoice, Product, 
  Store, StockTransaction, Employee, FinancialAccount, 
  Transaction, FundingEntity, ShiftRecord, LabTest, LabTestDefinition, AuditLog,
  User, Permission, TransferRequest
} from './types.ts';
import { supabase } from './supabase.ts';

const handleError = (error: any, fallbackMessage: string) => {
  console.error("Database Error Details:", error);
  const msg = error.message?.toLowerCase() || "";
  const code = error.code;

  if (
    code === '42P01' || 
    code === '42703' || 
    code === 'PGRST107' ||
    msg.includes('not found') || 
    msg.includes('schema cache') || 
    msg.includes('column') ||
    msg.includes('relation')
  ) {
    throw new Error(`SCHEMA_ERROR: خطأ في بنية قاعدة البيانات. يرجى التوجه لصفحة الإعدادات وتشغيل كود SQL المحدث لإعادة بناء الجداول.`);
  }

  throw new Error(error.message || fallbackMessage);
};

export class DB {
  static async login(username: string, password: string): Promise<User | null> {
    try {
      const { data, error } = await supabase
        .from('system_users')
        .select('*')
        .eq('username', username)
        .eq('password', password)
        .single();
      if (error || !data) return null;
      await this.log('تسجيل دخول', `دخل المستخدم ${data.name} إلى النظام`);
      return data as User;
    } catch (e) { return null; }
  }

  static async getPatients() {
    const { data, error } = await supabase.from('patients').select('*').order('created_at', { ascending: false });
    if (error) return handleError(error, "فشل جلب المرضى");
    return data || [];
  }

  static async addPatient(p: Partial<Patient>) {
    const { data, error } = await supabase.from('patients').insert([p]).select();
    if (error) return handleError(error, "فشل إضافة المريض");
    await this.log('إضافة مريض', `تمت إضافة المريض ${p.name}`);
    return data?.[0];
  }

  static async getAccounts() {
    const { data, error } = await supabase.from('financial_accounts').select('*').order('name');
    if (error) return handleError(error, "فشل جلب الحسابات");
    return data || [];
  }

  static async addAccount(a: Partial<FinancialAccount>) {
    const { data, error } = await supabase.from('financial_accounts').insert([a]).select();
    if (error) return handleError(error, "فشل إضافة الحساب");
    return data?.[0];
  }

  static async deleteAccount(id: string) {
    const { error } = await supabase.from('financial_accounts').delete().eq('id', id);
    if (error) return handleError(error, "فشل حذف الحساب");
  }

  static async getProducts() {
    const { data, error } = await supabase.from('products').select('*').order('name');
    if (error) return handleError(error, "فشل جلب الأصناف");
    return data || [];
  }

  static async addProduct(p: Partial<Product>) {
    const { data, error } = await supabase.from('products').insert([p]).select();
    if (error) return handleError(error, "فشل إضافة الصنف");
    return data?.[0];
  }

  static async deleteProduct(id: string) {
    const { error } = await supabase.from('products').delete().eq('id', id);
    if (error) return handleError(error, "فشل حذف الصنف");
  }

  static async getStores() {
    const { data, error } = await supabase.from('stores').select('*').order('name');
    if (error) return handleError(error, "فشل جلب المخازن");
    return data || [];
  }

  static async addStore(s: Partial<Store>) {
    const { data, error } = await supabase.from('stores').insert([s]).select();
    if (error) return handleError(error, "فشل إضافة المخزن");
    return data?.[0];
  }

  static async deleteStore(id: string) {
    const { error } = await supabase.from('stores').delete().eq('id', id);
    if (error) return handleError(error, "فشل حذف المخزن");
  }

  static async getUsers() {
    const { data, error } = await supabase.from('system_users').select('*');
    if (error) return handleError(error, "فشل جلب المستخدمين");
    return data || [];
  }

  static async addUser(u: Partial<User>) {
    const { data, error } = await supabase.from('system_users').insert([u]).select();
    if (error) return handleError(error, "فشل إضافة المستخدم");
    return data?.[0];
  }

  static async updateUser(id: string, u: Partial<User>) {
    const updateData = { ...u };
    if (!updateData.password) delete updateData.password;
    const { data, error } = await supabase.from('system_users').update(updateData).eq('id', id).select();
    if (error) return handleError(error, "فشل تحديث المستخدم");
    return data?.[0];
  }

  static async deleteUser(id: string) {
    const { error } = await supabase.from('system_users').delete().eq('id', id);
    if (error) return handleError(error, "فشل حذف المستخدم");
  }

  static async getServices() {
    const { data, error } = await supabase.from('services').select('*').order('name');
    if (error) return handleError(error, "فشل جلب الخدمات");
    return data || [];
  }

  static async addService(s: Partial<Service>) {
    const { data, error } = await supabase.from('services').insert([s]).select();
    if (error) return handleError(error, "فشل إضافة الخدمة");
    return data?.[0];
  }

  static async deleteService(id: string) {
    const { error } = await supabase.from('services').delete().eq('id', id);
    if (error) return handleError(error, "فشل حذف الخدمة");
  }

  static async getFundingEntities() {
    const { data, error } = await supabase.from('funding_entities').select('*').order('name');
    if (error) return handleError(error, "فشل جلب جهات التمويل");
    return data || [];
  }

  static async addFundingEntity(name: string) {
    const { data, error } = await supabase.from('funding_entities').insert([{ name }]).select();
    if (error) return handleError(error, "فشل إضافة جهة التعاقد");
    return data?.[0];
  }

  static async deleteFundingEntity(id: string) {
    const { error } = await supabase.from('funding_entities').delete().eq('id', id);
    if (error) return handleError(error, "فشل حذف جهة التعاقد");
  }

  static async getTransactions() {
    const { data, error } = await supabase.from('transactions').select('*').order('date', { ascending: false });
    if (error) return handleError(error, "فشل جلب المعاملات");
    return data || [];
  }

  static async addFinanceTx(tx: Partial<Transaction>) {
    // 1. تسجيل المعاملة
    const { data, error } = await supabase.from('transactions').insert([tx]).select();
    if (error) return handleError(error, "فشل تسجيل المعاملة");

    // 2. تحديث رصيد الحساب
    const { data: acc } = await supabase.from('financial_accounts').select('balance').eq('id', tx.account_id).single();
    if (acc) {
        const newBalance = tx.type === 'INCOME' 
            ? Number(acc.balance) + Number(tx.amount) 
            : Number(acc.balance) - Number(tx.amount);

        await supabase.from('financial_accounts').update({ balance: newBalance }).eq('id', tx.account_id);
    }

    await this.log('معاملة مالية', `تم تسجيل ${tx.type === 'INCOME' ? 'إيراد' : 'مصروف'} بمبلغ ${tx.amount}`);
    return data?.[0];
  }

  static async log(action: string, details: string) {
    try {
      const userStr = localStorage.getItem('dialysis_user');
      const user = userStr ? JSON.parse(userStr) : { name: 'Unknown' };
      await supabase.from('audit_logs').insert([{
        user_id: user.name,
        action,
        details,
        timestamp: new Date().toISOString()
      }]);
    } catch (e) {}
  }

  static async getSessions() {
    const { data, error } = await supabase.from('dialysis_sessions').select('*, patients(name)');
    if (error) return handleError(error, "فشل جلب الجلسات");
    return data || [];
  }

  static async getPatientSessions(patientId: string) {
    const { data, error } = await supabase
      .from('dialysis_sessions')
      .select('*')
      .eq('patient_id', patientId)
      .order('date', { ascending: false });
    if (error) return handleError(error, "فشل جلب جلسات المريض");
    return data || [];
  }

  static async addSession(s: any) {
    const { data, error } = await supabase.from('dialysis_sessions').insert([s]).select();
    if (error) return handleError(error, "فشل تسجيل الجلسة");
    return data?.[0];
  }

  static async getLabDefinitions() {
    const { data, error } = await supabase.from('lab_test_definitions').select('*');
    if (error) return handleError(error, "فشل جلب تعاريف المعمل");
    return data || [];
  }

  static async addLabDefinition(d: Partial<LabTestDefinition>) {
    const { data, error } = await supabase.from('lab_test_definitions').insert([d]).select();
    if (error) return handleError(error, "فشل إضافة تعريف التحليل");
    return data?.[0];
  }

  static async getLabTests() {
    const { data, error } = await supabase.from('lab_tests').select('*, patients(name), lab_test_definitions(name)');
    if (error) return handleError(error, "فشل جلب فحوصات المعمل");
    return data || [];
  }

  static async addLabTest(t: Partial<LabTest>) {
    const { data, error } = await supabase.from('lab_tests').insert([t]).select();
    if (error) return handleError(error, "فشل حجز التحليل");
    return data?.[0];
  }

  static async updateLabResult(id: string, result: string) {
    const { data, error } = await supabase.from('lab_tests').update({ result, status: 'COMPLETED' }).eq('id', id).select();
    if (error) return handleError(error, "فشل تحديث نتيجة التحليل");
    return data?.[0];
  }

  static async getEmployees() {
    const { data, error } = await supabase.from('employees').select('*');
    if (error) return handleError(error, "فشل جلب الموظفين");
    return data || [];
  }

  static async getShifts() {
    const { data, error } = await supabase.from('shift_records').select('*');
    if (error) return handleError(error, "فشل جلب سجلات الشفتات");
    return data || [];
  }

  static async resetShifts() {
    const { error } = await supabase.from('shift_records').delete().neq('id', '00000000-0000-0000-0000-000000000000');
    if (error) return handleError(error, "فشل تصفير سجلات الشفتات");
  }

  static async getTransferRequests() {
    const { data, error } = await supabase.from('transfer_requests').select('*');
    if (error) return handleError(error, "فشل جلب طلبات التحويل");
    return data || [];
  }

  static async createTransferRequest(req: Partial<TransferRequest>) {
    const { data, error } = await supabase.from('transfer_requests').insert([req]).select();
    if (error) return handleError(error, "فشل إنشاء طلب التحويل");
    return data?.[0];
  }

  static async getStockTransactions() {
    const { data, error } = await supabase.from('stock_transactions').select('*');
    if (error) return handleError(error, "فشل جلب الحركات المخزنية");
    return data || [];
  }

  static async addStockTransaction(tx: Partial<StockTransaction>) {
    const { data, error } = await supabase.from('stock_transactions').insert([tx]).select();
    if (error) return handleError(error, "فشل تسجيل العملية المخزنية");
    return data?.[0];
  }
}

import React, { useState, useEffect } from 'react';
import { AR } from '../constants.ts';
import { DB } from '../store.ts';
import { Product, Store, StockTransaction, TransferRequest } from '../types.ts';
import { 
  Package, ArrowLeftRight, TrendingUp, TrendingDown, ClipboardList, 
  Plus, ArrowRightLeft, Loader2, X, CheckCircle, FileText, ShoppingCart, Hash, Trash2, MapPin, AlertTriangle, ShieldX
} from 'lucide-react';

const InventoryModule: React.FC = () => {
  const [activeSubTab, setActiveSubTab] = useState<'stock' | 'transfers' | 'requests'>('stock');
  const [showMoveModal, setShowMoveModal] = useState(false);
  const [moveType, setMoveType] = useState<'ADD' | 'DEDUCT' | 'TRANSFER'>('ADD');

  const [loading, setLoading] = useState(false);
  const [products, setProducts] = useState<Product[]>([]);
  const [stores, setStores] = useState<Store[]>([]);
  const [requests, setRequests] = useState<TransferRequest[]>([]);
  const [stockTransactions, setStockTransactions] = useState<StockTransaction[]>([]);

  const [voucherItems, setVoucherItems] = useState<{ productId: string, quantity: number, price: number }[]>([]);
  const [selectedProductId, setSelectedProductId] = useState('');
  const [selectedQuantity, setSelectedQuantity] = useState(1);
  const [selectedPrice, setSelectedPrice] = useState(0);

  const [documentNumber, setDocumentNumber] = useState('');
  const [voucherNote, setVoucherNote] = useState('');
  const [targetStoreId, setTargetStoreId] = useState('');

  // Get current user permissions
  const currentUser = JSON.parse(localStorage.getItem('dialysis_user') || '{}');
  const userPerms = currentUser.permissions || [];

  useEffect(() => { loadData(); }, [activeSubTab]);

  const loadData = async () => {
    setLoading(true);
    try {
      const [p, s, r, tx] = await Promise.all([
        DB.getProducts(), 
        DB.getStores(), 
        DB.getTransferRequests(),
        DB.getStockTransactions()
      ]);
      setProducts(p || []);
      setStores(s || []);
      setRequests(r || []);
      setStockTransactions(tx || []);
    } catch (err) {
      console.error("Error in Inventory loadData:", err);
    } finally {
      setLoading(false);
    }
  };

  const calculateStock = (productId: string, storeId: string) => {
    let balance = 0;
    stockTransactions.forEach(tx => {
      if (tx.product_id !== productId) return;
      if (tx.type === 'ADD' && tx.store_id === storeId) balance += tx.quantity;
      else if (tx.type === 'DEDUCT' && tx.store_id === storeId) balance -= tx.quantity;
      else if (tx.type === 'TRANSFER') {
        if (tx.store_id === storeId) balance -= tx.quantity;
        if (tx.target_store_id === storeId) balance += tx.quantity;
      }
    });
    return balance;
  };

  const calculateTotalStock = (productId: string) => {
    return visibleStores.reduce((acc, store) => acc + calculateStock(productId, store.id), 0);
  };

  const visibleStores = stores.filter(s => 
    userPerms.includes('SYSTEM_SETUP') || 
    userPerms.includes('MANAGE_INVENTORY') || 
    userPerms.includes(`STORE_VIEW:${s.id}`) || 
    userPerms.includes(`STORE_MANAGE:${s.id}`)
  );

  const manageableStores = stores.filter(s => 
    userPerms.includes('SYSTEM_SETUP') || 
    userPerms.includes('MANAGE_INVENTORY') || 
    userPerms.includes(`STORE_MANAGE:${s.id}`)
  );

  const generateDocNumber = (type: string) => {
    const year = new Date().getFullYear();
    const prefix = type === 'ADD' ? 'REC' : type === 'DEDUCT' ? 'OUT' : 'TRF';
    const random = Math.floor(10000 + Math.random() * 90000);
    return `${prefix}-${year}-${random}`;
  };

  const openModal = (type: 'ADD' | 'DEDUCT' | 'TRANSFER') => {
    if (manageableStores.length === 0) {
      return alert("لا تملك صلاحية إدارة أي مخزن حالياً. يرجى مراجعة الإدارة.");
    }
    setMoveType(type);
    setVoucherItems([]);
    setDocumentNumber(generateDocNumber(type));
    setVoucherNote('');
    setTargetStoreId('');
    setShowMoveModal(true);
  };

  const addItemToVoucher = () => {
    if (!selectedProductId || selectedQuantity <= 0) return;
    if (voucherItems.find(i => i.productId === selectedProductId)) return alert("هذا الصنف مضاف بالفعل في القائمة");
    const p = products.find(prod => prod.id === selectedProductId);
    setVoucherItems([...voucherItems, { productId: selectedProductId, quantity: selectedQuantity, price: selectedPrice || p?.price || 0 }]);
    setSelectedProductId('');
    setSelectedQuantity(1);
    setSelectedPrice(0);
  };

  const removeItemFromVoucher = (pid: string) => setVoucherItems(voucherItems.filter(i => i.productId !== pid));

  const handleVoucherAction = async (e: React.FormEvent) => {
    e.preventDefault();
    if (voucherItems.length === 0) return alert("يرجى إضافة أصناف أولاً للمستند");

    const target = e.target as any;
    const storeId = target.storeId.value;

    if (!storeId) return alert("يرجى اختيار المخزن");

    // تأمين الصلاحيات برمجياً
    const canManage = userPerms.includes('SYSTEM_SETUP') || 
                      userPerms.includes('MANAGE_INVENTORY') || 
                      userPerms.includes(`STORE_MANAGE:${storeId}`);

    if (!canManage) return alert("عذراً، لا تملك صلاحية الإدارة على هذا المخزن.");

    if (moveType === 'TRANSFER' && !targetStoreId) return alert("يرجى اختيار المخزن المستلم");
    if (moveType === 'TRANSFER' && storeId === targetStoreId) return alert("لا يمكن التحويل لنفس المخزن");

    // التحقق من توفر الأرصدة قبل الصرف أو التحويل
    if (moveType === 'DEDUCT' || moveType === 'TRANSFER') {
        for (const item of voucherItems) {
            const available = calculateStock(item.productId, storeId);
            if (available < item.quantity) {
                const prodName = products.find(p => p.id === item.productId)?.name;
                return alert(`عذراً، الرصيد غير كافٍ للصنف: ${prodName}. المتاح حالياً: ${available}`);
            }
        }
    }

    setLoading(true);
    try {
      if (moveType === 'TRANSFER') {
        for (const item of voucherItems) {
          await DB.addStockTransaction({
            product_id: item.productId,
            store_id: storeId,
            target_store_id: targetStoreId,
            type: 'TRANSFER',
            quantity: item.quantity,
            date: new Date().toISOString().split('T')[0],
            note: `${documentNumber} | ${voucherNote}`
          });
        }
      } else {
        for (const item of voucherItems) {
          await DB.addStockTransaction({
            product_id: item.productId,
            store_id: storeId,
            type: moveType,
            quantity: item.quantity,
            date: new Date().toISOString().split('T')[0],
            note: `${documentNumber} | ${voucherNote}`
          });
        }
      }
      setShowMoveModal(false);
      setVoucherItems([]);
      alert(`تم تنفيذ العملية بنجاح. رقم المستند: ${documentNumber}`);
      loadData();
    } catch (err) {
      alert("حدث خطأ أثناء تنفيذ العملية.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 no-print">
        <div className="flex gap-2 p-1 bg-gray-200/50 rounded-xl w-fit">
          <button onClick={() => setActiveSubTab('stock')} className={`px-6 py-2 rounded-lg font-bold transition-all ${activeSubTab === 'stock' ? 'bg-white shadow-sm text-primary-600' : 'text-gray-500'}`}>الأرصدة المتاحة</button>
          <button onClick={() => setActiveSubTab('requests')} className={`px-6 py-2 rounded-lg font-bold transition-all ${activeSubTab === 'requests' ? 'bg-white shadow-sm text-indigo-600' : 'text-gray-500'}`}>طلبات التحويل ({requests.filter(r => r.status === 'PENDING').length})</button>
        </div>

        <div className="flex gap-2">
           <button 
             disabled={manageableStores.length === 0}
             onClick={() => openModal('TRANSFER')} 
             className="bg-indigo-600 text-white px-5 py-3 rounded-xl text-sm font-bold flex items-center gap-2 hover:bg-indigo-700 shadow-md transition-all disabled:opacity-50 disabled:cursor-not-allowed"
           >
             <ArrowLeftRight size={18} /> تحويل داخلي
           </button>
           <button 
             disabled={manageableStores.length === 0}
             onClick={() => openModal('DEDUCT')} 
             className="bg-orange-600 text-white px-5 py-3 rounded-xl text-sm font-bold flex items-center gap-2 shadow-md hover:bg-orange-700 transition-all disabled:opacity-50 disabled:cursor-not-allowed"
           >
             <TrendingDown size={18} /> إذن صـــرف
           </button>
           <button 
             disabled={manageableStores.length === 0}
             onClick={() => openModal('ADD')} 
             className="bg-green-600 text-white px-5 py-3 rounded-xl text-sm font-bold flex items-center gap-2 shadow-md hover:bg-green-700 transition-all disabled:opacity-50 disabled:cursor-not-allowed"
           >
             <TrendingUp size={18} /> توريد
           </button>
        </div>
      </div>

      <div className="bg-white rounded-3xl shadow-sm border overflow-hidden min-h-[400px]">
        {loading && activeSubTab === 'stock' ? (
          <div className="flex flex-col items-center justify-center py-40 gap-4 text-gray-400">
             <Loader2 className="animate-spin text-primary-600" size={40} />
             <p className="font-bold">جاري تحميل المخزون...</p>
          </div>
        ) : activeSubTab === 'stock' ? (
          <div className="p-8">
             <div className="flex justify-between items-center mb-6">
               <h3 className="font-bold text-xl text-gray-800">الأرصدة في المخازن المصرح لك بمشاهدتها</h3>
               <div className="flex items-center gap-4 text-xs">
                 <div className="flex items-center gap-1"><div className="w-3 h-3 bg-rose-50 border border-rose-200 rounded"></div> نواقص (أقل من حد الطلب)</div>
                 <div className="flex items-center gap-1"><div className="w-3 h-3 bg-white border border-gray-200 rounded"></div> متوفر</div>
               </div>
             </div>
             <div className="overflow-x-auto">
               <table className="w-full text-right">
                  <thead className="bg-gray-50 border-b">
                    <tr>
                      <th className="px-6 py-4 font-bold text-gray-600 text-xs">الصنف</th>
                      <th className="px-6 py-4 font-bold text-gray-600 text-xs">التصنيف</th>
                      <th className="px-6 py-4 font-bold text-gray-600 text-xs text-center">الإجمالي العام</th>
                      {visibleStores.map(s => <th key={s.id} className="px-6 py-4 font-bold text-gray-600 text-xs text-center">{s.name}</th>)}
                    </tr>
                  </thead>
                  <tbody className="divide-y">
                    {products.map(p => {
                      const totalStock = calculateTotalStock(p.id);
                      const isLowStock = totalStock <= (p.min_stock || 0);

                      return (
                        <tr key={p.id} className={`transition-colors ${isLowStock ? 'bg-rose-50/50 hover:bg-rose-50' : 'hover:bg-gray-50'}`}>
                          <td className="px-6 py-4 font-bold text-gray-700">
                             <div className="flex items-center gap-2">
                               {isLowStock && <AlertTriangle size={14} className="text-rose-500" />}
                               <span>{p.name} <span className="text-[10px] text-gray-400 font-normal">({p.unit})</span></span>
                             </div>
                          </td>
                          <td className="px-6 py-4 text-xs text-gray-400">{p.category || '---'}</td>
                          <td className={`px-6 py-4 font-black text-center ${isLowStock ? 'text-rose-600' : 'text-primary-800'}`}>
                            {totalStock}
                            {isLowStock && <span className="block text-[8px] font-bold">حد الطلب: {p.min_stock}</span>}
                          </td>
                          {visibleStores.map(s => {
                            const storeQty = calculateStock(p.id, s.id);
                            return (
                              <td key={s.id} className={`px-6 py-4 font-black text-center ${storeQty === 0 ? 'text-gray-300' : 'text-primary-700'}`}>
                                {storeQty}
                              </td>
                            );
                          })}
                        </tr>
                      );
                    })}
                    {products.length === 0 && (
                      <tr><td colSpan={visibleStores.length + 3} className="py-20 text-center text-gray-300 italic">لا توجد أصناف معرفة</td></tr>
                    )}
                  </tbody>
               </table>
             </div>
          </div>
        ) : (
          <div className="p-8 text-center text-gray-400 italic">سجل طلبات التحويل المخصص للمخازن التي تديرها</div>
        )}
      </div>

      {showMoveModal && (
        <div className="fixed inset-0 z-50 bg-black/60 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-5xl rounded-3xl shadow-2xl flex flex-col max-h-[95vh] overflow-hidden animate-in zoom-in-95">
            <div className={`p-6 text-white flex justify-between items-center ${moveType === 'ADD' ? 'bg-green-600' : moveType === 'TRANSFER' ? 'bg-indigo-600' : 'bg-orange-600'}`}>
              <div className="flex items-center gap-4">
                <h3 className="text-xl font-bold">{moveType === 'ADD' ? 'توريد' : moveType === 'TRANSFER' ? 'تحويل' : 'صرف'} مخزني</h3>
              </div>
              <button onClick={() => setShowMoveModal(false)} className="p-2 hover:bg-white/20 rounded-full transition-all"><X size={24} /></button>
            </div>

            <form id="voucherForm" onSubmit={handleVoucherAction} className="p-8 space-y-6 overflow-y-auto flex-1 custom-scrollbar">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6 bg-gray-50 p-6 rounded-3xl border">
                <div>
                  <label className="block text-xs font-bold text-gray-500 uppercase mb-2">المخزن (المصرح لك بإدارته)</label>
                  <select name="storeId" required className="w-full border rounded-xl p-3 bg-white font-bold outline-none">
                    <option value="">-- اختر المخزن --</option>
                    {manageableStores.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                  </select>
                </div>

                {moveType === 'TRANSFER' && (
                  <div>
                    <label className="block text-xs font-bold text-indigo-600 uppercase mb-2">مخزن الوجهة</label>
                    <select value={targetStoreId} onChange={e => setTargetStoreId(e.target.value)} required className="w-full border rounded-xl p-3 bg-white font-bold outline-none">
                      <option value="">-- اختر الوجهة --</option>
                      {stores.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                    </select>
                  </div>
                )}
              </div>

              {/* Items Section */}
              <div className="bg-primary-50/50 p-6 rounded-3xl border-2 border-dashed border-primary-200">
                 <div className="grid grid-cols-12 gap-4 items-end">
                    <div className="col-span-12 md:col-span-6">
                       <label className="block text-xs font-bold text-primary-700 mb-2">الصنف</label>
                       <select value={selectedProductId} onChange={e => setSelectedProductId(e.target.value)} className="w-full border rounded-xl p-3 bg-white outline-none">
                         <option value="">-- ابحث عن صنف... --</option>
                         {products.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                       </select>
                    </div>
                    <div className="col-span-6 md:col-span-3">
                       <label className="block text-xs font-bold text-primary-700 mb-2">الكمية</label>
                       <input type="number" min="0.1" step="0.1" value={selectedQuantity} onChange={e => setSelectedQuantity(parseFloat(e.target.value))} className="w-full border rounded-xl p-3 bg-white text-center font-bold outline-none" />
                    </div>
                    <div className="col-span-12 md:col-span-3">
                       <button type="button" onClick={addItemToVoucher} className="w-full py-3 bg-primary-600 text-white rounded-xl font-bold shadow-lg">إضافة</button>
                    </div>
                 </div>
              </div>

              <div className="border rounded-3xl overflow-hidden shadow-inner bg-white">
                 <table className="w-full text-right">
                    <thead className="bg-gray-100">
                       <tr>
                         <th className="px-6 py-3 font-bold text-gray-500">الصنف</th>
                         <th className="px-6 py-3 text-center font-bold text-gray-500">الكمية</th>
                         <th className="px-6 py-3 text-left font-bold text-gray-500">حذف</th>
                       </tr>
                    </thead>
                    <tbody className="divide-y">
                       {voucherItems.map((item, idx) => (
                         <tr key={idx}>
                            <td className="px-6 py-3 font-bold">{products.find(p => p.id === item.productId)?.name}</td>
                            <td className="px-6 py-3 text-center font-black text-primary-600">{item.quantity}</td>
                            <td className="px-6 py-3 text-left">
                               <button type="button" onClick={() => removeItemFromVoucher(item.productId)} className="text-red-400 p-2"><Trash2 size={16} /></button>
                            </td>
                         </tr>
                       ))}
                    </tbody>
                 </table>
              </div>
            </form>

            <div className="p-8 border-t bg-gray-50 flex gap-4">
              <button onClick={() => setShowMoveModal(false)} className="flex-1 py-4 bg-white border-2 rounded-2xl font-bold text-gray-500">إلغاء</button>
              <button type="submit" form="voucherForm" className={`flex-[2] py-4 text-white rounded-2xl font-bold shadow-xl ${moveType === 'ADD' ? 'bg-green-600' : moveType === 'TRANSFER' ? 'bg-indigo-600' : 'bg-orange-600'}`}>تأكيد الحفظ</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default InventoryModule;

import React, { useState, useEffect } from 'react';
import { AR } from '../constants';
import { DB } from '../store';
import { FinancialAccount, Transaction } from '../types';
import { Wallet, Landmark, ArrowUpCircle, ArrowDownCircle, Loader2, Plus, X, ShieldCheck } from 'lucide-react';

const FinanceModule: React.FC = () => {
  const [activeAccount, setActiveAccount] = useState<string>('all');
  const [showTxForm, setShowTxForm] = useState(false);
  const [txType, setTxType] = useState<'INCOME' | 'EXPENSE'>('INCOME');
  const [accounts, setAccounts] = useState<FinancialAccount[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [loading, setLoading] = useState(true);

  // Get current user permissions
  const currentUser = JSON.parse(localStorage.getItem('dialysis_user') || '{}');
  const userPerms = currentUser.permissions || [];

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    try {
      const [acc, tx] = await Promise.all([DB.getAccounts(), DB.getTransactions()]);
      setAccounts(acc || []);
      setTransactions(tx || []);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const visibleAccounts = accounts.filter(acc => 
    userPerms.includes('SYSTEM_SETUP') || 
    userPerms.includes('MANAGE_FINANCE') || 
    userPerms.includes(`ACCOUNT_VIEW:${acc.id}`) || 
    userPerms.includes(`ACCOUNT_MANAGE:${acc.id}`)
  );

  const manageableAccounts = accounts.filter(acc => 
    userPerms.includes('SYSTEM_SETUP') || 
    userPerms.includes('MANAGE_FINANCE') || 
    userPerms.includes(`ACCOUNT_MANAGE:${acc.id}`)
  );

  const handleAddTransaction = async (e: React.FormEvent) => {
    e.preventDefault();
    const target = e.target as any;
    const amount = parseFloat(target.amount.value);
    const accountId = target.accountId.value;

    // تأمين الصلاحيات برمجياً
    const canManage = userPerms.includes('SYSTEM_SETUP') || 
                      userPerms.includes('MANAGE_FINANCE') || 
                      userPerms.includes(`ACCOUNT_MANAGE:${accountId}`);

    if (!canManage) return alert("عذراً، لا تملك صلاحية الإدارة (قبض/صرف) على هذا الحساب.");

    try {
      await DB.addFinanceTx({
        account_id: accountId,
