        ))}

        {activeSessions.length === 0 && (
          <div className="col-span-full py-40 text-center bg-white rounded-[3rem] border-2 border-dashed border-gray-200 flex flex-col items-center gap-4">
            <User size={64} className="text-gray-200" />
