import React, { useState, useEffect } from 'react';
import { AR, BLOOD_TYPES, calculateAge, ROOMS } from '../constants';
import { DB } from '../store';
import { Patient, FundingEntity, DialysisSession } from '../types';
import { 
  Plus, Search, UserPlus, History, Phone, FileText, Loader2, 
  Calendar as CalendarIcon, X, User, Activity, MapPin, 
  Droplets, CreditCard, ShieldCheck, HeartPulse, Clock, FilePlus, Scale, CheckCircle
} from 'lucide-react';

interface PatientModuleProps {
  setTab?: (tab: string) => void;
}

const PatientModule: React.FC<PatientModuleProps> = ({ setTab }) => {
  const [view, setView] = useState<'list' | 'add'>('list');
  const [patients, setPatients] = useState<Patient[]>([]);
  const [fundingEntities, setFundingEntities] = useState<FundingEntity[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedPatient, setSelectedPatient] = useState<Patient | null>(null);
  const [patientSessions, setPatientSessions] = useState<DialysisSession[]>([]);
  const [loadingSessions, setLoadingSessions] = useState(false);

  // New Record Modal state
  const [showAddRecordModal, setShowAddRecordModal] = useState<Patient | null>(null);

  const [formData, setFormData] = useState<Partial<Patient>>({
    name: '',
    national_id: '',
    phone: '',
    blood_type: '',
    date_of_birth: '',
    address: '',
    emergency_contact: { name: '', phone: '', relation: '' }
  });

  useEffect(() => {
    loadPatients();
  }, []);

  const loadPatients = async () => {
    setLoading(true);
    try {
      const [p, f] = await Promise.all([DB.getPatients(), DB.getFundingEntities()]);
      setPatients(p || []);
      setFundingEntities(f || []);
    } catch (error: any) {
      console.error("Error loading patients:", error);
    } finally {
      setLoading(false);
    }
  };

  const handleOpenProfile = async (patient: Patient) => {
    setSelectedPatient(patient);
    setLoadingSessions(true);
    try {
      const sessions = await DB.getPatientSessions(patient.id);
      setPatientSessions(sessions);
    } catch (e) {
      console.error(e);
    } finally {
      setLoadingSessions(false);
    }
  };

  const handleAddPatient = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      await DB.addPatient(formData);
      await loadPatients();
      setView('list');
      setFormData({
        name: '',
        national_id: '',
        phone: '',
        blood_type: '',
        date_of_birth: '',
        emergency_contact: { name: '', phone: '', relation: '' }
      });
    } catch (error) {
      alert("حدث خطأ أثناء حفظ البيانات");
    }
  };

  const handleCreateNewRecord = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!showAddRecordModal) return;
    const target = e.target as any;
    try {
      await DB.addSession({
        patient_id: showAddRecordModal.id,
        status: 'WAITING',
        date: new Date().toISOString().split('T')[0],
        room: target.room.value,
        notes: target.notes.value,
        weight_before: parseFloat(target.weightBefore.value) || 0,
        blood_pressure: target.bp.value,
      });
      alert("تم إضافة السجل الطبي بنجاح.");
      setShowAddRecordModal(null);
    } catch (e) {
      alert("فشل إضافة السجل.");
    }
  };

  const filteredPatients = patients.filter(p => 
    p.name.includes(searchTerm) || p.national_id.includes(searchTerm) || p.phone.includes(searchTerm)
  );

  if (view === 'add') {
    return (
      <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-gray-100 max-w-4xl mx-auto animate-in fade-in slide-in-from-bottom-4">
